vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.311664em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.208331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;т╝ЈСИГ№╝ї &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;a_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; Тў»тћ»СИђуџё РђюуггСИђСИфтЁЃу┤аРђЮ№╝їтЈѕуД░УАетц┤тЁЃу┤а№╝Џ&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;a_n&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; Тў»тћ»СИђуџё РђюТюђтљјСИђСИфтЁЃу┤аРђЮ№╝їтЈѕуД░УАет░ЙтЁЃу┤асђѓжЎцуггСИђСИфтЁЃу┤атцќ№╝їТ»ЈСИфтЁЃу┤аТюЅСИћС╗ЁТюЅСИђСИфуЏ┤ТјЦтЅЇжЕ▒сђѓжЎцТюђтљјСИђСИфтЁЃу┤атцќ№╝їТ»ЈСИфтЁЃу┤аТюЅСИћС╗ЁТюЅСИђСИфуЏ┤ТјЦтљјжЕ▒сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ућ▒ТГц№╝їу║┐ТђДУАеуџёуЅ╣уѓ╣Тў»№╝џ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;УАеСИГтЁЃу┤ауџёСИфТЋ░ТюЅжЎљсђѓ&lt;/li&gt;
&lt;li&gt;УАеСИГтЁЃу┤атЁиТюЅжђ╗УЙЉСИіуџёжА║т║ЈТђД№╝їУАеСИГТЋ░ТЇ«ТюЅтЁХтЁѕтљјТгАт║Јсђѓ&lt;/li&gt;
&lt;li&gt;УАеСИГтЁЃу┤ажЃйТў»ТЋ░ТЇ«тЁЃу┤а№╝їТ»ЈСИфтЁЃу┤ажЃйТў»тЇЋСИфТЋ░ТЇ«сђѓ&lt;/li&gt;
&lt;li&gt;УАеСИГтЁЃу┤ауџёТЋ░ТЇ«у▒╗тъІжЃйуЏИтљї№╝їУ┐ЎТёЈтЉ│уЮђТ»ЈСИфтЁЃу┤ажЃйтЇаТюЅуЏИтљїтцДт░ЈуџётГўтѓеуЕ║жЌ┤сђѓ&lt;/li&gt;
&lt;li&gt;УАеСИГтЁЃу┤атЁиТюЅТійУ▒АТђД№╝їтЇ│С╗ЁУ«еУ«║тЁЃу┤ажЌ┤уџёжђ╗УЙЉтЁ│у│╗№╝їУђїСИЇУђЃУЎЉтЁЃу┤ауЕХуФЪУАеуц║С╗ђС╣ѕтєЁт«╣сђѓ&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;212-у║┐ТђДУАеуџёТЊЇСйю&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#212-у║┐ТђДУАеуџёТЊЇСйю&#34;&gt;#&lt;/a&gt; 2.1.2сђЂу║┐ТђДУАеуџёТЊЇСйю№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	у║┐ТђДУАеуџёСИ╗УдЂТЊЇСйютдѓСИІ№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;InitList (&amp;amp;L)		  	 №╝џтѕЮтДІтїќУАесђѓТъёжђаСИђСИфуЕ║уџёу║┐ТђДУАесђѓ&lt;/p&gt;
&lt;p&gt;Length (L)				 №╝џТ▒ѓУАежЋ┐сђѓУ┐ћтЏъу║┐ТђДУАе L уџёжЋ┐т║д№╝їтЇ│ L СИГТЋ░ТЇ«тЁЃу┤ауџёСИфТЋ░сђѓ&lt;/p&gt;
&lt;p&gt;LocateElem (L,e)	  №╝џТїЅтђ╝ТЪЦТЅЙТЊЇСйюсђѓтюеУАе L СИГТЪЦТЅЙтЁиТюЅу╗Ўт«џтЁ│жћ«тГЌтђ╝уџётЁЃу┤асђѓ&lt;/p&gt;
&lt;p&gt;GetElem (L,i)			 №╝џТїЅСйЇТЪЦТЅЙТЊЇСйюсђѓУјитЈќУАе L СИГугг i СИфСйЇуй«уџётЁЃу┤ауџётђ╝сђѓ&lt;/p&gt;
&lt;p&gt;ListInsert (&amp;amp;L,i,e)	  №╝џТЈњтЁЦТЊЇСйюсђѓтюеУАе L СИГуџёугг i СИфСйЇуй«СИіТЈњтЁЦТїЄт«џтЁЃу┤а e сђѓ&lt;/p&gt;
&lt;p&gt;ListDelete (&amp;amp;L,i,&amp;amp;e)  №╝џтѕажЎцТЊЇСйюсђѓтѕажЎцУАе L СИГугг i СИфСйЇуй«уџётЁЃу┤а№╝їт╣Хуће e У┐ћтЏътѕажЎцтЁЃу┤ауџётђ╝сђѓ&lt;/p&gt;
&lt;p&gt;PrintList (L)				№╝џУЙЊтЄ║ТЊЇСйюсђѓТїЅтЅЇтљјжА║т║ЈУЙЊтЄ║у║┐ТђДУАе L уџёТЅђТюЅтЁЃу┤атђ╝сђѓ&lt;/p&gt;
&lt;p&gt;Empty (L)					№╝џтѕцуЕ║ТЊЇСйюсђѓУІЦ L СИ║уЕ║УАе№╝їтѕЎУ┐ћтЏъ true№╝їтљдтѕЎУ┐ћтЏъ falseсђѓ&lt;/p&gt;
&lt;p&gt;DestroyList (&amp;amp;L)		№╝џжћђТ»ЂТЊЇСйюсђѓжћђТ»Ђу║┐ТђДУАе№╝їт╣ХжЄіТћЙу║┐ТђДУАе L ТЅђтЇаућеуџётєЁтГўсђѓ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;22-у║┐ТђДУАеуџёжА║т║ЈУАеуц║&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#22-у║┐ТђДУАеуџёжА║т║ЈУАеуц║&#34;&gt;#&lt;/a&gt; 2.2сђЂу║┐ТђДУАеуџёжА║т║ЈУАеуц║№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;221-жА║т║ЈУАеуџёт«џС╣Ѕ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#221-жА║т║ЈУАеуџёт«џС╣Ѕ&#34;&gt;#&lt;/a&gt; 2.2.1сђЂжА║т║ЈУАеуџёт«џС╣Ѕ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	у║┐ТђДУАеуџёжА║т║ЈтѓетГўтЈѕуД░жА║т║ЈУАесђѓт«ЃТў»ућеСИђу╗ётю░тЮђУ┐ъу╗ГуџётГўтѓетЇЋтЁЃСЙЮТгАтГўтѓеу║┐ТђДУАеСИГуџёТЋ░ТЇ«тЁЃу┤а№╝їС╗јУђїСй┐тЙЌжђ╗УЙЉСИіуЏИжѓ╗уџёСИцСИфтЁЃу┤атюеуЅЕуљєСйЇуй«СИіС╣ЪуЏИжѓ╗сђѓугг 1 СИфтЁЃу┤атГўтѓетюеу║┐ТђДУАеуџёУхитДІСйЇуй«№╝їугг i СИфтЁЃу┤ауџётГўтѓеСйЇуй«тљјжЮбу┤ДУиЪуЮђтГўтѓеСйЇуй«уџёТў»угг i + 1 СИфтЁЃу┤а№╝їуД░ i СИ║тЁЃу┤а &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;a_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; тюеу║┐ТђДУАеСИГуџёСйЇт║ЈсђѓтЏаТГц№╝їжА║т║ЈУАеуџёуЅ╣уѓ╣Тў»УАеСИГтЁЃу┤ауџёжђ╗УЙЉжА║т║ЈСИјуЅЕуљєжА║т║ЈуЏИтљїсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тЂЄУ«Йу║┐ТђДУАе L тГўтѓеуџёУхитДІтю░тЮђСИ║ LOC (A)№╝їsizeof (ElemType) Тў»Т»ЈСИфТЋ░ТЇ«тЁЃу┤аТЅђтЇаућетєЁтГўуЕ║жЌ┤уџётцДт░Ј№╝їтѕЎУАе L ТЅђт»╣т║ћуџёжА║т║ЈтГўтѓетдѓСИІтЏЙТЅђуц║сђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/bd840c3208a24e56b5b03ad912b601bf.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	жђџтИИућежФўу║ДУ»ГУеђСИГуџёТЋ░у╗ёТЮЦТЈЈУ┐░у║┐ТђДУАеуџёжА║т║ЈтГўтѓеу╗ЊТъёсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тЂЄт«џу║┐ТђДУАеуџётЁЃу┤ау▒╗тъІСИ║ ElemType №╝їтѕЎу║┐ТђДУАеуџёжА║т║ЈтГўтѓеу▒╗тъІТЈЈУ┐░СИ║№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MaxSize 50					&lt;span class=&#34;comment&#34;&gt;//т«џС╣Ѕу║┐ТђДУАеуџёТюђтцДжЋ┐т║д&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ElemType data[MaxSize];			&lt;span class=&#34;comment&#34;&gt;//жА║т║ЈУАеуџётЁЃу┤а&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; length;						&lt;span class=&#34;comment&#34;&gt;//жА║т║ЈУАеуџётйЊтЅЇжЋ┐т║д&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; SqList;							&lt;span class=&#34;comment&#34;&gt;//жА║т║ЈУАеуџёу▒╗тъІт«џС╣Ѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	СИђу╗┤ТЋ░у╗ётЈ»С╗ЦТў»жЮЎТђЂтѕєжЁЇуџё№╝їС╣ЪтЈ»С╗ЦТў»тіеТђЂтѕєжЁЇуџёсђѓтюежЮЎТђЂтѕєжЁЇТЌХ№╝їућ▒С║јТЋ░у╗ёуџётцДт░ЈтњїуЕ║жЌ┤С║ІтЁѕти▓у╗ЈтЏ║т«џ№╝їСИђТЌдуЕ║жЌ┤тЇаТ╗А№╝їтєЇтіатЁЦТќ░уџёТЋ░ТЇ«т░▒С╝џС║ДућЪТ║бтЄ║№╝їУ┐ЏУђїт»╝УЄ┤уеІт║Јт┤ЕТ║Ѓсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	УђїтюетіеТђЂтѕєжЁЇТЌХ№╝їтГўтѓеТЋ░у╗ёуџёуЕ║жЌ┤т«ътюеуеІт║ЈТЅДУАїУ┐ЄуеІСИГжђџУ┐ЄтіеТђЂтГўтѓетѕєжЁЇУ»ГтЈЦтѕєжЁЇтѕ░№╝їСИђТЌдТЋ░ТЇ«уЕ║жЌ┤тЇаТ╗А№╝їт░▒тЈдтцќт╝ђУЙЪСИђтЮЌТЏ┤тцДуџётГўтѓеуЕ║жЌ┤№╝їућеС╗ЦТЏ┐ТЇбтјЪТЮЦуџётГўтѓеуЕ║жЌ┤№╝їС╗јУђїУЙЙтѕ░ТЅЕтЁЁтГўтѓеТЋ░у╗ёуЕ║жЌ┤уџёуЏ«уџё№╝їУђїСИЇжюђУдЂСИ║у║┐ТђДУАеСЙЮТгАТђДтю░тѕњтѕєТЅђТюЅуЕ║жЌ┤сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; InitSize 100				&lt;span class=&#34;comment&#34;&gt;//УАежЋ┐т║дуџётѕЮтДІт«џС╣Ѕ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	ElemType *data;					&lt;span class=&#34;comment&#34;&gt;//ТїЄуц║тіеТђЂтѕєжЁЇТЋ░у╗ёуџёТїЄжњѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; MaxSize,length;				&lt;span class=&#34;comment&#34;&gt;//ТЋ░у╗ёуџёТюђтцДт«╣жЄЈтњїтйЊтЅЇСИфТЋ░&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; SeqList;							&lt;span class=&#34;comment&#34;&gt;//тіеТђЂтѕєжЁЇТЋ░у╗ёжА║т║ЈУАет«џС╣Ѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	C У»ГУеђтѕЮтДІтіеТђЂтѕєжЁЇУ»ГтЈЦСИ║№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;L.data = (ElemType*)&lt;span class=&#34;built_in&#34;&gt;malloc&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(ElemType)*InitSize);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	жА║т║ЈУАеТюђСИ╗УдЂуџёуЅ╣уѓ╣Тў»жџЈТю║У«┐жЌ«№╝їтЇ│жђџУ┐Єждќтю░тЮђтњїтЁЃу┤ат║ЈтЈитЈ»тюеТЌХжЌ┤ O (1) тєЁТЅЙтѕ░ТїЄт«џуџётЁЃу┤асђѓ&lt;/p&gt;
&lt;p&gt;РђІ	жА║т║ЈУАеуџётГўтѓет»єт║джФў№╝їТ»ЈСИфу╗Њуѓ╣тЈфтГўтѓеТЋ░ТЇ«тЁЃу┤асђѓ&lt;/p&gt;
&lt;p&gt;РђІ	жА║т║ЈУАежђ╗УЙЉСИіуЏИжѓ╗уџётЁЃу┤ауЅЕуљєСИіС╣ЪуЏИжѓ╗№╝їТЅђС╗ЦТЈњтЁЦтњїтѕажЎцТЊЇСйюжюђУдЂуД╗тіетцДжЄЈтЁЃу┤асђѓ&lt;/p&gt;
&lt;h2 id=&#34;222-жА║т║ЈУАеСИітЪ║ТюгТЊЇСйюуџёт«ъуј░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#222-жА║т║ЈУАеСИітЪ║ТюгТЊЇСйюуџёт«ъуј░&#34;&gt;#&lt;/a&gt; 2.2.2сђЂжА║т║ЈУАеСИітЪ║ТюгТЊЇСйюуџёт«ъуј░№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;1-ТЈњтЁЦТЊЇСйю&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-ТЈњтЁЦТЊЇСйю&#34;&gt;#&lt;/a&gt; №╝ѕ1№╝ЅсђЂТЈњтЁЦТЊЇСйю№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тюежА║т║ЈУАе L уџёугг i (1&amp;lt;= i &amp;lt;= L.Length+1) СИфСйЇуй«ТЈњтЁЦТќ░тЁЃу┤а e сђѓУІЦ i уџёУЙЊтЁЦСИЇтљѕТ│Ћ№╝їтѕЎУ┐ћтЏъ false №╝їУАеуц║ТЈњтЁЦтц▒У┤Ц№╝ЏтљдтѕЎ№╝їт░єугг i СИфтЁЃу┤атЈітЁХтљјуџёТЅђТюЅтЁЃу┤аСЙЮТгАтЙђтљјуД╗тіеСИђСИфСйЇуй«№╝їУЁЙтЄ║СИђСИфуЕ║СйЇуй«ТЈњтЁЦТќ░тЁЃу┤а e №╝їжА║т║ЈУАежЋ┐т║дтбътіа 1№╝їТЈњтЁЦТѕљтіЪ№╝їУ┐ћтЏъ trueсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;stdio.h&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MaxSize 50&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; data[MaxSize];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; length;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; SqList;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;ListInsert&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(SqList *L,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i , &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; e)&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    SqList L;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    L.length = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; i &amp;lt; &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;; i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        L.data[i] = i + &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        L.length += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ListInsert(&amp;amp;L,&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; i &amp;lt; L.length; i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d,&amp;quot;&lt;/span&gt;,L.data[i]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n%d&amp;quot;&lt;/span&gt;,L.length);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//т«ъуј░ТЈњтЁЦу«ЌТ│ЋуџёСИ╗СйЊтЄйТЋ░&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;ListInsert&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(SqList *L,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i , &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; e)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (i &amp;lt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; || i &amp;gt; L-&amp;gt;length + &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (L-&amp;gt;length &amp;gt;= MaxSize)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; j = L-&amp;gt;length;j &amp;gt;= i;j--)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        L-&amp;gt;data[j] = L-&amp;gt;data[j&lt;span class=&#34;number&#34;&gt;-1&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    L-&amp;gt;data[i - &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;] = e;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    L-&amp;gt;length ++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	&lt;strong&gt;Т│еТёЈ№╝џтї║тѕФжА║т║ЈУАеуџёСИ║т║ЈтњїТЋ░у╗ёСИІТаЄсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;РђІ	ТюђтЦйТЃЁтєх№╝џтюеУАет░ЙТЈњтЁЦ№╝ѕi = n + 1№╝Ѕ№╝їтЁЃу┤атљјуД╗У»ГтЈЦт░єСИЇТЅДУАї№╝їТЌХжЌ┤тцЇТЮѓт║дСИ║ O (1)сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ТюђтЮЈТЃЁтєх№╝џтюеУАетц┤ТЈњтЁЦ№╝ѕi = 1№╝Ѕ№╝їтЁЃу┤атљјуД╗У»ГтЈЦт░єТЅДУАї n ТгА№╝їТЌХжЌ┤тцЇТЮѓт║дСИ║ O (n)сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	т╣│тЮЄТЃЁтєх№╝џтЂЄУ«Й &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;p_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;№╝ѕ&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mo&gt;Рѕњ&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;p_i=1/(n-1)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;Рѕњ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;№╝ЅТў»тюеугг i СИфСйЇуй«СИіТЈњтЁЦСИђСИфу╗Њуѓ╣уџёТдѓујЄ№╝їтѕЎтюежЋ┐т║дСИ║ n уџёу║┐ТђДУАеСИГТЈњтЁЦСИђСИфу╗Њуѓ╣ТЌХ№╝їТЅђжюђуД╗тіеуџёу╗Њуѓ╣т╣│тЮЄТгАТЋ░СИ║№╝џ&lt;/p&gt;
