4; style=&#34;border-bottom-width:0.04em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.677em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.686em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose nulldelimiter&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mopen nulldelimiter&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mfrac&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.427em;&#34;&gt;&lt;span style=&#34;top:-2.314em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.23em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;frac-line&#34; style=&#34;border-bottom-width:0.04em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.677em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.686em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose nulldelimiter&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:2.00744em;vertical-align:-0.686em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mopen nulldelimiter&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mfrac&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.32144em;&#34;&gt;&lt;span style=&#34;top:-2.314em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.23em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;frac-line&#34; style=&#34;border-bottom-width:0.04em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.677em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.686em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose nulldelimiter&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тЏаТГц№╝їжА║т║ЈУАеТїЅтђ╝ТЪЦТЅЙу«ЌТ│Ћуџёт╣│тЮЄТЌХжЌ┤тцЇТЮѓт║дСИ║ O (n)сђѓ&lt;/p&gt;
&lt;h1 id=&#34;23-у║┐ТђДУАеуџёжЊЙт╝ЈУАеуц║&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#23-у║┐ТђДУАеуџёжЊЙт╝ЈУАеуц║&#34;&gt;#&lt;/a&gt; 2.3сђЂу║┐ТђДУАеуџёжЊЙт╝ЈУАеуц║№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	жЊЙт╝ЈтГўтѓеу║┐ТђДУАеТЌХ№╝їСИЇжюђУдЂСй┐ућетю░тЮђУ┐ъу╗ГуџётГўтѓетЇЋтЁЃ№╝їтЇ│СИЇУдЂТ▒ѓжђ╗УЙЉСИіуЏИжѓ╗уџётЁЃу┤атюеуЅЕуљєСйЇуй«СИіС╣ЪуЏИжѓ╗№╝їт«ЃжђџУ┐Є РђюжЊЙРђЮ т╗║уФІУхитЁЃу┤аС╣ІжЌ┤уџёжђ╗УЙЉтЁ│у│╗№╝їтЏаТГцТЈњтЁЦтњїтѕажЎцТЊЇСйюСИЇжюђУдЂуД╗тіетЁЃу┤а№╝їУђїтЈфжюђС┐«Тћ╣ТїЄжњѕ№╝їСйєС╣ЪС╝џтц▒тј╗жА║т║ЈУАетЈ»жџЈТю║тГўтЈќуџёС╝ўуѓ╣сђѓ&lt;/p&gt;
&lt;h2 id=&#34;231-тЇЋжЊЙУАеуџёт«џС╣Ѕ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#231-тЇЋжЊЙУАеуџёт«џС╣Ѕ&#34;&gt;#&lt;/a&gt; 2.3.1сђЂтЇЋжЊЙУАеуџёт«џС╣Ѕ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	у║┐ТђДУАеуџёжЊЙт╝ЈтГўтѓетЈѕуД░тЇЋжЊЙУАе№╝їт«ЃТў»ТїЄжђџУ┐ЄСИђу╗ёС╗╗ТёЈуџётГўтѓетЇЋСйЇТЮЦтГўтѓеу║┐ТђДУАеСИГуџёТЋ░ТЇ«тЁЃу┤асђѓСИ║С║єт╗║уФІТЋ░ТЇ«тЁЃу┤аС╣ІжЌ┤уџёу║┐ТђДтЁ│у│╗№╝їт»╣Т»ЈСИфжЊЙУАеу╗Њуѓ╣№╝їжЎцтГўТћЙтЁЃу┤аУЄфУ║ФуџёС┐АТЂ»тцќ№╝їУ┐ўжюђтГўТћЙСИђСИфТїЄтљЉтЁХтљју╗ДуџёТїЄжњѕсђѓтЇЋжЊЙУАеу╗Њуѓ╣СИђУѕгтГўТћЙСИцСИфтЪЪ№╝їСИђСИфТЌХ data ТЋ░ТЇ«тЪЪ№╝їућеС║јтГўТћЙТЋ░ТЇ«№╝ЏтЈдСИђСИф next СИ║ТїЄжњѕтЪЪ№╝їућеС║јтГўТћЙтљју╗Ду╗Њуѓ╣уџётю░тЮђсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тЇЋжЊЙУАеСИГу╗Њуѓ╣у▒╗тъІуџёТЈЈУ┐░тдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;LNode&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ElemType data;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;LNode&lt;/span&gt; *&lt;span class=&#34;title&#34;&gt;next&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;LNode,*LinkList;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тѕЕућетЇЋжЊЙУАетЈ»С╗ЦУДБтє│жА║т║ЈУАежюђУдЂтцДжЄЈУ┐ъу╗ГтГўтѓетЇЋтЁЃуџёу╝║уѓ╣№╝їСйєтЇЋжЊЙУАежЎётіаТїЄжњѕтЪЪ№╝їС╣ЪтГўтюеТхфУ┤╣тГўтѓеуЕ║жЌ┤уџёу╝║уѓ╣сђѓућ▒С║јтЇЋжЊЙУАеуџётЁЃу┤ауд╗ТЋБтю░тѕєтИЃтюетГўтѓеуЕ║жЌ┤СИГ№╝їТЅђС╗ЦтЇЋжЊЙУАеТў»жЮъжџЈТю║тГўтЈќуџётГўтѓеу╗ЊТъё№╝їтЇ│СИЇУЃйуЏ┤ТјЦТЅЙтѕ░УАеСИГТЪљСИфуЅ╣т«џуџёу╗Њуѓ╣сђѓТЪЦТЅЙТЪљСИфуЅ╣т«џуџёТјЦтЙЁСйаТЌХ№╝їжюђУдЂС╗јтц┤т╝ђтДІжЂЇтјє№╝їСЙЮТгАТЪЦТЅЙсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	жђџтИИућетц┤ТїЄжњѕТЮЦУАеуц║СИђСИфтЇЋжЊЙУАе№╝їтдѓтЇЋжЊЙУАе L №╝їтц┤ТїЄжњѕСИ║ NULL ТЌХУАеуц║СИђСИфуЕ║УАесђѓТГцтцќ№╝їСИ║С║єТЊЇСйюСИіуџёТќ╣СЙ┐№╝їтюетЇЋжЊЙУАеуггСИђСИфу╗Њуѓ╣С╣ІтЅЇжЎётіаСИђСИфу╗Њуѓ╣№╝їТѕљСИ║тц┤у╗Њуѓ╣сђѓтц┤у╗Њуѓ╣уџёТЋ░ТЇ«тЪЪтЈ»С╗ЦСИЇУ«ЙС╗╗СйЋС┐АТЂ»№╝їС╣ЪтЈ»С╗ЦУ«░тйЋУАежЋ┐уГЅС┐АТЂ»сђѓтц┤у╗Њуѓ╣уџёТїЄжњѕтЪЪТїЄтљЉу║┐ТђДУАеуџёуггСИђСИфтЁЃу┤ау╗Њуѓ╣№╝їтдѓСИІтЏЙ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/b0105c322a31496e97a856a9a5b7948c.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тц┤у╗Њуѓ╣тњїтц┤ТїЄжњѕуџётї║тѕє№╝џСИЇу«АтИдСИЇтИдтц┤у╗Њуѓ╣№╝їтц┤ТїЄжњѕжЃйтДІу╗ѕТїЄтљЉжЊЙУАеуџёуггСИђСИфу╗Њуѓ╣№╝їУђїтц┤у╗Њуѓ╣ТЌХтИдтц┤Уіѓуѓ╣уџёжЊЙУАеСИГуџёуггСИђСИфу╗Њуѓ╣№╝їу╗Њуѓ╣тєЁжђџтИИСИЇтГўтѓеС┐АТЂ»сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	т╝ЋтЁЦтц┤у╗Њуѓ╣тљј№╝їтЈ»С╗ЦтИдТЮЦСИцСИфС╝ўуѓ╣сђѓ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;ућ▒С║југгСИђСИфТЋ░ТЇ«у╗Њуѓ╣уџёСйЇуй«УбФтГўТћЙтюетц┤у╗Њуѓ╣уџёТїЄжњѕтЪЪСИГ№╝їтЏаТГцтюежЊЙУАеуџёуггСИђСИфСйЇуй«СИіуџёТЊЇСйютњїтюеУАеуџётЁХС╗ќСйЇуй«СИіуџёТЊЇСйюСИђУЄ┤№╝їТЌажюђУ┐ЏУАїуЅ╣Т«ітцёуљєсђѓ&lt;/li&gt;
&lt;li&gt;ТЌаУ«║жЊЙУАеТў»тљдСИ║уЕ║№╝їтЁХтц┤ТїЄжњѕжЃйТў»ТїЄтљЉтц┤у╗Њуѓ╣уџёжЮъуЕ║ТїЄжњѕ№╝ѕуЕ║УАеСИГтц┤у╗Њуѓ╣уџёТїЄжњѕтЪЪСИ║уЕ║№╝Ѕ№╝їтЏаТГцуЕ║УАетњїжЮъуЕ║УАеуџётцёуљєС╣Ът░▒тЙЌтѕ░С║єу╗ЪСИђсђѓ&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;232-тЇЋжЊЙУАеСИітЪ║ТюгТЊЇСйютњїт«ъуј░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#232-тЇЋжЊЙУАеСИітЪ║ТюгТЊЇСйютњїт«ъуј░&#34;&gt;#&lt;/a&gt; 2.3.2сђЂтЇЋжЊЙУАеСИітЪ║ТюгТЊЇСйютњїт«ъуј░№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;1-жЄЄућетц┤ТЈњТ│Ћт╗║уФІтЇЋжЊЙУАе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-жЄЄућетц┤ТЈњТ│Ћт╗║уФІтЇЋжЊЙУАе&#34;&gt;#&lt;/a&gt; 1сђЂжЄЄућетц┤ТЈњТ│Ћт╗║уФІтЇЋжЊЙУАе№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	У»ЦТќ╣Т│ЋС╗јСИђСИфуЕ║УАет╝ђтДІ№╝їућЪТѕљТќ░Уіѓуѓ╣№╝їт╣Хт░єУ»╗тЈќтѕ░уџёТЋ░ТЇ«тГўТћЙтѕ░С┐Ау╗Њуѓ╣уџёТЋ░ТЇ«тЪЪСИГ№╝їуёХтљјт░єТќ░у╗Њуѓ╣ТЈњтЁЦтѕ░тйЊтЅЇжЊЙУАеуџёУАетц┤№╝їтЇ│тц┤у╗Њуѓ╣С╣Ітљј№╝їтдѓСИІтЏЙ:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/a25e2c3a10d9431daacfaf9ee4d71e5f.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тц┤ТЈњТ│Ћт╗║уФІтЇЋжЊЙУАеуџёу«ЌТ│ЋтдѓСИІ№╝џ&lt;/p&gt;
