ne&#34;&gt;        p = p-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    AllFree(DL);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DLinkList &lt;span class=&#34;title function_&#34;&gt;create&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DLinkList DL)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; x;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DL = (DLinkList)&lt;span class=&#34;built_in&#34;&gt;malloc&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(DNode));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DLinkList s,r = DL;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;scanf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;,&amp;amp;x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (x != &lt;span class=&#34;number&#34;&gt;9999&lt;/span&gt;)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        s = (DLinkList) &lt;span class=&#34;built_in&#34;&gt;malloc&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(DNode));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        s-&amp;gt;data = x;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        r-&amp;gt;next = s;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        r-&amp;gt;next-&amp;gt;prior = r;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        r = s;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;scanf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;,&amp;amp;x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    r-&amp;gt;next = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; DL;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DLinkList &lt;span class=&#34;title function_&#34;&gt;GetElem&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DLinkList DL,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (i &amp;lt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; j = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DLinkList p = DL-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(p != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &amp;amp;&amp;amp; j &amp;lt; i)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p = p-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        j ++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DLinkList &lt;span class=&#34;title function_&#34;&gt;Insert&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DLinkList DL,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; e)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DLinkList s,p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    s = (DLinkList) &lt;span class=&#34;built_in&#34;&gt;malloc&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(DNode));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    p = GetElem(DL,i&lt;span class=&#34;number&#34;&gt;-1&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    s-&amp;gt;data = e;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    s-&amp;gt;next = p-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    p-&amp;gt;next-&amp;gt;prior = s;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    s-&amp;gt;prior = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    p-&amp;gt;next = s;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; DL;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//т«ъуј░тѕажЎцу╗Њуѓ╣уџётЄйТЋ░уџёСИ╗СйЊ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DLinkList &lt;span class=&#34;title function_&#34;&gt;Delete&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DLinkList DL,&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DLinkList p,q;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    q = GetElem(DL,i);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    p = q-&amp;gt;prior;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    p-&amp;gt;next = q-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    q-&amp;gt;next-&amp;gt;prior = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;free&lt;/span&gt;(q);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; DL;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;AllFree&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DLinkList DL)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DLinkList p = DL-&amp;gt;next,r;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(p)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        r = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p = p-&amp;gt;next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;free&lt;/span&gt;(r);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;free&lt;/span&gt;(p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;free&lt;/span&gt;(DL);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;234-тЙфуј»жЊЙУАе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#234-тЙфуј»жЊЙУАе&#34;&gt;#&lt;/a&gt; 2.3.4сђЂтЙфуј»жЊЙУАе№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;1-тЙфуј»тЇЋжЊЙУАе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-тЙфуј»тЇЋжЊЙУАе&#34;&gt;#&lt;/a&gt; 1сђЂтЙфуј»тЇЋжЊЙУАе№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тЙфуј»тЇЋжЊЙУАетњїтЇЋжЊЙУАеуџётї║тѕФтюеС║ј№╝їУАеСИГТюђтљјСИђСИфу╗Њуѓ╣уџёТїЄжњѕСИЇТў» NULL №╝їУђїТћ╣СИ║ТїЄтљЉтц┤у╗Њуѓ╣№╝їС╗јУђїТЋ┤СИфжЊЙУАетйбТѕљСИђСИфуј»№╝їтдѓСИІтЏЙ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/59bedaba5a4946ada2d61376dbaf51de.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тюетЙфуј»тЇЋжЊЙУАеСИГ№╝їУАет░Йу╗Њуѓ╣уџё next тЪЪТїЄтљЉ L №╝їТЋЁУАеСИГТ▓АТюЅТїЄжњѕтЪЪСИ║ NULL уџёу╗Њуѓ╣№╝їтЏаТГц№╝їтЙфуј»тЇЋжЊЙУАеуџётѕцуЕ║ТЮАС╗ХСИЇТў»тц┤у╗Њуѓ╣уџёТїЄжњѕТў»тљдСИ║уЕ║№╝їУђїТў»т«ЃТў»тљдуГЅС║јтц┤ТїЄжњѕсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тЙфуј»тЇЋжЊЙУАеуџёТЈњтЁЦсђЂтѕажЎцу«ЌТ│ЋСИјтЇЋжЊЙУАеуџётЄаС╣јСИђТаи№╝їТЅђСИЇтљїуџёТў»УІЦТЊЇСйютюеУАет░ЙУ┐ЏУАї№╝їтѕЎТЅДУАїуџёТЊЇСйюСИЇтљї№╝їС╗ЦУ«ЕтЇЋжЊЙУАеу╗Ду╗ГС┐ЮТїЂтЙфуј»уџёуЅ╣ТђДсђѓтйЊуёХ№╝їТГБтЏаСИ║тЙфуј»тЇЋжЊЙУАеТў»СИђСИфуј»№╝їтЏаТГцтюеС╗╗СйЋСИђСИфСйЇтЮђСИіуџёТЈњтЁЦтњїтѕажЎцТЊЇСйюжЃйТў»уГЅС╗иуџё№╝їТЌажюђтѕцТќГТў»тљдТў»УАет░Йсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тюетЇЋжЊЙУАеСИГтЈфУЃйС╗јУАетц┤у╗Њуѓ╣т╝ђтДІтЙђтљјжА║т║ЈжЂЇтјєТЋ┤СИфжЊЙУАе№╝їУђїтЙфуј»тЇЋжЊЙУАетЈ»С╗ЦС╗јУАеСИГуџёС╗╗ТёЈСИђСИфу╗Њуѓ╣т╝ђтДІжЂЇтјєТЋ┤СИфжЊЙУАесђѓТюЅТЌХт»╣тЙфуј»жЊЙУАеСИЇУ«Йтц┤ТїЄжњѕС╗ЁУ«Йт░ЙТїЄжњѕ№╝їС╗ЦСй┐тЙЌТЊЇСйюТЋѕујЄТЏ┤жФўсђѓтЁХтјЪтЏаТў»№╝їУІЦУ«ЙуџёТў»тц┤ТїЄжњѕ№╝їт»╣тюеУАет░ЙТЈњтЁЦтЁЃу┤ажюђУдЂ O (n) уџёТЌХжЌ┤тцЇТЮѓт║д№╝їУђїУІЦУ«ЙуџёТў»т░ЙТїЄжњѕ r №╝їr-&amp;gt;next тЇ│СИ║тц┤ТїЄжњѕ№╝їт»╣тюеУАетц┤ТѕќУАет░ЙТЈњтЁЦтЁЃу┤ажЃйтЈфжюђУдЂ O (1) уџёТЌХжЌ┤тцЇТЮѓт║дсђѓ&lt;/p&gt;
&lt;h3 id=&#34;2-тЙфуј»тЈїжЊЙУАе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-тЙфуј»тЈїжЊЙУАе&#34;&gt;#&lt;/a&gt; 2сђЂтЙфуј»тЈїжЊЙУАе№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	ућ▒тЙфуј»тЇЋжЊЙУАеуџёт«џС╣ЅСИЇжџЙжђђтЄ║т»╗СйаТЇбтЈїжЊЙУАесђѓСИЇтљїуџёТў»тюетЙфуј»тЈїжЊЙУАеСИГ№╝їтц┤у╗Њуѓ╣уџё prior ТїЄжњѕУ┐ўУдЂТїЄтљЉУАет░Йу╗Њуѓ╣№╝їтдѓСИІтЏЙ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/7aa6062623704f9abe809b2910d86dd6.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тюетЙфуј»тЈїжЊЙУАе L СИГ№╝їТЪљУіѓуѓ╣ *p СИ║т░Йу╗Њуѓ╣ТЌХ№╝їp-&amp;gt;next == L №╝ЏтйЊтЙфуј»тЈїжЊЙУАеСИ║уЕ║УАеТЌХ№╝їтЁХтц┤у╗Њуѓ╣уџё prior тЪЪтњї next тЪЪжЃйуГЅС║ј L сђѓ&lt;/p&gt;
&lt;h2 id=&#34;235-жЮЎТђЂжЊЙУАе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#235-жЮЎТђЂжЊЙУАе&#34;&gt;#&lt;/a&gt; 2.3.5сђЂжЮЎТђЂжЊЙУАе№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	жЮЎТђЂжЊЙУАетђЪтіЕТЋ░у╗ёТЮЦТЈЈУ┐░у║┐ТђДУАеуџёжЊЙт╝ЈтГўтѓеу╗ЊТъё№╝їу╗Њуѓ╣С╣ЪТюЅТЋ░ТЇ«тЪЪ data тњї ТїЄжњѕтЪЪ next №╝їСИјС╣ІтЅЇуџёжЊЙУАеСИГуџёТїЄжњѕСИЇтљїуџёТў»№╝їУ┐ЎжЄїуџёТїЄжњѕТў»у╗Њуѓ╣уџёуЏИт»╣тю░тЮђ№╝ѕТЋ░у╗ёСИІТаЄ№╝Ѕ№╝їтЈѕуД░ТИИТаЄсђѓтњїжА║т║ЈУАеСИђТаи№╝їжЮЎТђЂжЊЙУАеС╣ЪУдЂжбётЁѕтѕєжЁЇСИђТ«хУ┐ъу╗ГуџётєЁтГўуЕ║жЌ┤сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	жЮЎТђЂжЊЙУАетњїтЇЋжЊЙУАеуџёт»╣т║ћтЁ│у│╗тдѓСИІсђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/2a2e6df4ef5a4cc6b62218841143f149.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	жЮЎТђЂжЊЙУАеу╗ЊТъёу▒╗тъІуџёТЈЈУ┐░тдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MaxSize 50&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ElemType data;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; next;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;SLinkList[MaxSize];&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	жЮЎТђЂжЊЙУАеС╗Ц next == 1 СйюСИ║тЁХу╗ЊТЮЪуџёТаЄт┐ЌсђѓжЮЎТђЂжЊЙУАеуџёТЈњтЁЦсђЂтѕажЎцТЊЇСйюСИјтіеТђЂжЊЙУАеуџёуЏИтљї№╝їтЈфжюђУдЂС┐«Тћ╣ТїЄжњѕ№╝їУђїСИЇжюђУдЂуД╗тіетЁЃу┤а№╝їжЮЎТђЂжЊЙУАеТ▓АТюЅтЇЋжЊЙУАеСй┐ућеУхиТЮЦТќ╣СЙ┐№╝їСйєтюеСИђС║ЏСИЇТћ»ТїЂТїЄжњѕуџёжФўу║ДУ»ГУеђСИГ№╝їУ┐ЎТў»СИђуДЇжЮътИИтиДтдЎуџёУ«ЙУ«АТќ╣Т│Ћсђѓ&lt;/p&gt;

 &lt;h1 id=&#34;уѕгУЎФУјитЈќТЅђТюЅтЏЙуЅЄ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#уѕгУЎФУјитЈќТЅђТюЅтЏЙуЅЄ&#34;&gt;#&lt;/a&gt; уѕгУЎФУјитЈќТЅђТюЅтЏЙуЅЄ№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;УЃїТЎ»&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#УЃїТЎ»&#34;&gt;#&lt;/a&gt; УЃїТЎ»№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ		ТюђУ┐ЉтЂџСИђС║Џ Web жбў№╝їтЈЉуј░С║єС║ЏуйЉжАхуџёУЃїТЎ»С╝џжџЈТю║тЄ║уј░№╝їТ»ЈСИђТгАтѕиТќ░жЃйС╝џтЄ║уј░СИЇСИђТаиуџётЏЙ№╝їТёЪУДЅТюЅуѓ╣ТёЈТђЮ№╝їУ»ЋуЮђуаћуЕХСИІ№╝їтйЊуёХ№╝їУѓ»т«џСИЇТў»уаћуЕХтњІт╝ёуџёУ┐ЎСИф№╝їУђїТў»№╝їapi жЄїуџётЏЙТђјС╣ѕуѕгтЈќ№╝џ&lt;/p&gt;
&lt;h2 id=&#34;ждќтЁѕ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ждќтЁѕ&#34;&gt;#&lt;/a&gt; ждќтЁѕ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ		ТјЦтЈБТќЄТАБтдѓСИІ№╝џ&lt;/p&gt;
&lt;p&gt;С╣ІтљјуЏ┤ТјЦСИіТ║љуаЂ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; requests&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; os&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;pe&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3400&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url = &lt;span class=&#34;string&#34;&gt;&amp;quot;https://img.loliapi.cn/i/pe/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        resp = requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; resp.status_code == &lt;span class=&#34;number&#34;&gt;404&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; os.path.exists(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pe/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i)):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pe/img&amp;#123;&amp;#125;.webpти▓тГўтюе&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;pass&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pe/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i), &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                f.write(resp.content)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;pc&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;690&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1000&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url = &lt;span class=&#34;string&#34;&gt;&amp;quot;https://img.loliapi.cn/i/pc/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        resp = requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; resp.status_code == &lt;span class=&#34;number&#34;&gt;404&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; os.path.exists(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pc/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i)):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pc/img&amp;#123;&amp;#125;.webpти▓тГўтюе&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;pass&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./img/pc/img&amp;#123;&amp;#125;.webp&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(i),&lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                f.write(resp.content)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; __name__ == &lt;span class=&#34;string&#34;&gt;&amp;#x27;__main__&amp;#x27;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    model = &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;input&lt;/span&gt;())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; model == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pc()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;elif&lt;/span&gt; model == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pe()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;тЄаСИфСИЇжћЎуџёapi&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#тЄаСИфСИЇжћЎуџёapi&#34;&gt;#&lt;/a&gt; тЄаСИфСИЇжћЎуџё api№╝џ&lt;/h1&gt;
&lt;p&gt;Те▒Уі▒С║їТгАтЁЃтЏЙуЅЄ API-Dmoe&lt;/p&gt;
&lt;p&gt;РђІ		&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuZG1vZS5jYy8=&#34;&gt;https://www.dmoe.cc/&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;жџЈТю║тЏЙ API&lt;/p&gt;
&lt;p&gt;РђІ		&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pbWFnZS5hbm9zdS50b3AvaW5kZXguaHRtbA==&#34;&gt;https://image.anosu.top/index.html&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;LoliApi№╝џ&lt;/p&gt;
&lt;p&gt;РђІ		&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb2NzLmxvbGlhcGkuY29tLw==&#34;&gt;https://docs.loliapi.com/&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;жџЈТю║тЏЙ APIРђћРђћ жџЈТю║У┐ћтЏъТѕЉУђЂтЕє№╝ѕ&lt;/p&gt;
&lt;p&gt;РђІ		&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmppdHN1LnRvcC9hcmNoaXZlcy8zLw==&#34;&gt;https://blog.jitsu.top/archives/3/&lt;/span&gt;&lt;/p&gt;

 &lt;h1 id=&#34;misc&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#misc&#34;&gt;#&lt;/a&gt; Misc№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;1-ТХљУ┤фТЂІтњїС╝▒-ућЙ7d├ЕТ»јтЁ«Т»јуДњ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-ТХљУ┤фТЂІтњїС╝▒-ућЙ7d├ЕТ»јтЁ«Т»јуДњ&#34;&gt;#&lt;/a&gt; 1сђЂТХљУ┤фТЂІтњїС╝▒сђЂућЙРђЋРЉ║d├Е Т»јтЁ«Т»јуДњ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	жбўуЏ«ТЈЈУ┐░№╝џlaosebi№╝їТЌаУёЉ LSB жџљтєЎ№╝їтЁетЈќТюђСйјСйЇуџё LSB жџљтєЎ№╝їТІ┐тѕ░ flagсђѓТюЅтцДСйгуЏ┤ТјЦ&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT16c3RlZyZhbXA7c3BtPTEwMDEuMjEwMS4zMDAxLjcwMjA=&#34;&gt; zsteg&lt;/span&gt; уДњС║є№╝їтюеУ┐ЎжЄїТЈљСИђСИІ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/26e0013c62b2436084480bade59025b5.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;2-СйаУ»┤тЙЌт»╣Сйє__&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-СйаУ»┤тЙЌт»╣Сйє__&#34;&gt;#&lt;/a&gt; 2сђЂСйаУ»┤тЙЌт»╣№╝їСйє__&lt;/h2&gt;
&lt;p&gt;РђІ	СИІУййСИІТЮЦТў»СИђСИфтЏЙуЅЄ№╝їжђџУ┐Є foremost тѕєуд╗тЏЙуЅЄ№╝їтЙЌтѕ░тЏЏт╝атЏЙуЅЄ№╝їТ»ЈСИђт╝ажЃйТў»СИђСИфС║їу╗┤уаЂуџёСИђжЃетѕє№╝їТІ╝тЄ║ТЮЦТЅФСИђСИІт░▒УАїС║є№╝їт«їС║Ітё┐№╝џ&lt;/p&gt;
