&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;idx? &amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  __isoc99_scanf(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;, &amp;amp;v0);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ( v0 &amp;lt;= &lt;span class=&#34;number&#34;&gt;0xF&lt;/span&gt; &amp;amp;&amp;amp; *(&amp;amp;ptr + (&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt;)v0) )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;free&lt;/span&gt;(*(&amp;amp;ptr + (&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt;)v0));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;no such chunk!&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	ућ▒С║јтюе free ТјЅСИђСИф chunk С╣ІтљјТ▓АТюЅт»╣тЁХТїЄжњѕУ┐ЏУАїуй«жЏХ№╝їТЅђС╗ЦУ┐ЎжЄїтЈ»УЃйС║ДућЪС║є UAF№╝їТъюуёХ№╝їТѕЉтцфУЈюС║є№╝їТюђу«ђтЇЋуџё UAF жЃйуюІСИЇТЄѓ№╝їУиЪуЮђтцДСйгуюІуюІу«ЌС║є№╝їТа╣ТЇ«тцДСйгС╗гуџё wp№╝їС╝╝С╣јТў»жђџУ┐ЄТ│ёжю▓__malloc_hook уџётю░тЮђ№╝їуёХтљјТа╣ТЇ«тіеТђЂжЊЙТјЦт║ЊТќЄС╗Ху«ЌтЂЈуД╗№╝їТІ┐тѕ░ /bin/sh уГЅуџётю░тЮђ№╝їтЁиСйЊтјЪуљєС╣ІтљјтєЇуюІ№╝їтЁѕС║єУДБСИІУ┐ЎТў»СИфтЋЦСИюУЦ┐№╝їтњІТЊЇСйюуџё№╝їуЏ┤ТјЦУ┤┤СИђСИфтцДСйгуџё exp№╝џ&lt;/p&gt;
