&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LitCTF&amp;#123;Give_y0ur_hand_to_me!!!_plz&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;6-уа┤ТЇЪуџётЏЙуЅЄтѕЮу║Д&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-уа┤ТЇЪуџётЏЙуЅЄтѕЮу║Д&#34;&gt;#&lt;/a&gt; 6сђЂуа┤ТЇЪуџётЏЙуЅЄ (тѕЮу║Д)&lt;/h2&gt;
&lt;p&gt;РђІ	ТќЄС╗Хуће 010editor у╝ќУЙЉ№╝їТи╗СИі % pngРђд№╝їС╣Ът░▒Тў» 89504E470D0A1A0A№╝їтєЇт░єтЏЙуЅЄжЄЇтЉйтљЇСИ║.png тЏЙуЅЄ№╝їТЅЊт╝ђтЏЙуЅЄСЙ┐Тў» flag№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LitCTF&amp;#123;May you, the beauty of this world, always shine.&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;7-osintт░Јж║дТъюТ▒Ђ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7-osintт░Јж║дТъюТ▒Ђ&#34;&gt;#&lt;/a&gt; 7сђЂOsint т░Јж║дТъюТ▒Ђ&lt;/h2&gt;
&lt;p&gt;РђІ	ТѕЉ tm№╝їТЃ│Тџ┤ТЅЊтЄ║жбўС║║№╝їу«ЌС║є№╝їт┐Їт┐Їсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	СИіжЮбуюІтѕ░СИђСИфтЙѕТўјТўЙуџётГЌугд№╝їуюІУхиТЮЦтЃЈТў» wifi тљЇ№╝їhacker&amp;amp;craft№╝їуЏ┤ТјЦтюеуЎЙт║дтю░тЏЙТљюу┤бж╗Љт«б№╝їтЈЉуј░С║єСИђСИфтљЇтГЌ№╝їж╗Љт«бСИју▓ЙжЁ┐№╝їflag№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LitCTF&amp;#123;ж╗Љт«бСИју▓ЙжЁ┐&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;8-easy_shark&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#8-easy_shark&#34;&gt;#&lt;/a&gt; 8сђЂeasy_shark&lt;/h2&gt;
&lt;p&gt;РђІ	тЈѕТў»СИфТг║У┤ЪТѕЉ 010 ТюЅжЌ«жбў№╝їуюЪТюЇС║є№╝їТЃ│Тџ┤ТЅЊтЄ║жбўС║║сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	У┐ўТў»У»┤СИІТђЮУи»т░▒УАїС║єтљД№╝їТІќУ┐Џ 010№╝їС┐«Тћ╣ 90 00 СИ║ 00 00 тЇ│тЈ»№╝їуёХтљјСИЇућет»єуаЂУДБтјІ№╝їУ┐йУИф http ТхЂ№╝їтюетцџСИф http ТхЂСИГТЅЙтѕ░С║єСИђСИф php СИђтЈЦУ»ЮТюежЕг№╝їуёХтљјтєЇТЅЙ№╝їуггС║ћтЇЂтЄаСИфт░▒УЃйТЅЙтѕ░СИфТќ╣уеІ№╝їуёХтљјСИцСИф key№╝їт║ћУ»ЦТў»С╗┐т░ёт»єуаЂ№╝їС╗ЦтЈі #тљјжЮбТў»СИђСИфтГЌугдСИ▓№╝їТа╝т╝ЈтЙѕТЃ│ flagсђѓС╣ІтљјС╗┐т░ёт»єуаЂУДБтє│№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LitCTF&amp;#123;w13e5hake_1s_a_900d_t3a771c_t001_a&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;9-osint-ТјбтДгтј╗тЊфС║є_0&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#9-osint-ТјбтДгтј╗тЊфС║є_0&#34;&gt;#&lt;/a&gt; 9сђЂOSINT ТјбтДгтј╗тЊфС║є№╝Ъ_0&lt;/h2&gt;
&lt;p&gt;РђІ	тЈѕТў»уцЙтиЦ (T^T)№╝џ&lt;/p&gt;
&lt;p&gt;otfound (тѕЮу║Д)&lt;/p&gt;
&lt;p&gt;РђІ	СИђт╝атЏЙуЅЄ№╝їУ«░С║ІТюгТЅЊт╝ђ№╝їтЅЇтЄаУАїТюЅ flag№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LitCTF&amp;#123;Its_404_but_1ts_n0t_a_page&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;java-ioтиЦСйюТю║тѕХ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java-ioтиЦСйюТю║тѕХ&#34;&gt;#&lt;/a&gt; Java I/O тиЦСйюТю║тѕХ№╝џ&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Т│е№╝џу«ђУдЂугћУ«░№╝їуц║СЙІС╗БуаЂтЈ»УЃйУЙЃт░Љ№╝їућџУЄ│Т▓АТюЅсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;1-java-уџё-io-у▒╗т║ЊуџётЪ║ТюгТъХТъё&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-java-уџё-io-у▒╗т║ЊуџётЪ║ТюгТъХТъё&#34;&gt;#&lt;/a&gt; 1сђЂJava уџё I/O у▒╗т║ЊуџётЪ║ТюгТъХТъёсђѓ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	Java уџё I/O ТЊЇСйюу▒╗тюетїЁ java.io СИІ№╝їтцДТдѓТюЅт░єУ┐Љ80СИфу▒╗№╝їУ┐ЎС║Џу▒╗тцДТдѓтЈ»С╗ЦтѕєСИ║тдѓСИІтЏЏу╗ёсђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;тЪ║С║јтГЌУіѓТЊЇСйюуџё I/O ТјЦтЈБ№╝џInputStream тњї OutputStream сђѓ&lt;/li&gt;
&lt;li&gt;тЪ║С║јтГЌугдТЊЇСйюуџё I/O ТјЦтЈБ№╝џWriter тњї Reader сђѓ&lt;/li&gt;
&lt;li&gt;тЪ║С║јуБЂуЏўТЊЇСйюуџё I/O ТјЦтЈБ№╝џFileсђѓ&lt;/li&gt;
&lt;li&gt;тЪ║С║јуйЉу╗юТЊЇСйюуџё I/O ТјЦтЈБ№╝џSocketсђѓ&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;11-тЪ║С║јтГЌУіѓуџё-io-ТЊЇСйюТјЦтЈБ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#11-тЪ║С║јтГЌУіѓуџё-io-ТЊЇСйюТјЦтЈБ&#34;&gt;#&lt;/a&gt; 1.1сђЂтЪ║С║јтГЌУіѓуџё I/O ТЊЇСйюТјЦтЈБ&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;	тЪ║С║јтГЌУіѓуџё I/O ТЊЇСйюТјЦтЈБУЙЊтЁЦтњїУЙЊтЄ║тѕєтѕФТў»№╝џInputStream тњї OutputStream сђѓInputStream уџёу▒╗т▒ѓТгАтдѓСИІ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/93c3c26c8f0c429d9c12af10d397733a.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	УЙЊтЁЦТхЂТа╣ТЇ«ТЋ░ТЇ«у▒╗тъІтњїТЊЇСйюТќ╣т╝ЈтЈѕУбФтѕњтѕєСИ║УІЦт╣▓СИфтГљу▒╗№╝їТ»ЈСИфтГљу▒╗тѕєтѕФтцёуљєСИЇтљїТЊЇСйюу▒╗тъІсђѓOutputStream  уџёу▒╗т▒ѓТгАу╗ЊТъёС╣Ъу▒╗С╝╝№╝їтдѓСИІтЏЙ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/00775864970f46c398a03144a73f5731.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;12-тЪ║С║јтГЌугдуџё-io-ТЊЇСйюТјЦтЈБ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#12-тЪ║С║јтГЌугдуџё-io-ТЊЇСйюТјЦтЈБ&#34;&gt;#&lt;/a&gt; 1.2сђЂтЪ║С║јтГЌугдуџё I/O ТЊЇСйюТјЦтЈБ&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;	СИІтЏЙТў»тєЎтГЌугдуџё I/O ТЊЇСйюТјЦтЈБТХЅтЈіуџёу▒╗№╝їWriter у▒╗ТЈљСЙЏС║єСИђСИфТійУ▒АТќ╣Т│Ћ write(char cbuf[],int off,int len)сђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/c64a10bb54654d2582c6ab90569e86af.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	У»╗тГЌугдуџёТЊЇСйюТјЦтЈБС╣ЪТюЅу▒╗С╝╝уџёу╗ЊТъё№╝їтдѓСИІтЏЙ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/f5005cbcaaff4263931e50ded600ba04.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	У»╗тГЌугдуџёТЊЇСйюТјЦтЈБТў» int read(char cbuf[],int off,int len)№╝їсђѓУ┐ћтЏъУ»╗тѕ░уџёnСИфтГЌУіѓТЋ░№╝їСИЇу«АТў» Writer У┐ўТў» Reader у▒╗№╝їт«ЃС╗гжЃйтЈфт«џС╣ЅС║єУ»╗тЈќТѕќтєЎтЁЦуџёТЋ░ТЇ«тГЌугдуџёТќ╣т╝Ј№╝їС╣Ът░▒Тў»ТђјС╣ѕтєЎТѕќУ»╗сђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;13-тГЌУіѓСИјтГЌугдуџёУйгтїќТјЦтЈБ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#13-тГЌУіѓСИјтГЌугдуџёУйгтїќТјЦтЈБ&#34;&gt;#&lt;/a&gt; 1.3сђЂтГЌУіѓСИјтГЌугдуџёУйгтїќТјЦтЈБ&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;	тГЌугдтѕ░тГЌУіѓжюђУдЂУйгтїќ№╝їтЁХСИГ№╝їУ»╗уџёУйгтїќУ┐ЄуеІтдѓСИІ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/0430cb0a57574ced8bd3c3a5d50eb254.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	InputStreamReader у▒╗Тў»тГЌУіѓтѕ░тГЌугдуџёУйгтїќТАЦТбЂ№╝їInputSream тѕ░ Reader уџёУ┐ЄуеІУдЂТїЄт«џу╝ќуаЂтГЌугджЏє№╝їтљдтѕЎт░єжЄЄућеТЊЇСйюу│╗у╗Ъж╗ўУ«цтГЌугджЏє№╝їтЙѕтЈ»УЃйС╝џтЄ║уј░С╣▒уаЂжЌ«жбўсђѓSteamDecoder ТГБТў»т«їТѕљтГЌУіѓтѕ░тГЌугдуџёУДБуаЂуџёт«ъуј░у▒╗сђѓу▒╗С╝╝тдѓСИІС╗БуаЂУ»╗тѕ░СИђСИфТќЄС╗ХТЌХ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;StringBuffer&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;str&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;StringBuffer&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;char&lt;/span&gt;[] buf = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;char&lt;/span&gt;[&lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;FileReader&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;f&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;FileReader&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;file&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (f.read(buf) &amp;gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                str.append(buf);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            str.toString();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (IOException e)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	FileReader у▒╗т░▒Тў»ТїЅуЁДСИіжЮбуџётиЦСйюТќ╣т╝ЈУ»╗тЈќТќЄС╗Хуџё№╝їFileReader у╗ДТЅ┐С║є InputStramReader у▒╗№╝їт«ъжЎЁСИіТЌХУ»╗тЈќТќЄС╗ХТхЂ№╝їуёХтљјжђџУ┐Є StreamDecoder УДБуаЂТѕљ char №╝їтЈфСИЇУ┐ЄУ┐ЎжЄїуџёу╝ќуаЂтГЌугджЏєТЌХж╗ўУ«цтГЌугджЏєсђѓ

	тєЎтЁЦС╣ЪТў»у▒╗С╝╝уџёУ┐ЄуеІ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/8b8af04f03ea4ba9851c5648efe58d48.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	жђџУ┐Є OutputStreamWriter у▒╗т«їТѕљтГЌугдтѕ░тГЌУіѓуџёу╝ќуаЂУ┐ЄуеІ№╝їућ▒ StreamEncoder т«їТѕљу╝ќуаЂУ┐ЄуеІсђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;2-уБЂуЏў-io-тиЦСйюТю║тѕХ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-уБЂуЏў-io-тиЦСйюТю║тѕХ&#34;&gt;#&lt;/a&gt; 2сђЂуБЂуЏў I/O тиЦСйюТю║тѕХ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;21-тЄауДЇУ«┐жЌ«ТќЄС╗ХуџёТќ╣т╝Ј&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#21-тЄауДЇУ«┐жЌ«ТќЄС╗ХуџёТќ╣т╝Ј&#34;&gt;#&lt;/a&gt; 2.1сђЂтЄауДЇУ«┐жЌ«ТќЄС╗ХуџёТќ╣т╝Ј&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;ТаЄтЄєУ«┐жЌ«ТќЄС╗ХТќ╣т╝Јсђѓ&lt;/li&gt;
&lt;li&gt;уЏ┤ТјЦ I/O Тќ╣т╝Јсђѓ&lt;/li&gt;
&lt;li&gt;тљїТГЦУ«┐жЌ«ТќЄС╗ХТќ╣т╝Јсђѓ&lt;/li&gt;
&lt;li&gt;т╝ѓТГЦУ«┐жЌ«ТќЄС╗ХТќ╣т╝Јсђѓ&lt;/li&gt;
&lt;li&gt;тєЁтГўТўат░ёТќ╣т╝Јсђѓ&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;22-java-У«┐жЌ«уБЂуЏўТќЄС╗Х&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#22-java-У«┐жЌ«уБЂуЏўТќЄС╗Х&#34;&gt;#&lt;/a&gt; 2.2сђЂJava У«┐жЌ«уБЂуЏўТќЄС╗Х&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;	тйЊС╝атЁЦСИђСИфТќЄС╗ХУи»тЙёТЌХ№╝їт░єС╝џТа╣ТЇ«У┐ЎСИфУи»тЙётѕЏт╗║СИђСИф File т»╣У▒АТЮЦУАеуц║У┐ЎСИфТќЄС╗Х№╝їуёХтљјТа╣ТЇ«У┐ЎСИф File т»╣У▒АтѕЏт╗║уюЪТГБУ»╗тЈќТќЄС╗ХуџёТЊЇСйют»╣У▒А№╝їУ┐ЎТЌХт░єС╝џуюЪТГБтѕЏт╗║СИђСИфтЁ│УЂћуюЪт«ътГўтюеуџёуБЂуЏўТќЄС╗ХуџёТќЄС╗ХТЈЈУ┐░угд FileDescriptor№╝їжђџУ┐ЄУ┐ЎСИфт»╣У▒АтЈ»С╗ЦуЏ┤ТјЦТјДтѕХУ┐ЎСИфуБЂуЏўТќЄС╗Х№╝їсђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/d55db7d024654510987ff7e1cbce21c1.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;23-java-т║ЈтѕЌтїќТіђТю»&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#23-java-т║ЈтѕЌтїќТіђТю»&#34;&gt;#&lt;/a&gt; 2.3сђЂJava т║ЈтѕЌтїќТіђТю»&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;	Java т║ЈтѕЌтїќт░▒Тў»т░єСИђСИфт»╣У▒АУйгтїќСИ║СИђСИ▓С║їУ┐ЏтѕХУАеуц║уџётГЌУіѓТЋ░у╗ё№╝їжђџУ┐ЄС┐ЮтГўТѕќУйгуД╗У┐ЎС║ЏтГЌУіѓТЋ░ТЇ«ТЮЦУЙЙтѕ░ТїЂС╣ЁтїќуџёуЏ«уџёсђѓжюђУдЂТїЂС╣Ётїќ№╝їт»╣У▒Ат┐ЁжА╗у╗ДТЅ┐ java.io.Serializable ТјЦтЈБсђѓтЈЇт║ЈтѕЌтїќтѕЎТў»уЏИтЈЇуџёУ┐ЄуеІ№╝їт░єУ┐ЎСИфтГЌУіѓТЋ░у╗ётєЇжЄЇТќ░ТъёжђаТѕљт»╣У▒АсђѓТѕЉС╗гуЪЦжЂЊтЈЇт║ЈтѕЌтїќТЌХ№╝їт┐ЁжА╗ТюЅтјЪтДІу▒╗СйюСИ║ТеАТЮ┐№╝їТЅЇУЃйт░єУ┐ЎСИфт»╣У▒АУ┐ўтјЪ№╝їС╗јУ┐ЎСИфУ┐ЄуеІТѕЉС╗гтЈ»С╗ЦуїюТхІ№╝їт║ЈтѕЌтїќуџёТЋ░ТЇ«т╣ХСИЇтЃЈ class ТќЄС╗ХжѓБТаиС┐ЮтГўу▒╗уџёт«їТЋ┤уџёу╗ЊТъёС┐АТЂ»сђѓСИІжЮбТў»СИђСИфу«ђтЇЋуџёт║ЈтѕЌтїќуџёС╗БуаЂ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Serialize&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Serializable&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;serialVersionUID&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;6849794470754660011L&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;num&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1390&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;FileOutputStream&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;fos&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;FileOutputStream&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;d:/serialize.dat&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;ObjectOutputStream&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;oos&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;ObjectOutputStream&lt;/span&gt;(fos);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;type&#34;&gt;Serialize&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;serialize&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Serialize&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            oos.writeObject(serialize);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            oos.flush();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            oos.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (IOException e) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            e.printStackTrace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;	т║ЈтѕЌтїќуџёТќЄС╗ХС║їУ┐ЏтѕХтГЌУіѓТЋ░ТЇ«тдѓСИІ№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/6544ad53b377490c9f7a60d5ad99cb04.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;уггСИђжЃетѕєТў»тЈЇт║ЈтѕЌтїќТќЄС╗Хтц┤сђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/ab3ed5c157264bbc833860233f8b314a.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уггС║їжЃетѕєТў»УдЂтЈЇт║ЈтѕЌтїќуџёу▒╗уџёТЈЈУ┐░№╝їтюеУ┐ЎжЄїТў» Serialize у▒╗сђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/7f9959f931e741a4bee64dbd23c56c97.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уггСИЅжЃетѕєТў»т»╣У▒АСИГтљёСИфт▒ъТђДжА╣уџёТЈЈУ┐░&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/4e058285c2b246fa9cfc8c911e61ecfd.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уггтЏЏжЃетѕєУЙЊтЄ║У»Цт»╣У▒АуџёуѕХу▒╗С┐АТЂ»ТЈЈУ┐░№╝їУ┐ЎжЄїТ▓АТюЅуѕХу▒╗№╝їтдѓТъюТюЅ№╝їТЋ░ТЇ«Та╝т╝ЈСИјуггС║їжЃетѕєСИђТаисђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/67a0a799eefe4e809e27094075061210.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уггС║ћжЃетѕєУЙЊтЄ║т»╣У▒Ауџёт▒ъТђДжА╣уџёт«ъжЎЁтђ╝№╝їтдѓТъют▒ъТђДжА╣Тў»СИђСИфт»╣У▒А№╝їжѓБС╣ѕУ┐ЎжЄїУ┐ўт░єт║ЈтѕЌтїќУ┐ЎСИфт»╣У▒А№╝їУДётѕЎтњїуггС║їжЃетѕєСИђТаисђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/e6306bc60426477eb218df3426486b27.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;&lt;strong&gt;Т│е№╝џтЏаСИ║ТѕЉт╣ХСИЇт«їтЁеТў»СИ║С║єС╗ј 0 т╝ђтДІ Java т╝ђтЈЉ№╝їтЏаТГц№╝їТѕЉУ┐ЎжЄїтЁѕТџѓТЌХУи│У┐ЄуггС║їуФаТюЇтіАтЎеуј»тбЃуЏИтЁ│уџётєЁт«╣№╝їуЏ┤ТјЦт╝ђтДІуггСИЅуФауџётєЁт«╣сђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;h1 id=&#34;31-servlet-уџётЪ║Тюгу╗ЊТъё&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#31-servlet-уџётЪ║Тюгу╗ЊТъё&#34;&gt;#&lt;/a&gt; 3.1сђЂServlet уџётЪ║Тюгу╗ЊТъё№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	СИІжЮбуџёС╗БуаЂу╗ЎтЄ║С║єСИђСИфтЪ║Тюгуџё Servlet №╝їт«Ѓтцёуљє GET У»иТ▒ѓсђѓGET У»иТ▒ѓТў»ТхЈУДѕтЎеУ»иТ▒ѓуџётИИУДЂу▒╗тъІ№╝їућеТЮЦУ»иТ▒ѓ Web жАхжЮбсђѓућеТѕитюетю░тЮђТаЈСИГУЙЊтЁЦ URL сђЂуѓ╣тЄ╗ Web жАхжЮбтєЁуџёУ┐ъТјЦсђЂТѕќТЈљС║цТ▓АТюЅТїЄт«џ METHOD Тѕќ METHOD=РђюGETРђЮ уџё HTML УАетЇЋТЌХ№╝їТхЈУДѕтЎежЃйС╝џућЪТѕљУ┐ЎСИфУ»иТ▒ѓсђѓ Servlet У┐ўтЈ»С╗Цт«╣ТўЊтю░тцёуљє POST У»иТ▒ѓ№╝ѕТЈљС║ц METHOD=РђюPOSTРђЮ уџё HTML УАетЇЋТЌХ№╝їС╝џућЪТѕљ POST У»иТ▒ѓ№╝ЅсђѓHTML УАетЇЋуџёСй┐ућеу╗єУіѓС╗ЦтЈі GET тњї POST С╣ІжЌ┤уџётї║тѕФсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.ServletException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletRequest;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletResponse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.PrintWriter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;ServletTemplate&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HttpServlet&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;doGet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HttpServletRequest req, HttpServletResponse resp)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServletException, IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//Use &amp;quot;request&amp;quot; to read incoming HTTP headers&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//(e.g.,Cookies) and query data from HTML forms .&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//Use &amp;quot;response&amp;quot; to specify the HTTP response status&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//code and headers (e.g.,the content type ,cookies)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;PrintWriter&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;out&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; resp.getWriter();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//Use &amp;quot;out&amp;quot; to send content to browser&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	Servlet СИђУѕгТЅЕт▒Ћ HttpServlet №╝їт╣ХСЙЮТЋ░ТЇ«тЈЉжђЂТќ╣т╝ЈуџёСИЇтљї№╝ѕGET Тѕќ POST№╝Ѕ№╝їУдєуЏќ doGet Тѕќ doPost Тќ╣Т│ЋсђѓтдѓТъютИїТюЏ Servlet т»╣ GET тњї POST У»иТ▒ѓжЄЄућетљїТаиуџёУАїтіе№╝їтЈфжюђУдЂУ«Е doGet У░Ѓуће doPost №╝їтЈЇС╣І№╝їСЙЮуёХсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	doGet тњї doPost жЃйТјЦтЈЌСИцСИфтЈѓТЋ░№╝џHttpServletRequest тњї HttpServletResponse сђѓжђџУ┐Є HttpServletRequest№╝їтЈ»С╗ЦтЙЌтѕ░ТЅђТюЅуџёУЙЊтЁЦТЋ░ТЇ«№╝ЏУ┐ЎСИфу▒╗ТЈљСЙЏуЏИт║ћуџёТќ╣Т│Ћ№╝їжђџУ┐ЄУ┐ЎС║ЏТќ╣Т│ЋтЈ»С╗ЦТЅЙтЄ║У»ИтдѓУАетЇЋ№╝ѕТЪЦУ»б№╝ЅТЋ░ТЇ«сђЂHTTP У»иТ▒ѓТіЦтц┤тњїт«бТѕиуџёСИ╗Тю║тљЇуГЅС┐АТЂ»сђѓжђџУ┐Є HttpServletResponse тЈ»С╗ЦтѕХт«џУЙЊтЄ║С┐АТЂ»№╝їТ»ћтдѓ HTTP уіХТђЂС╗БуаЂ№╝ѕ200№╝ї404 уГЅ№╝ЅтњїтЊЇт║ћТіЦтц┤№╝ѕContent-Type№╝їSet-Cookie уГЅ№╝ЅсђѓТюђжЄЇУдЂуџёТў»№╝їжђџУ┐Є HttpServletResponse тЈ»С╗ЦУјитЙЌ PrintWriter №╝їућет«ЃтЈ»С╗Цт░єТќЄТАБтєЁт«╣тЈЉжђЂу╗Ўт«бТѕисђѓт»╣С║ју«ђтЇЋуџё Servlet №╝їтцДжЃетѕєтиЦСйюжЃйУі▒тюеуће println У»ГтЈЦућЪТѕљТюЪТюЏуџёжАхжЮбСИісђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ућ▒С║ј doGet тњї doPost  ТіЏтЄ║СИцуДЇт╝ѓтИИ№╝ѕServletException тњї IOException№╝Ѕ№╝їТЅђС╗ЦтюеТќ╣Т│ЋтБ░ТўјСИГтїЁТІгС╗ќС╗гсђѓТюђтљј№╝їУ┐ўт┐ЁжА╗т»╝тЁЦ &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2phdmEuaW8=&#34;&gt;java.io&lt;/span&gt;№╝ѕPrintWrite уГЅ№╝ЅсђЂjavax.servlet№╝ѕHttpServlet уГЅ№╝Ѕтњї javax.servlet.http№╝ѕHttpServletResponse тњї HttpServletRequest№╝ЅСИГуџёу▒╗сђѓ&lt;/p&gt;
&lt;h1 id=&#34;32-ућЪТѕљу║»ТќЄТюгуџё-servlet&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#32-ућЪТѕљу║»ТќЄТюгуџё-servlet&#34;&gt;#&lt;/a&gt; 3.2сђЂућЪТѕљу║»ТќЄТюгуџё Servlet №╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	С╗БуаЂ 3.2 тѕЌтЄ║С║єСИђСИфУЙЊтЄ║у║»ТќЄТюгуџёу«ђтЇЋ Servlet№╝їтЏЙ 3.2 Тў»т«ЃуџёУЙЊтЄ║сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//С╗БуаЂ 3.2 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.ServletException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.annotation.WebServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletRequest;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletResponse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.PrintWriter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@WebServlet(&amp;quot;/hello&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HelloWorld&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HttpServlet&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;doGet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HttpServletRequest req, HttpServletResponse resp)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServletException, IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;PrintWriter&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;out&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; resp.getWriter();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;Hello World&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЏЙ 3.2№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/5c0bf5adcfa84c18800d9ca4c37c61c3.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;33-ућЪТѕљ-html-уџё-servlet&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#33-ућЪТѕљ-html-уџё-servlet&#34;&gt;#&lt;/a&gt; 3.3сђЂућЪТѕљ HTML уџё Servlet№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	тцДтцџТЋ░уџё Servlet ућЪТѕљ HTML №╝їУђїжЮътЅЇУ┐░СЙІтГљСИГуџёу║»ТќЄТюгсђѓУдЂућЪТѕљ HTML №╝їжюђУдЂтюетѕџТЅЇС╗Іу╗ЇуџёУ┐ЄуеІСИГтіатЁЦтдѓСИІСИЅТГЦ№╝џ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;тЉіуЪЦТхЈУДѕтЎе№╝їтЇ│т░єтљЉт«ЃтЈЉжђЂ  HTML сђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;С┐«Тћ╣ println У»ГтЈЦ№╝їТъёт╗║тљѕТ│Ћуџё Web жАхжЮбсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ућетйбт╝ЈУ»ГТ│ЋТБђжфїтЁХ№╝ѕformat syntax validator№╝ЅТБђТЪЦућЪТѕљуџё HTMLсђѓ&lt;/p&gt;
&lt;p&gt;уггСИђТГЦжђџУ┐Єт░є HTTP Content-Type тЊЇт║ћТіЦтц┤У«ЙСИ║ text/html ТЮЦт«їТѕљсђѓСИђУѕгУђїУеђ№╝їТіЦтц┤Сй┐уће HttpServletResponse уџё setHeader Тќ╣Т│ЋТЮЦУ«Йуй«№╝їСйєућ▒С║јУ«Йуй«тєЁт«╣уџёу▒╗тъІТў»СИђжА╣тЇЂтѕєтИИУДЂуџёС╗╗тіА№╝їтЏаУђї№╝їHttpServletResponse ТЈљСЙЏуЅ╣Т«іуџё setContentType Тќ╣Т│Ћ№╝їСИЊжЌеућеС║јУ┐ЎуДЇуЏ«уџёсђѓТїЄТўј HTML уџёТќ╣т╝ЈТў»Сй┐уће text/html у▒╗тъІ№╝їтЏаТГц№╝їС╗БуаЂт║ћУ»ЦтдѓСИІ№╝џ&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;resp.setContentType(&lt;span class=&#34;string&#34;&gt;&amp;quot;text/html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	т░йу«А HTML Тў» Servlet тѕЏт╗║уџёТюђтИИУДЂуџёТќЄТАБу▒╗тъІ№╝їСйєТў»№╝їServlet тѕЏт╗║тЁХС╗ќу▒╗тъІТќЄТАБуџёТЃЁтєхС╣ЪтЙѕтИИУДЂсђѓСЙІтдѓ№╝їСй┐уће Servlet ућЪТѕљуџё Excel УАеТа╝№╝ѕтєЁт«╣у▒╗тъІТў» application/vnd.ms-excel№╝ЅсђЂJPEG тЏЙтЃЈ№╝ѕтєЁт«╣у▒╗тъІТў» image/jpeg №╝Ѕтњї XML ТќЄТАБ№╝ѕтєЁт«╣у▒╗тъІТў» text/xml№╝ЅуџёТЃЁтєхС╣ЪТў»тЇЂтѕєтИИУДЂсђѓтљїТЌХ№╝їСИђУѕгтЙѕт░ЉСй┐уће Servlet ућЪТѕљТа╝т╝ЈуЏИт»╣тЏ║т«џуџё HTML жАхжЮб№╝ѕтЇ│Т»ЈТгАУ»иТ▒ѓ№╝їжАхжЮбуџётИЃт▒ђТћ╣тіетЙѕт░Ј№╝Ѕ№╝ЏУ┐ЎуДЇТЃЁтєхСИІ JSP тИИтИИТЏ┤СИ║Тќ╣СЙ┐сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	жюђУдЂТ│еТёЈуџёТў»№╝џжюђУдЂтюе PrintWriter т«ъжЎЁУ┐ћтЏъС╗╗СйЋтєЁт«╣С╣ІтЅЇ№╝їУ«Йуй«тЊЇт║ћТіЦтц┤сђѓУ┐ЎТў»ућ▒С║ј HTTP тЊЇт║ћућ▒уіХТђЂУАїсђЂСИђСИфТѕќтцџСИфТіЦтц┤сђЂСИђСИфуЕ║УАїтњїт«ъжЎЁуџёТќЄТАБСИђТгАТгАт║ЈТъёТѕљсђѓтїЁтц┤уџётЄ║уј░ТгАт║Јт╣ХСИЇжЄЇУдЂ№╝їServlet С╝џу╝Њтє▓ТіЦтц┤ТЋ░ТЇ«№╝їт░єС╗ќС╗гСИђТгАТ│ЋТАѕжђЂтѕ░т«бТѕиуФ»№╝їтЏаТГц№╝їтЇ│Сй┐тюеУ«Йт«џТіЦтц┤С╣Ітљј№╝їСЙЮТЌДтЈ»С╗ЦУ«Йуй«уіХТђЂС╗БуаЂ№╝ѕт▒ъС║јУ┐ћтЏътєЁт«╣уџёуггСИђУАї№╝ЅсђѓСйєТў»№╝їServlet СИЇТў»СИђт«џУдЂу╝Њтє▓ТќЄТАБТюгУ║Ф№╝їтЏаСИ║т»╣С║ју»Єт╣ЁУЙЃжЋ┐уџёжАхжЮб№╝їућеТѕиТѕќУ«ИтЈфтИїТюЏуюІтѕ░жЃетѕєу╗ЊТъюсђѓServlet т╝ЋТЊјтЈ»С╗Цу╝Њтє▓жЃетѕєУЙЊтЄ║№╝їСйєт╣ХТюфУДёт«џу╝Њтє▓тї║уџётцДт░ЈсђѓтЈ»С╗ЦСй┐уће HttpServletResponse тњї getBufferSize Тќ╣Т│ЋуА«т«џУ┐ЎСИфтцДт░Ј№╝їТѕќСй┐уће setBufferSize ТїЄт«џУ┐ЎСИфтцДт░ЈсђѓС╣ЪтЈ»С╗Цтюеу╝Њтє▓тї║тАФТ╗А№╝їУдЂтЈЉтЙђт«бТѕиТЌХ№╝їт»╣ТіЦтц┤У┐ЏУАїУ«Йуй«сђѓтдѓТъюСИЇуА«т«џу╝Њтє▓тї║Тў»тљдти▓у╗ЈтЈЉжђЂтЄ║тј╗№╝їтЈ»С╗ЦСй┐уће isCommitted Тќ╣Т│ЋТЮЦТБђТЪЦсђѓтЈіТЌХтдѓТГц№╝їТюђСй│уџёТќ╣ТАѕУ┐ўТў»т░є setContentType УАїТћЙтюеС╗╗СйЋ PrintWrite уџёУАїС╣ІтЅЇсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	&lt;strong&gt;УГдтЉі№╝џт┐ЁжА╗тюеС╝ажђЂт«ъжЎЁуџёТќЄТАБС╣ІтЅЇУ«Йт«џтєЁт«╣уџёу▒╗тъІсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тюеу╝ќтєЎТъёт╗║ HTML ТќЄТАБуџё Servlet ТЌХ№╝їуггС║їТГЦТЌХуће println У»ГтЈЦУЙЊтЄ║ HTML№╝ѕСИЇтєЇТў»у║»ТќЄТюг№╝ЅсђѓС╗БуаЂ 303 тѕЌтЄ║С║є HelloServlet.java №╝їу╗ЊТъютдѓтЏЙ 3.3 ТЅђуц║№╝їТхЈУДѕтЎеТїЅуЁД HTML ТЮЦТа╝т╝ЈтїќтЙЌтѕ░уџёу╗ЊТъю№╝їУђїжЮъТїЅуЁДу║»ТќЄТюг№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//С╗БуаЂ 3.3&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.ServletException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.annotation.WebServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletRequest;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletResponse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.PrintWriter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@WebServlet(&amp;quot;/hello&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HelloServlet&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HttpServlet&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;doGet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HttpServletRequest req, HttpServletResponse resp)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServletException, IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        resp.setContentType(&lt;span class=&#34;string&#34;&gt;&amp;quot;text/html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;PrintWriter&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;out&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; resp.getWriter();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;String&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;docType&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;!DOCTYPE HTML PUBLIC \&amp;quot;-//W3C//DTD HTML 4.0&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;string&#34;&gt;&amp;quot;Transitional//EN\&amp;quot;&amp;gt;\n&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        out.println(docType +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HTML&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HEAD&amp;gt;&amp;lt;TITLE&amp;gt;Hello&amp;lt;/TITLE&amp;gt;&amp;lt;HEAD&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;BODY BGCOLOR=\&amp;quot;#FDF5E6\&amp;quot;&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;H1&amp;gt;Hello&amp;lt;/H1&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/BODY&amp;gt;&amp;lt;/HTML&amp;gt;&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЏЙ 3.3 №╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/2ff45d069c9f4963b377e8952ef0ca66.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	ТюђтљјСИђТГЦТЌХтљѕжђѓућЪТѕљуџё HTML СИГ№╝їСИЇтГўтюеТюЅтЈ»УЃйС╝џтюеСИЇтљїуџёТхЈУДѕтЎеСИіт╝ЋУхиСИЇтЈ»жбёТюЪу╗ЊТъюуџёУ»ГТ│ЋжћЎУ»»сђѓтЈѓУђЃ 3.5 УіѓСИГТюЅтЁ│ HTML жфїУ»ЂтЁХуџёУ«║У┐░сђѓ&lt;/p&gt;
&lt;h1 id=&#34;34-servlet-уџёТЅЊтїЁ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#34-servlet-уџёТЅЊтїЁ&#34;&gt;#&lt;/a&gt; 3.4сђЂServlet уџёТЅЊтїЁ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	тюеС║ДтЊЂт╝ђтЈЉУ┐ЄуеІСИГ№╝їтцџСИфуеІт║ЈтЉўтЈ»УЃйСИ║тљїСИђТюЇтіАтЎет╝ђтЈЉ ServletсђѓтЏаТГц№╝їт░єТЅђТюЅуџё Servlet ТћЙтѕ░тљїСИђуЏ«тйЋСИГт░єС╝џућЪТѕљТЋ░уЏ«т║ътцДСИћжџЙС╗Цу«Ауљєуџёу▒╗№╝їтдѓТъюСИцСИфт╝ђтЈЉС║║тЉўСИ║ Servlet ТѕќСй┐ућетиЦтЁиу▒╗тљЇТЌХ№╝їСИЇу╗ЈТёЈжЌ┤жђЅТІЕС║єуЏИтљїуџётљЇуД░№╝їУ┐ўС╝џт»╝УЄ┤тЉйтљЇтє▓уфЂсђѓуј░тюе№╝їжђџУ┐Є Web т║ћуће№╝їтЈ»С╗Цт░єтєЁт«╣тѕњтѕєтѕ░тцџСИфтЇЋуІгуџёуЏ«тйЋСИГ№╝їТ»ЈСИфуЏ«тйЋжЃйТюЅУЄфти▒уџёСИђтЦЌ ServletсђЂт«ъућетиЦтЁиу▒╗сђЂJSP жАхжЮбтњї HTML ТќЄС╗Х№╝їжЂ┐тЁЇС║єУ┐ЎСИфжЌ«жбўсђѓуёХУђї№╝їућ▒С║јтЇЋСИф Web т║ћућеС╣ЪтЈ»УЃйТ»ћУЙЃт║ътцД№╝їтЏаТГц№╝їТѕЉС╗гСЙЮТЌДжюђУдЂжЄЄуће Java СИГућеС╗ЦжЂ┐тЁЇтЉйтљЇтє▓уфЂуџёТаЄтЄєУДБтє│Тќ╣ТАѕ№╝џтїЁсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тюет░є Servlet ТћЙтѕ░тїЁСИГ№╝їжюђУдЂТЅДУАїСИІжЮбСИцСИфжбЮтцќуџёТГЦжфцсђѓ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;т░єТќЄС╗ХТћЙтѕ░СИјжбёт«џуџётїЁтљЇтї╣жЁЇуџётГљуЏ«тйЋСИГсђѓ&lt;/li&gt;
&lt;li&gt;тюеу▒╗ТќЄС╗ХСИГТЈњтЁЦтїЁУ»ГтЈЦсђѓ&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;35-у«ђтЇЋуџё-html-Тъёт╗║тиЦтЁи&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#35-у«ђтЇЋуџё-html-Тъёт╗║тиЦтЁи&#34;&gt;#&lt;/a&gt; 3.5сђЂу«ђтЇЋуџё HTML Тъёт╗║тиЦтЁи№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	ућ▒С║ј HTML ТќЄТАБуџёу╗ЊТъётдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;!DOCTYPE ...&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;HTML&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;HEAD&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;TITLE&lt;/span&gt;&amp;gt;&lt;/span&gt;...&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;TITLE&lt;/span&gt;&amp;gt;&lt;/span&gt;...&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;HEAD&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;BODY&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;...&lt;/span&gt;&amp;gt;&lt;/span&gt;...&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;BODY&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;HTML&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тюеСй┐уће Servlet Тъёт╗║ HTML ТЌХ№╝їтЈ»УЃйС╝џуЋЦтј╗У┐ЎСИфу╗ЊТъёуџёТЪљСИфжЃетѕє№╝їт░цтЁХТў» DOCTYPE УАї№╝їтЏаСИ║УЎйуёХ HTML УДёУїЃжюђУдЂт«Ѓ№╝їСйєтЄаС╣јТЅђТюЅСИ╗ТхЂуџёТхЈУДѕтЎежЃйт┐йуЋЦт«ЃсђѓТѕЉС╗гТъЂСИЇУхъТѕљУ┐ЎуДЇтЂџТ│ЋсђѓDOCTYPE УАїуџёжЋ┐тцёТў»№╝їт«ЃтЉіУ»Ѕ HTML жфїУ»ЂтЎеТѓеСй┐ућеуџёТў» HTML уџётЊфСИфуЅѕТюг№╝їС╗јУђїжфїУ»ЂтЎеуЪЦжЂЊт║ћУ»ЦТїЅуЁДтЊфуДЇУДёУїЃт»╣ТќЄТАБУ┐ЏУАїТБђТЪЦсђѓУ┐ЎС║ЏжфїУ»ЂтЎет»╣У░ЃУ»ЋтЙѕТюЅС╗итђ╝№╝їУЃйтцЪтИ«тіЕТѓеТЇЋУјижѓБС║ЏТѓеуџёУи» i тЁ░тЦЄтЈ»С╗ЦТјеТхІтЄ║ТЮЦ№╝їСйєтЁХС╗ќТхЈУДѕтЎетюеТўЙуц║ТЌХтЈ»УЃйС╝џТюЅтЏ░жџЙуџё HTML У»ГТ│ЋжћЎУ»»сђѓ&lt;/p&gt;
&lt;p&gt;РђІ	Т»ФТЌауќЉжЌ«№╝їСй┐уће println У»ГтЈЦућЪТѕљ HTML ТюЅС║ЏугежЄЇ№╝їт░цтЁХТў»жѓБС║ЏтєЌжЋ┐С╣ЈтЉ│уџёУАї№╝їтдѓ DOCTYPE тБ░ТўјсђѓТюЅС║ЏС║║у╝ќтєЎтЙѕжЋ┐уџё HTML ућЪТѕљСй┐ућетиЦтЁиуеІт║Ј№╝їуёХтљј№╝їтюеу╝ќтєЎ Servlet ТЌХСй┐ућеУ┐ЎС║Џт«ъућетиЦтЁиуеІт║Ј№╝ї№╝їС╗ЦТГцТЮЦУДБтє│У┐ЎСИфжЌ«жбўсђѓТѕЉС╗гт»╣У┐Ўу▒╗ТЅЕт▒Ћт║ЊуџёТюЅТЋѕТђДТїЂТђђуќЉТђЂт║дсђѓждќтЁѕСИћТюђжЄЇУдЂуџёТў»№╝їтЈўТѕљућЪТѕљ HTML уџёСИЇСЙ┐Тў» JSP УДБтє│уџёСИ╗УдЂжЌ«жбўС╣ІСИђсђѓтЁХТгА№╝їућеТЮЦућЪТѕљ HTML уџёСЙІуеІтЈ»УЃйтЇЂтѕєугежЄЇ№╝їСИђУѕгт╣ХСИЇТћ»ТїЂТЅђТюЅуџё HTML т▒ъТђДсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ТаЄтЄє Servlet СИГ№╝їWeb жАхжЮбСИГуџёСИцжЃетѕєтєЁт«╣№╝ѕDOCTYPE тњї HEAD№╝ЅСИђУѕгСИЇС╝џтЈЉућЪтЈўтїќ№╝їтЏаУђїтЈ»С╗Цтйњу╗Њтѕ░СИђСИфу«ђтЇЋуџёСй┐ућетиЦтЁиТќЄС╗ХСИГсђѓС╗БуаЂ 3.5 т░▒Тў»У┐ЎТаиСИђСИфТќЄС╗Х№╝їС╗БуаЂ 3.6 тѕЌтЄ║ HelloServlet у▒╗уџётЈѕСИђСИфтЈўСйЊ№╝їт«ЃСй┐ућеУ┐ЎСИфт«ъућетиЦтЁиу▒╗сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//С╗БуаЂ 3.5&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;ServletUtilities&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;String&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;DOCTYPE&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;!DOCTYPE HTML PUBLIC \&amp;quot;-//W3C//DTD HTML 4.0 &amp;quot;&lt;/span&gt; + &lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;string&#34;&gt;&amp;quot;Transitional//EN\&amp;quot;&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; String &lt;span class=&#34;title function_&#34;&gt;headWithTitle&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String title)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; (DOCTYPE + &lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HTML&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HEAD&amp;gt;&amp;lt;TITLE&amp;gt;&amp;quot;&lt;/span&gt; + title + &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/TITLE&amp;gt;&amp;lt;HEAD&amp;gt;\n&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//С╗БуаЂ 3.6&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.ServletException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.annotation.WebServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletRequest;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletResponse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.PrintWriter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@WebServlet(&amp;quot;/hello&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HelloServlet3&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HttpServlet&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;doGet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HttpServletRequest req, HttpServletResponse resp)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServletException, IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        resp.setContentType(&lt;span class=&#34;string&#34;&gt;&amp;quot;text/html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;PrintWriter&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;out&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; resp.getWriter();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;String&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;title&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;hello3&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        out.println(ServletUtilities.headWithTitle(title) +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;BODY BGCOLOR=\&amp;quot;#FDF5E6\&amp;quot;&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;H1&amp;gt;&amp;quot;&lt;/span&gt; + title + &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/H1&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/BODY&amp;gt;&amp;lt;/HTML&amp;gt;&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	у╝ќУ»Љт«ї HelloServlet3.java С╣Ітљј№╝ѕС╝џт»╝УЄ┤УЄфтіеу╝ќУ»Љ ServletUtilities.java№╝Ѕ№╝їжюђУдЂт░єУ┐ЎСИцСИфу▒╗ТќЄС╗ХуД╗тіетѕ░ТюЇтіАтЎеж╗ўУ«цжЃеуй▓СйЇуй«№╝ѕРђд/WEB-INF/classes№╝ЅСИГ№╝їуџёуЏИт║ћуџётїЁСИГсђѓТюђтљју╗ЊТъютдѓСИІтЏЙТЅђуц║№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/8eb34a2c73134aec92788cccbfd1c2d0.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;36-servlet-уџёућЪтЉйтЉеТюЪ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#36-servlet-уџёућЪтЉйтЉеТюЪ&#34;&gt;#&lt;/a&gt; 3.6сђЂServlet уџёућЪтЉйтЉеТюЪ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	ТюЇтіАтЎетЈфтѕЏт╗║Т»ЈСИф  Servlet уџётЇЋСИђт«ъСЙІ№╝їТ»ЈСИфућеТѕиУ»иТ▒ѓжЃйС╝џт╝ЋтЈЉТќ░уџёу║┐уеІ РђћРђћ т░єућеТѕиУ»иТ▒ѓС║цС╗ўу╗ЎуЏИт║ћуџё doGet Тѕќ doPost У┐ЏУАїтцёуљєсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ждќТгАтѕЏт╗║ Servlet ТЌХ№╝їт«Ѓуџё init Тќ╣Т│ЋС╝џтЙЌтѕ░У░Ѓуће№╝їтЏаТГц№╝їinit Тў»ТћЙуй«СИђТгАТђДУ«Йуй«С╗БуаЂуџётю░Тќ╣сђѓтюеУ┐ЎС╣Ітљј№╝їжњѕт»╣Т»ЈСИфућеТѕиУ»иТ▒ѓ№╝їжЃйС╝џтѕЏжђаСИђСИфу║┐уеІ№╝їУ»Цу║┐уеІУ░ЃућетЅЇжЮбтѕЏт╗║уџёт«ъСЙІуџё Servlet Тќ╣Т│ЋсђѓтцџСИфт╣ХтЈЉУ»иТ▒ѓСИђУѕгС╝џт»╝УЄ┤тцџСИфу║┐уеІтљїТЌХУ░Ѓуће serviceсђѓС╣Ітљјућ▒ service Тќ╣Т│ЋСЙЮТЇ«ТјЦТћХтѕ░уџё HTTP У»иТ▒ѓуџёу▒╗тъІ№╝їУ░Ѓуће doGet№╝їdoPost№╝їТѕќтЁХС╗ќ doXxx Тќ╣Т│ЋсђѓТюђтљј№╝їтдѓТъюТюЇтіАтЎетє│т«џтЇИУййТЪљСИф Servlet №╝їт«ЃС╝џждќтЁѕУ░Ѓуће Servlet уџё destroy Тќ╣Т│Ћсђѓ&lt;/p&gt;
&lt;h2 id=&#34;361-service-Тќ╣Т│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#361-service-Тќ╣Т│Ћ&#34;&gt;#&lt;/a&gt; 3.6.1сђЂservice Тќ╣Т│Ћ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	ТюЇтіАтЎеТ»ЈТгАТјЦТћХтѕ░т»╣ Servlet уџёУ»иТ▒ѓ№╝їжЃйС╝џС║ДућЪСИђСИфТќ░уџёу║┐уеІ№╝їУ░Ѓуће service Тќ╣Т│Ћсђѓservice Тќ╣Т│ЋТБђТЪЦ HTTP У»иТ▒ѓуџёу▒╗тъІ№╝ѕGET№╝їPOST№╝їPUT№╝їDELETE уГЅ№╝Ѕт╣ХуЏИт║ћтю░У░Ѓуће doGet№╝їdoPost№╝їdoPut№╝їdoDelete уГЅТќ╣Т│Ћсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тдѓТъюжюђУдЂтюе Servlet СИГуГЅтљїтю░тцёуљє POST тњї GET У»иТ▒ѓ№╝їтЈфжюђУдЂУ«Е doPost У░Ѓуће doGet ТѕќУђЁтЈЇУ┐ЄТЮЦтЇ│тЈ»№╝їт░йжЄЈтѕФуЏ┤ТјЦУдєуЏќ service Тќ╣Т│Ћсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	УЎйуёХУ┐ЎуДЇТќ╣Т│ЋУдЂтцџтЄ║тЄаУАїС╗БуаЂ№╝їСйєуЏИт»╣С║јуЏ┤ТјЦУдєуЏќ service №╝їт«ЃТюЅтЄаСИфТюЅуѓ╣сђѓждќтЁѕ№╝їС╣ІтљјУ┐ўтЈ»С╗ЦтіатЁЦ doPut№╝їdoTrace уГЅ№╝їТћ»ТїЂтЁХС╗ќуџё HTTP У»иТ▒ѓТќ╣Т│ЋсђѓуЏ┤ТјЦУдєуЏќ service тѕЎТјњжЎцС║єУ┐ЎуДЇтЈ»УЃйТђДсђѓтЁХТгА№╝їУ┐ўтЈ»С╗ЦжђџУ┐ЄТи╗тіа getLastModified Тќ╣Т│Ћ№╝їтіатЁЦт»╣С┐«Тћ╣ТЌЦТюЪуџёТћ»ТїЂ№╝їућ▒С║ј getLastModified ућ▒ж╗ўУ«цуџё service Тќ╣Т│ЋУ░Ѓуће№╝їТЅђС╗ЦУдєуЏќ service Тќ╣Т│ЋС╣Ът░▒тц▒тј╗С║єУ┐ЎСИфжђЅжА╣сђѓТюђтљј№╝їservice ТЈљСЙЏт»╣ HEAD№╝їOPTION тњї TRACE У»иТ▒ѓуџёУЄфтіеТћ»ТїЂсђѓ&lt;/p&gt;
&lt;h2 id=&#34;362-dogetdopost-тњї-doxxx-Тќ╣Т│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#362-dogetdopost-тњї-doxxx-Тќ╣Т│Ћ&#34;&gt;#&lt;/a&gt; 3.6.2сђЂdoGet№╝їdoPost тњї doXxx Тќ╣Т│Ћ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	У┐ЎС║ЏжЃетѕєТЅЇТў» Servlet уџёСИ╗СйЊсђѓтЏаТГц№╝їтЈ»С╗ЦУдєуЏќ doGet тњї doPostсђѓтдѓТъюТё┐ТёЈ№╝їС╣ЪтЈ»С╗ЦУдєуЏќ DELETE У»иТ▒ѓуџё doDeleteсђЂPUT У»иТ▒ѓуџё doPut сђЂOPTIONS У»иТ▒ѓуџё doOptions С╗ЦтЈі TRACE У»иТ▒ѓуџё doTraceсђѓуёХУђї№╝їУдЂУ«░СйЈти▓у╗ЈТІЦТюЅт»╣ OPTION тњї TRACE уџёУЄфтіеТћ»ТїЂсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	СИђУѕгТЃЁтєхСИІ№╝їСИЇжюђУдЂт«ъуј░ doHead С╗Цтцёуљє HEAD У»иТ▒ѓ№╝ѕHEAD У»иТ▒ѓУДёт«џ№╝їТюЇтіАтЎет║ћУ»ЦтЈфУ┐ћтЏъТГБтИИуџё HTTP ТіЦтц┤№╝їСИЇтљФСИјС╣ІуЏИтЁ│УЂћуџёТќЄТАБ№╝Ѕсђѓућ▒С║ју│╗у╗ЪС╝џУЄфтіеУ░Ѓуће doGet №╝їт╣ХућеућЪТѕљуџёуіХТђЂУАїтњїТіЦтц┤У«Йт«џТЮЦт║ћуГћ HEAD У»иТ▒ѓ№╝їТЋЁУђї№╝їСИђУѕгСИЇжюђУдЂт«ъуј░ doHead сђѓТюЅТЌХ№╝їСИ║С║єУЃйтцЪТЏ┤т┐Фтю░ућЪТѕљт»╣ HEAD У»иТ▒ѓуџётЊЇт║ћ№╝їС╝џт«ъуј░ doHead Тќ╣Т│Ћсђѓ&lt;/p&gt;
&lt;h2 id=&#34;363-init-Тќ╣Т│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#363-init-Тќ╣Т│Ћ&#34;&gt;#&lt;/a&gt; 3.6.3сђЂinit Тќ╣Т│Ћ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	тцДтцџТЋ░ТЌХтђЎ№╝їServlet тЈфжюђтцёуљєтЇЋСИфУ»иТ▒ѓуџёТЋ░ТЇ«№╝їdoGet Тѕќ doPost Тў»ућЪтЉйтЉеТюЪСИГтћ»СИђжюђУдЂуџёТќ╣Т│ЋсђѓуёХУђї№╝їТюЅТЌХтђЎтИїТюЏтюе Servlet ждќТгАУййтЁЦТЌХ№╝їТЅДУАїтцЇТЮѓуџётѕЮтДІтїќС╗╗тіА№╝їСйєт╣ХСИЇТЃ│Т»ЈСИфУ»иТ▒ѓжЃйжЄЇтцЇУ┐ЎС║ЏС╗╗тіАсђѓinit Тќ╣Т│Ћт░▒Тў»СИЊжЌежњѕт»╣У┐ЎуДЇТЃЁтєхУ«ЙУ«А№╝Џт«Ѓтюе Servlet тѕЮТгАтѕЏт╗║ТЌХУбФУ░Ѓуће№╝їС╣ІтљјтцёуљєТ»ЈСИфућеТѕиуџёУ»иТ▒ѓТЌХ№╝їтѕЎСИЇтєЇУ░ЃућеУ┐ЎСИфТќ╣Т│ЋсђѓтЏаТГц№╝їт«ЃСИ╗УдЂућеС║јСИђТгАТђДуџётѕЮтДІтїќ№╝їтњї applet уџё init Тќ╣Т│ЋуЏИтљїсђѓServlet СИђУѕгтюеућеТѕиждќТгАУ░Ѓућет»╣т║ћуџё Servlet уџё URL ТЌХтѕЏт╗║№╝їСйєС╣ЪтЈ»С╗ЦТїЄт«џ Servlet тюеТюЇтіАтЎетљ»тіетљјУййтЁЦсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	init Тќ╣Т│ЋТЅДУАїСИцуДЇу▒╗тъІуџётѕЮтДІтїќ№╝џтИИУДётѕЮтДІтїќ№╝їС╗ЦтЈіућ▒тѕЮтДІтїќтЈѓТЋ░ТјДтѕХуџётѕЮтДІтїќсђѓ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;тИИУДётѕЮтДІтїќ№╝џ&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;init тЈфТў»тѕЏт╗║ТѕќУййтЁЦтюе Servlet тБ░ТўјтЉеТюЪтєЁућетѕ░уџёСИђС║ЏТЋ░ТЇ«№╝їТѕќУђЁТЅДУАїТЪљС║ЏСИђТгАТђДуџёУ«Ау«Ќсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;ућ▒тѕЮтДІтїќтЈѓТЋ░ТјДтѕХуџётѕЮтДІтїќ№╝џ&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;364-destroy-Тќ╣Т│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#364-destroy-Тќ╣Т│Ћ&#34;&gt;#&lt;/a&gt; 3.6.4сђЂdestroy Тќ╣Т│Ћ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	ТюЇтіАтЎетЈ»УЃйС╝џтє│т«џуД╗жЎцС╣ІтЅЇУййтЁЦуџё Servlet т«ъСЙІ№╝їТѕќУ«ИтЏаСИ║ТюЇтіАтЎеуџёу«АуљєтЉўУдЂТ▒ѓт«ЃУ┐ЎТаитЂџсђѓСйєТў»№╝їтюеТюЇтіАтЎеуД╗жЎц Servlet уџёт«ъСЙІС╣ІтЅЇ№╝їт«ЃС╝џУ░Ѓуће Servlet уџё destroy Тќ╣Т│Ћ№╝їС╗јУђїСй┐тЙЌ Servlet ТюЅТю║С╝џтЁ│жЌГТЋ░ТЇ«т║ЊУ┐ъТјЦсђЂтЂюТГбтљјтЈ░уџёу║┐уеІсђЂт░є Cookie тѕЌУАетњїуѓ╣тЄ╗У«АТЋ░тєЎтЁЦтѕ░уБЂуЏўсђЂт╣ХТЅДУАїтЁХС╗ќТИЁуљєТ┤╗тіесђѓСйєТў»№╝їУдЂТёЈУ»єтѕ░ Web ТюЇтіАтЎеТюЅтЈ»УЃйт┤ЕТ║ЃсђѓтЏаТГц№╝їСИЇУдЂт░є destroy Тю║тѕХСйюСИ║тљЉуБЂуЏўСИіС┐ЮтГўуіХТђЂуџётћ»СИђТю║тѕХсђѓтдѓТъюТюЇтіАтЎеТЅДУАїУ»Итдѓуѓ╣тЄ╗У«АТЋ░№╝їТѕќт»╣ Cookie тђ╝уџётѕЌУАеУ┐ЏУАїу┤»тіауГЅТ┤╗тіе№╝їт║ћУ»ЦСИ╗тіетю░т«џТюЪт░єТЋ░ТЇ«тєЎтѕ░уБЂуЏўСИісђѓ&lt;/p&gt;
&lt;h1 id=&#34;37-singlethreadmodel-ТјЦтЈБ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#37-singlethreadmodel-ТјЦтЈБ&#34;&gt;#&lt;/a&gt; 3.7сђЂSingleThreadModel ТјЦтЈБ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	&lt;strong&gt;Т│е№╝џућ▒С║јТѕЉу╝║т░ЉтЅЇуй«уЪЦУ»є№╝їТЅђС╗ЦУ┐ЎжЃетѕєтєЁт«╣тЁѕСИ┤ТЌХУи│У┐Є№╝їтђЪжЅ┤ТѕЉуџётЇџт«бтєЁт«╣тГдС╣ауџётИѕтѓЁтЈ»С╗Цтј╗Тћ»ТїЂСИІУ┐ЎТюгС╣дсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;h1 id=&#34;38-servlet-уџёУ░ЃУ»Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#38-servlet-уџёУ░ЃУ»Ћ&#34;&gt;#&lt;/a&gt; 3.8сђЂServlet уџёУ░ЃУ»Ћ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	тдѓСИІ№╝їС╣дСИГтѕЌтЄ║С║єСИђжЃетѕєуџёУ░ЃУ»ЋТіђтиД№╝џ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;Сй┐ућеТЅЊтЇ░У»ГтЈЦсђѓ&lt;/li&gt;
&lt;li&gt;Сй┐ућежЏєТѕљтюе IDE СИГуџёУ░ЃУ»ЋтЎесђѓ&lt;/li&gt;
&lt;li&gt;Сй┐ућеТЌЦт┐ЌТќЄС╗Хсђѓ&lt;/li&gt;
&lt;li&gt;Сй┐уће Apache Log4Jсђѓ&lt;/li&gt;
&lt;li&gt;у╝ќтєЎуІгуФІу▒╗сђѓ&lt;/li&gt;
&lt;li&gt;жбётЁѕтЂџтЦйТЋ░ТЇ«у╝║тц▒Тѕќт╝ѓтИИуџётЄєтцЄсђѓ&lt;/li&gt;
&lt;li&gt;ТБђТЪЦ HTML Т║љС╗БуаЂсђѓ&lt;/li&gt;
&lt;li&gt;тЇЋуІгТБђТЪЦУ»иТ▒ѓТЋ░ТЇ«сђѓ&lt;/li&gt;
&lt;li&gt;тЇЋуІгТБђТЪЦтЊЇт║ћТЋ░ТЇ«сђѓ&lt;/li&gt;
&lt;li&gt;тЂюТГбтњїжЄЇтљ»ТюЇтіАтЎесђѓ&lt;br&gt;
&lt;strong&gt;Т│е№╝џућ▒С║јТѕЉу╝║т░ЉтЅЇуй«уЪЦУ»є№╝їТЅђС╗ЦУ┐ЎжЃетѕєтєЁт«╣тЁѕСИ┤ТЌХУи│У┐Є№╝їтђЪжЅ┤ТѕЉуџётЇџт«бтєЁт«╣тГдС╣ауџётИѕтѓЁтЈ»С╗Цтј╗Тћ»ТїЂСИІУ┐ЎТюгС╣дсђѓ&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;38-servlet-уџёУ░ЃУ»Ћ-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#38-servlet-уџёУ░ЃУ»Ћ-2&#34;&gt;#&lt;/a&gt; 3.8сђЂServlet уџёУ░ЃУ»Ћ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	тдѓСИІ№╝їС╣дСИГтѕЌтЄ║С║єСИђжЃетѕєуџёУ░ЃУ»ЋТіђтиД№╝џ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;Сй┐ућеТЅЊтЇ░У»ГтЈЦсђѓ&lt;/li&gt;
&lt;li&gt;Сй┐ућежЏєТѕљтюе IDE СИГуџёУ░ЃУ»ЋтЎесђѓ&lt;/li&gt;
&lt;li&gt;Сй┐ућеТЌЦт┐ЌТќЄС╗Хсђѓ&lt;/li&gt;
&lt;li&gt;Сй┐уће Apache Log4Jсђѓ&lt;/li&gt;
&lt;li&gt;у╝ќтєЎуІгуФІу▒╗сђѓ&lt;/li&gt;
&lt;li&gt;жбётЁѕтЂџтЦйТЋ░ТЇ«у╝║тц▒Тѕќт╝ѓтИИуџётЄєтцЄсђѓ&lt;/li&gt;
&lt;li&gt;ТБђТЪЦ HTML Т║љС╗БуаЂсђѓ&lt;/li&gt;
&lt;li&gt;тЇЋуІгТБђТЪЦУ»иТ▒ѓТЋ░ТЇ«сђѓ&lt;/li&gt;
&lt;li&gt;тЇЋуІгТБђТЪЦтЊЇт║ћТЋ░ТЇ«сђѓ&lt;/li&gt;
&lt;li&gt;тЂюТГбтњїжЄЇтљ»ТюЇтіАтЎесђѓ&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;&lt;strong&gt;Т│е№╝џУ»Цу│╗тѕЌугћУ«░Тў»ућеС║јТѕЉтюе сђіServlet СИј JSP ТаИт┐Ѓу╝ќуеІсђІУ┐ЎТюгС╣дСИГуџётГдС╣аугћУ«░№╝їТЌатЁХС╗ќТёЈТђЮ№╝їСЙхТЮЃУ»иУЂћу│╗ 2082045221@qq.com тѕажЎцсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;РђІ	уггСИђуФатєЁт«╣УЙЃт░Љ№╝їТЅђС╗ЦТџѓТЌХТюЅућеуџёугћУ«░С╣ЪСИЇтцџсђѓ&lt;/p&gt;
&lt;h1 id=&#34;11-servlet-уџётіЪуће&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#11-servlet-уџётіЪуће&#34;&gt;#&lt;/a&gt; 1.1сђЂServlet уџётіЪуће№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	Servlet Тў»У┐љУАїтюе Web ТюЇтіАтЎеТѕќт║ћућеТюЇтіАтЎеСИіуџё Java уеІт║Ј№╝їт«ЃТў»СИђСИф№╝їУ┤ЪУ┤БУ┐ъТјЦТЮЦУЄф Web ТхЈУДѕтЎеТѕќтЁХС╗ќ HTTP т«бТѕиуеІт║ЈуџёУ»иТ▒ѓтњї HTTP ТюЇтіАтЎеСИіуџёТЋ░ТЇ«т║ЊТѕќт║ћућеуеІт║ЈсђѓServlet уџётиЦСйюТў»ТЅДУАїСИІжЮбуџёС╗╗тіА№╝їтдѓтЏЙ 1.1 ТЅђуц║№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/764d654f16ff499ca886496abc121f94.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;У»╗тЈќт«бТѕитЈЉжђЂуџёТўЙт╝ЈТЋ░ТЇ«сђѓ&lt;/p&gt;
&lt;p&gt;Тюђу╗ѕућеТѕиСИђУѕгтюеуйЉжАхуџё HTML УАетЇЋСИГУЙЊтЁЦуџёУ┐ЎС║ЏТЋ░ТЇ«сђѓуёХУђї№╝їТЋ░ТЇ«У┐ўТюЅтЈ»УЃйТЮЦУЄфС║ј Applet Тѕќт«џтѕХуџё HTTP т«бТѕиуеІт║Јсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;У»╗тЈќућ▒ТхЈУДѕтЎетЈЉжђЂуџёжџљт╝ЈУ»иТ▒ѓТЋ░ТЇ«сђѓ&lt;/p&gt;
&lt;p&gt;тЏЙ 1.1 СИГТўЙуц║С║єСИђТЮАС╗јт«бТѕиуФ»тѕ░ Web ТюЇтіАтЎе№╝ѕServlet тњї JSP ТЅђтюеуџёт▒ѓ№╝ЅуџётЇЋу«Гтц┤№╝їСйєт«ъжЎЁСИіС╗јт«бТѕиуФ»С╝ажђЂтѕ░  Web ТюЇтіАтЎеуџёТЋ░ТЇ«ТюЅСИцуДЇ№╝їт«ЃС╗гтѕєтѕФСИ║ућеТѕитюеУАетЇЋСИГУЙЊтЁЦуџёТўЙт╝ЈТЋ░ТЇ«№╝їС╗ЦтЈітљјтЈ░уџё HTTP С┐АТЂ»сђѓСИцуДЇТЋ░ТЇ«жЃйтЙѕжЄЇУдЂсђѓHTTP С┐АТЂ»тїЁТІг CookieсђЂТхЈУДѕтЎеТЅђУЃйУ»єтѕФуџётфњСйЊу▒╗тъІтњїтјІу╝ЕТеАт╝ЈуГЅсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ућЪТѕљу╗ЊТъюсђѓ&lt;/p&gt;
&lt;p&gt;У┐ЎСИфУ┐ЄуеІтЈ»УЃйжюђУдЂУ«┐жЌ«ТЋ░ТЇ«т║ЊсђЂТЅДУАї RMI Тѕќ EJB У░Ѓуће сђЂУ░Ѓуће Web ТюЇтіА№╝їТѕќУђЁуЏ┤ТјЦУ«Ау«ЌтЙЌтЄ║т»╣т║ћуџётЊЇт║ћсђѓт«ъжЎЁуџёТЋ░ТЇ«тЈ»УЃйтГўтѓетюетЁ│у│╗тъІТЋ░ТЇ«т║ЊСИГсђѓУ»ЦТЋ░ТЇ«т║ЊтЈ»УЃйСИЇуљєУДБ HTTP №╝їТѕќУђЁСИЇУЃйУ┐ћтЏъ HTML тйбт╝Јуџёу╗ЊТъю№╝їТЅђС╗Ц Web ТхЈУДѕтЎеСИЇУЃйуЏ┤ТјЦСИјТЋ░ТЇ«т║ЊУ┐ЏУАїС╝џУ»ЮсђѓтЈіТЌХУЃйтцЪтЂџтѕ░У┐ЎСИђуѓ╣№╝їСИ║С║єт«ЅтЁе№╝їС╣ЪСИЇтИїТюЏУ«Ет«ЃУ┐ЎС╣ѕтЂџсђѓт»╣С║јтцДтцџТЋ░тЁХС╗ќт║ћућеуеІт║Ј№╝їС╣ЪтГўтюеу▒╗С╝╝уџёжЌ«жбўсђѓтЏаТГц№╝їжюђУдЂ Web СИГжЌ┤т▒ѓС╗ј HTTP ТхЂСИГТЈљтЈќУЙЊтЁЦТЋ░ТЇ«№╝їСИјт║ћућеуеІт║ЈС╝џУ»Ю№╝їт╣Хт░єу╗ЊТъютхїтЁЦтѕ░ТќЄТАБСИГсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;тљЉт«бТѕитЈЉжђЂТўЙт╝ЈТЋ░ТЇ«№╝ѕтЇ│ТќЄТАБ№╝Ѕсђѓ&lt;/p&gt;
&lt;p&gt;У┐ЎСИфТќЄТАБтЈ»С╗ЦућетљёуДЇтЈЉжђЂ№╝їтїЁТІгТќЄТюг№╝ѕHTML Тѕќ XML№╝Ѕ№╝їС║їУ┐ЏтѕХ№╝ѕGIF тЏЙ№╝Ѕ№╝їућџУЄ│тЈ»С╗ЦТў»т╗║уФІтюетЁХС╗ќт║Ћт▒ѓТа╝т╝Ј№╝їтдѓ gzipсђѓСйєТў»№╝їтѕ░уЏ«тЅЇСИ║ТГб№╝їHTML Тў»ТюђтИИућеуџёТа╝т╝Ј№╝їТЋЁУђї Servlet тњї JSP уџёжЄЇУдЂС╗╗тіАС╣ІСИђт░▒Тў»т░єу╗ЊТъютїЁУБЁтѕ░ HTML СИГсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;тЈЉжђЂжџљт╝Јуџё HTTP тЊЇт║ћТЋ░ТЇ«сђѓ&lt;/p&gt;
&lt;p&gt;тЏЙ 1.1 СИГТўЙуц║С║єСИђТЮАС╗ј Web СИГжЌ┤т▒ѓ№╝ѕServlet Тѕќ JSP жАхжЮб№╝Ѕтѕ░т«бТѕиуФ»уџётЇЋу«Гтц┤сђѓСйєТў»№╝їт«ъжЎЁтЈЉжђЂуџёТЋ░ТЇ«ТюЅСИцуДЇ№╝џТќЄТАБТюгУ║Ф№╝їС╗ЦтЈітљјтЈ░уџё HTTP С┐АТЂ»сђѓтљїТаи№╝їСИцуДЇТЋ░ТЇ«т»╣т╝ђтЈЉТЮЦУ»┤жЃйТў»УЄ│тЁ│жЄЇУдЂуџёсђѓHTTP тЊЇт║ћТЋ░ТЇ«уџётЈЉжђЂУ┐ЄуеІТХЅтЈітЉіуЪЦТхЈУДѕтЎеТѕќтЁХС╗ќт«бТѕиуеІт║ЈТЅђУ┐ћтЏъТќЄТАБуџёу▒╗тъІ№╝ѕСЙІтдѓ HTML№╝Ѕ№╝їТў»ТїЄ Cookie тњїу╝ЊтГўтЈѓТЋ░№╝їС╗ЦтЈітЁХС╗ќу▒╗С╝╝уџёС╗╗тіАсђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;12-тіеТђЂТъёт╗║уйЉжАхуџётјЪтЏа&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#12-тіеТђЂТъёт╗║уйЉжАхуџётјЪтЏа&#34;&gt;#&lt;/a&gt; 1.2сђЂтіеТђЂТъёт╗║уйЉжАхуџётјЪтЏа№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ		т«ъТЌХТъёт╗║уйЉжАхуџёуљєућ▒№╝џ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;уйЉжАхтЪ║С║јт«бТѕитЈЉжђЂуџёТЋ░ТЇ«сђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уйЉжАхућ▒жбЉу╣ЂТћ╣тЈўуџёТЋ░ТЇ«т»╝тЄ║сђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;уйЉжАхСИГСй┐ућеС║єТЮЦУЄфтЁгтЈИТЋ░ТЇ«т║ЊТѕќтЁХС╗ќТюЇтіАтЎеуФ»ТЋ░ТЇ«Т║љуџёС┐АТЂ»сђѓ&lt;/p&gt;
&lt;p&gt;уљєУ«║СИіУ«▓№╝їServlet т╣ХжЮътЈфућеС║јтцёуљє HTTP У»иТ▒ѓуџё Web ТюЇтіАтЎеТѕќт║ћућеТюЇтіАтЎе№╝їт«ЃтљїТаитЈ»С╗ЦућеС║јтЁХС╗ќу▒╗тъІуџёТюЇтіАтЎесђѓУђїСИћ№╝їућеС║јС╝џУ»Ютљ»тіетЇЈУ««№╝ѕSession Initiation Protocol№╝ї SIP№╝ЅТюЇтіАтЎеуџё Servlet API ТюђУ┐Љти▓у╗ЈУбФТаЄтЄєтїќсђѓСйєТў»тюет«ъУихСИГ№╝їServlet уџёУ┐ЎуДЇућеТ│Ћт░џСИЇТхЂУАї№╝їТЅђС╗ЦС╗ЦСИІжЃйтЈфУ»┤ HTTP Servlet сђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;13-servlet-С╗БуаЂтѕЮТјб&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#13-servlet-С╗БуаЂтѕЮТјб&#34;&gt;#&lt;/a&gt; 1.3сђЂServlet С╗БуаЂтѕЮТјб№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	уј░тюе№╝їтЁѕт┐ФжђЪтю░УДѓт»ЪСИђСИфу«ђтЇЋуџё Servlet №╝їС╗Цт»╣т«ЃуџётцЇТЮѓуеІт║дТюЅСИђСИфтЪ║ТюгуџёС║єУДБсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ждќтЁѕ№╝їу╗ЎСИђСИфу«ђтЇЋуџё Servlet С╗БуаЂ№╝їт«ЃтљЉт«бТѕиуФ»УЙЊтЄ║С║єСИђСИфу«ђтЇЋуџё HTML жАхжЮб№╝їСИЇУ┐ЄжюђУдЂТ│еТёЈС╗ЦСИІтЄауѓ╣№╝џ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;т«ЃТў»тИИУДёуџё Java С╗БуаЂсђѓ&lt;/li&gt;
&lt;li&gt;т«ЃТюЅСИЇуєЪТѓЅуџёжЄЇУдЂУ»ГтЈЦсђѓ&lt;/li&gt;
&lt;li&gt;т«Ѓт»╣ТаЄтЄєуџёу▒╗№╝ѕHttpServlet№╝ЅУ┐ЏУАїС║єТЅЕт▒Ћсђѓ&lt;/li&gt;
&lt;li&gt;т«ЃУдєуЏќ№╝ѕoverride№╝ЅС║є doGet Тќ╣Т│Ћсђѓ&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.firstweb.study01;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.ServletException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.annotation.WebServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServlet;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletRequest;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; jakarta.servlet.http.HttpServletResponse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.PrintWriter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@WebServlet(&amp;quot;/hello&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HelloServlet&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;HttpServlet&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;doGet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HttpServletRequest req, HttpServletResponse resp)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServletException, IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        resp.setContentType(&lt;span class=&#34;string&#34;&gt;&amp;quot;text/html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;PrintWriter&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;out&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; resp.getWriter();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;String&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;docType&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;!DOCTYPE HTML PUBLIC \&amp;quot;-//W3C//DTD HTML 4.0&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;string&#34;&gt;&amp;quot;Transitional//EN\&amp;quot;&amp;gt;\n&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        out.println(docType +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HTML&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;HEAD&amp;gt;&amp;lt;TITLE&amp;gt;Hello&amp;lt;/TITLE&amp;gt;&amp;lt;HEAD&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;BODY BGCOLOR=\&amp;quot;#FDF5E6\&amp;quot;&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;H1&amp;gt;Hello&amp;lt;/H1&amp;gt;\n&amp;quot;&lt;/span&gt; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/BODY&amp;gt;&amp;lt;/HTML&amp;gt;&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;УЙЊтЄ║у╗ЊТъютдѓСИІ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/d18f9356267b41459a74fd01cd064c76.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
