t;span class=&#34;number&#34;&gt;0x11c7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1017&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                   &lt;span class=&#34;number&#34;&gt;0x1fd7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1f17&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1107&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0xf47&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1127&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1037&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1e47&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1037&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1fd7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1107&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1fd7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x1107&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0x2787&lt;/span&gt;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; len;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    len=&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(data)/&lt;span class=&#34;keyword&#34;&gt;sizeof&lt;/span&gt;(data[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; index=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; j=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;j&amp;lt;len;j++)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; i=&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;;i&amp;lt;&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;;i++)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;((((i*&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;0x14&lt;/span&gt;)^&lt;span class=&#34;number&#34;&gt;0x4D&lt;/span&gt;)+&lt;span class=&#34;number&#34;&gt;0x1E&lt;/span&gt;)==data[j])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                flag[index++]=(&lt;span class=&#34;type&#34;&gt;char&lt;/span&gt;)i;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    flag[index]=&lt;span class=&#34;string&#34;&gt;&amp;#x27;\0&amp;#x27;&lt;/span&gt;;&lt;span class=&#34;comment&#34;&gt;//charтъІ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;puts&lt;/span&gt;(flag);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//flag&amp;#123;67e9a228e45b622c2992fb5174a4f5f5&amp;#125;	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;pwn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwn&#34;&gt;#&lt;/a&gt; Pwn&lt;/h2&gt;
&lt;h3 id=&#34;gostackтцЇуј░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gostackтцЇуј░&#34;&gt;#&lt;/a&gt; gostack№╝ѕтцЇуј░№╝Ѕ:&lt;/h3&gt;
&lt;p&gt;go У»ГУеђуџёТаѕТ║бтЄ║№╝їТ▓АжЂЄтѕ░У┐Є№╝їУхЏтљјтцЇуј░СИІ№╝їуюІуюІУЃйтљдт╣▓тЄ║ТЮЦсђѓ&lt;br&gt;
ждќтЁѕТў»ТБђТЪЦС┐ЮТіц№╝їСИЇУ┐Є 64 СйЇ№╝їтЄ║С║є NX С╣ІтцќТ▓АТюЅС╗╗СйЋС┐ЮТіц№╝їжѓБт░▒у«ђтЇЋСИЇт░Љ№╝їТІќтѕ░ IDA жЄїуюІуюІ№╝їтЙѕУй╗ТЮЙт░▒УЃйТЅЙтѕ░ mainmain№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;// main.main&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;void __fastcall main_main()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  __int64 v0; // r14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  void *retaddr; // [&lt;span class=&#34;type&#34;&gt;rsp&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;h&lt;/span&gt;] [&lt;span class=&#34;type&#34;&gt;rbp&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;h&lt;/span&gt;] BYREF&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ( (unsigned __int64)&amp;amp;retaddr &amp;lt;= *(_QWORD *)(v0 + &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;) )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    runtime_morestack_noctxt();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  main_main_func1();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ( (unsigned __int8)main_main_func3() )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    main_main_func2();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;СИЇУ┐ЄУ┐ЎСИфтЙѕТўјТўЙ№╝їТюЅуѓ╣уюІСИЇТЄѓ№╝їТ»ЋуФЪТ▓АТјЦУДдУ┐Є go У»ГУеђ№╝їжѓБС╣ѕ№╝їтЁѕуЏ┤ТјЦУ┐љУАїСИІуюІуюІуеІт║ЈТў»тЋЦТЃЁтєх№╝Ъ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den&lt;span class=&#34;literal&#34;&gt;-virtual-machine&lt;/span&gt;:/mnt/shared&lt;span class=&#34;comment&#34;&gt;# ./pwn&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Welcome to CISCN!&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Happy magic golang!&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Input your magic message :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAaaaaaaa&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Your magic message :AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAaaaaaaa&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
