&lt;h3 id=&#34;Та╝т╝ЈтїќтГЌугдСИ▓уџёТа╝т╝Ј&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#Та╝т╝ЈтїќтГЌугдСИ▓уџёТа╝т╝Ј&#34;&gt;#&lt;/a&gt; Та╝т╝ЈтїќтГЌугдСИ▓уџёТа╝т╝Ј№╝џ&lt;/h3&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;%[parameter][flags][field width][.precision][length]type&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЁХСИГ№╝їжюђУдЂТ│еТёЈуџёТюЅ parameter тЈѓТЋ░№╝їС╗ЦтЈі type тЈѓТЋ░№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;parameter№╝џ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  n$№╝їУјитЈќТа╝т╝ЈтїќтГЌугдСИ▓СИГуџёТїЄт«џтЈѓТЋ░
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;type№╝џ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;d/i№╝їТюЅугдтЈиТЋ┤ТЋ░&lt;/li&gt;
&lt;li&gt;u№╝їТЌаугдтЈиТЋ┤ТЋ░&lt;/li&gt;
&lt;li&gt;x/X№╝ї16 У┐ЏтѕХ unsigned int сђѓx Сй┐ућет░ЈтєЎтГЌТ»Ї№╝ЏX Сй┐ућетцДтєЎтГЌТ»ЇсђѓтдѓТъюТїЄт«џС║єу▓Йт║д№╝їтѕЎУЙЊтЄ║уџёТЋ░тГЌСИЇУХ│ТЌХтюетидСЙДУАЦ 0сђѓж╗ўУ«цу▓Йт║дСИ║ 1сђѓу▓Йт║дСИ║ 0 СИћтђ╝СИ║ 0№╝їтѕЎУЙЊтЄ║СИ║уЕ║сђѓ&lt;/li&gt;
&lt;li&gt;o№╝ї8 У┐ЏтѕХ unsigned int сђѓтдѓТъюТїЄт«џС║єу▓Йт║д№╝їтѕЎУЙЊтЄ║уџёТЋ░тГЌСИЇУХ│ТЌХтюетидСЙДУАЦ 0сђѓж╗ўУ«цу▓Йт║дСИ║ 1сђѓу▓Йт║дСИ║ 0 СИћтђ╝СИ║ 0№╝їтѕЎУЙЊтЄ║СИ║уЕ║сђѓ&lt;/li&gt;
&lt;li&gt;s№╝їтдѓТъюТ▓АТюЅуће l ТаЄт┐Ќ№╝їУЙЊтЄ║ null у╗Њт░ЙтГЌугдСИ▓уЏ┤тѕ░у▓Йт║дУДёт«џуџёСИіжЎљ№╝ЏтдѓТъюТ▓АТюЅТїЄт«џу▓Йт║д№╝їтѕЎУЙЊтЄ║ТЅђТюЅтГЌУіѓсђѓтдѓТъюућеС║є l ТаЄт┐Ќ№╝їтѕЎт»╣т║ћтЄйТЋ░тЈѓТЋ░ТїЄтљЉ wchar_t тъІуџёТЋ░у╗ё№╝їУЙЊтЄ║ТЌХТііТ»ЈСИфт«йтГЌугдУйгтїќСИ║тцџтГЌУіѓтГЌугд№╝їуЏИтйЊС║јУ░Ѓуће wcrtomb тЄйТЋ░сђѓ&lt;/li&gt;
&lt;li&gt;c№╝їтдѓТъюТ▓АТюЅуће l ТаЄт┐Ќ№╝їТіі int тЈѓТЋ░УйгСИ║ unsigned char тъІУЙЊтЄ║№╝ЏтдѓТъюућеС║є l ТаЄт┐Ќ№╝їТіі wint_t тЈѓТЋ░УйгСИ║тїЁтљФСИцСИфтЁЃу┤ауџё wchart_t ТЋ░у╗ё№╝їтЁХСИГуггСИђСИфтЁЃу┤атїЁтљФУдЂУЙЊтЄ║уџётГЌугд№╝їуггС║їСИфтЁЃу┤аСИ║ null т«йтГЌугдсђѓ&lt;/li&gt;
&lt;li&gt;p№╝ї void * тъІ№╝їУЙЊтЄ║т»╣т║ћтЈўжЄЈуџётђ╝сђѓprintf (&amp;quot;% p&amp;quot;,a) ућетю░тЮђуџёТа╝т╝ЈТЅЊтЇ░тЈўжЄЈ a уџётђ╝№╝їprintf (&amp;quot;% p&amp;quot;, &amp;amp;a) ТЅЊтЇ░тЈўжЄЈ a ТЅђтюеуџётю░тЮђсђѓ&lt;/li&gt;
&lt;li&gt;n№╝їСИЇУЙЊтЄ║тГЌугд№╝їСйєТў»Тііти▓у╗ЈТѕљтіЪУЙЊтЄ║уџётГЌугдСИфТЋ░тєЎтЁЦт»╣т║ћуџёТЋ┤тъІТїЄжњѕтЈѓТЋ░ТЅђТїЄуџётЈўжЄЈсђѓ&lt;/li&gt;
&lt;li&gt;%№╝ї &#39; &lt;code&gt;%&lt;/code&gt; &#39; тГЌжЮбтђ╝№╝їСИЇТјЦтЈЌС╗╗СйЋ flags, widthсђѓ&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	СИІжЮбСй┐ућетЄаСИфТАѕСЙІТЮЦУ»┤ТўјСИІтЄаСИфжюђУдЂТ│еТёЈуџётЈѓТЋ░№╝џ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;parameter№╝џ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  n$ УАеуц║УјитЈќтљјжЮбтЈѓТЋ░тѕЌУАеСИГуџёуггтЄаСИфтЈѓТЋ░сђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;p&gt;РђІ	Т»ћтдѓтдѓСИІС╗БуаЂ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;lt;stdio.h&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%2$d\n&amp;quot;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	жђџУ┐Єу╝ќУ»ЉУ┐љУАїС╣ІтљјтЙЌтѕ░уџётђ╝тЇ┤Тў»&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@g01den-virtual-machine:/home/g01den/Temp&lt;span class=&#34;comment&#34;&gt;# ./a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЦйС║є№╝їТѕЉС╗гуеЇтЙ«С┐«Тћ╣СИІтѕџтѕџуџёС╗БуаЂ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;span class=&#34;keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;lt;stdio.h&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;%d%d%d\n&amp;quot;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	уёХтљју╝ќУ»ЉСИ║ 32 СйЇС╣Ітљј№╝їТЪЦуюІСИІТ▒Єу╝ќС╗БуаЂ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;0000119d &amp;lt;main&amp;gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    119d:       8d 4c 24 04             lea    0x4(%esp),%ecx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    11a1:       83 e4 f0                and    $0xfffffff0,%esp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    11a4:       ff 71 