p;#x27;_dl_audit_preinit&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1b:006cРћѓ-01c 0xffffd36c РђћРќИ 0xf7fc2400 РђћРќИ 0xf7c00000 РЌѓРђћ 0x464c457f&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1c:0070Рћѓ-018 0xffffd370 РђћРќИ 0xffffd3a0 РђћРќИ 0xf7e1dff4 (_GLOBAL_OFFSET_TABLE_) РЌѓРђћ 0x21dd8c&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1d:0074Рћѓ-014 0xffffd374 РђћРќИ 0xf7fc25d8 РђћРќИ 0xf7ffdb9c РђћРќИ 0xf7fc26f0 РђћРќИ 0xf7ffda30 РЌѓРђћ ...                                                                    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1e:0078Рћѓ-010 0xffffd378 РђћРќИ 0xf7fc2ab0 РђћРќИ 0xf7c1f22d РЌѓРђћ &lt;span class=&#34;string&#34;&gt;&amp;#x27;GLIBC_PRIVATE&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1f:007cРћѓ-00c 0xffffd37c РЌѓРђћ 0x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20:0080Рћѓ-008 0xffffd380 РЌѓРђћ 0x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21:0084Рћѓ-004 0xffffd384 РЌѓРђћ 0x0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22:0088Рћѓ ebp 0xffffd388 РЌѓРђћ 0x0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23:008cРћѓ+004 0xffffd38c РђћРќИ 0xf7c237c5 (__libc_start_call_main+117) РЌѓРђћ add esp, 0x10                                                                       &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24:0090Рћѓ+008 0xffffd390 РЌѓРђћ 0x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25:0094Рћѓ+00c 0xffffd394 РђћРќИ 0xffffd444 РђћРќИ 0xffffd5c2 РЌѓРђћ &lt;span class=&#34;string&#34;&gt;&amp;#x27;/mnt/shared/ret2libc2&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26:0098Рћѓ+010 0xffffd398 РђћРќИ 0xffffd44c РђћРќИ 0xffffd5d8 РЌѓРђћ &lt;span class=&#34;string&#34;&gt;&amp;#x27;COLORTERM=truecolor&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27:009cРћѓ+014 0xffffd39c РђћРќИ 0xffffd3b0 РђћРќИ 0xf7e1dff4